var documenterSearchIndex = {"docs":
[{"location":"guide/image_generation/#images_guide","page":"Image Generation","title":"Image Generation","text":"UniLM.jl supports image generation via the OpenAI Images API using models like gpt-image-1.5.","category":"section"},{"location":"guide/image_generation/#Basic-Usage","page":"Image Generation","title":"Basic Usage","text":"result = generate_image(\n    \"A watercolor painting of a friendly robot reading a Julia programming book\",\n    size=\"1024x1024\",\n    quality=\"medium\"\n)\nprintln(\"Success: \", result isa ImageSuccess)\nif result isa ImageSuccess\n    imgs = image_data(result)\n    println(\"Images: \", length(imgs))\n    println(\"Base64 length: \", length(imgs[1]))\n    save_image(imgs[1], joinpath(@__DIR__, \"..\", \"assets\", \"generated_robot.png\"))\n    println(\"Image saved to assets/generated_robot.png\")\nelse\n    println(\"Images: 0\")\n    println(\"Image generation failed — see result for details\")\nend\n\n(Image: Generated image: A watercolor painting of a friendly robot reading a Julia programming book)","category":"section"},{"location":"guide/image_generation/#The-ImageGeneration-Type","page":"Image Generation","title":"The ImageGeneration Type","text":"For full control, construct an ImageGeneration object:\n\nig = ImageGeneration(\n    prompt=\"A minimalist logo for a Julia programming package\",\n    model=\"gpt-image-1.5\",\n    size=\"1024x1024\",\n    quality=\"high\",\n    background=\"transparent\",\n    output_format=\"png\"\n)\nprintln(\"Model: \", ig.model)\nprintln(\"Size: \", ig.size)\nprintln(\"Quality: \", ig.quality)\nprintln(\"\\nRequest JSON:\")\nprintln(JSON.json(ig))","category":"section"},{"location":"guide/image_generation/#Configuration-Options","page":"Image Generation","title":"Configuration Options","text":"Parameter Values Default\nmodel \"gpt-image-1.5\" \"gpt-image-1.5\"\nsize \"1024x1024\", \"1536x1024\", \"1024x1536\", \"auto\" API default\nquality \"low\", \"medium\", \"high\", \"auto\" API default\nbackground \"transparent\", \"opaque\", \"auto\" API default\noutput_format \"png\", \"webp\", \"jpeg\" API default\noutput_compression 0–100 (for webp/jpeg) API default\nn 1–10 1","category":"section"},{"location":"guide/image_generation/#Multiple-Images","page":"Image Generation","title":"Multiple Images","text":"Generate multiple images in a single request:\n\nresult = generate_image(\"A cute robot learning to program\", n=3, size=\"1024x1024\")\n\nif result isa ImageSuccess\n    imgs = image_data(result)\n    for (i, img) in enumerate(imgs)\n        save_image(img, \"robot_$i.png\")\n    end\nend","category":"section"},{"location":"guide/image_generation/#Transparent-Backgrounds","page":"Image Generation","title":"Transparent Backgrounds","text":"Perfect for logos and icons:\n\nresult = generate_image(\n    \"A simple geometric icon of a butterfly\",\n    background=\"transparent\",\n    output_format=\"png\",\n    quality=\"high\"\n)\n\nif result isa ImageSuccess\n    save_image(image_data(result)[1], \"butterfly_icon.png\")\n    # => PNG with transparent background\nend","category":"section"},{"location":"guide/image_generation/#Result-Structure","page":"Image Generation","title":"Result Structure","text":"# Show the type hierarchy for image results\nprintln(\"ImageSuccess <: \", supertype(ImageSuccess))\nprintln(\"ImageFailure <: \", supertype(ImageFailure))\nprintln(\"ImageCallError <: \", supertype(ImageCallError))\n\nresult = generate_image(\"A sunset over mountains\")\n\nif result isa ImageSuccess\n    r = result.response\n\n    r.created                 # Unix timestamp\n    r.data                    # Vector{ImageObject}\n    r.data[1].b64_json        # base64-encoded image data\n    r.data[1].revised_prompt  # revised prompt (may be nothing)\n    r.usage                   # token usage Dict\n\n    # Convenience accessors\n    image_data(result)        # Vector{String} of base64 data\n    save_image(image_data(result)[1], \"sunset.png\")\nend","category":"section"},{"location":"guide/image_generation/#Saving-Images","page":"Image Generation","title":"Saving Images","text":"The save_image helper decodes base64 and writes to disk:\n\n# Demonstrate save_image with a tiny test payload\ntmpfile = tempname() * \".txt\"\nUniLM.save_image(\"aGVsbG8=\", tmpfile)  # \"hello\" in base64\nprintln(\"File saved to: \", basename(tmpfile))\nprintln(\"Contents: \", read(tmpfile, String))\nrm(tmpfile)","category":"section"},{"location":"guide/image_generation/#Error-Handling","page":"Image Generation","title":"Error Handling","text":"result = generate_image(\"A sunset over mountains\")\n\nif result isa ImageSuccess\n    save_image(image_data(result)[1], \"sunset.png\")\nelseif result isa ImageFailure\n    @warn \"HTTP $(result.status): $(result.response)\"\nelseif result isa ImageCallError\n    @error \"Call failed: $(result.error)\"\nend","category":"section"},{"location":"guide/image_generation/#Retry-Behaviour","page":"Image Generation","title":"Retry Behaviour","text":"generate_image automatically retries on HTTP 429, 500, and 503 errors with exponential backoff and jitter (up to 30 attempts, max 60s delay). On 429 responses, the Retry-After header is respected.","category":"section"},{"location":"guide/image_generation/#See-Also","page":"Image Generation","title":"See Also","text":"ImageGeneration — request configuration type\nImageResponse — response type\ngenerate_image — request function\nimage_data, save_image — accessor/utility functions","category":"section"},{"location":"api/mcp/#mcp_api","page":"MCP Client & Server","title":"MCP Client & Server","text":"Types and functions for the Model Context Protocol — connecting to MCP servers and building MCP servers in Julia.","category":"section"},{"location":"api/mcp/#Client-Types","page":"MCP Client & Server","title":"Client Types","text":"","category":"section"},{"location":"api/mcp/#Client-Functions","page":"MCP Client & Server","title":"Client Functions","text":"","category":"section"},{"location":"api/mcp/#Lifecycle","page":"MCP Client & Server","title":"Lifecycle","text":"","category":"section"},{"location":"api/mcp/#Discovery","page":"MCP Client & Server","title":"Discovery","text":"","category":"section"},{"location":"api/mcp/#Operations","page":"MCP Client & Server","title":"Operations","text":"","category":"section"},{"location":"api/mcp/#Tool-Bridge","page":"MCP Client & Server","title":"Tool Bridge","text":"","category":"section"},{"location":"api/mcp/#Server-Types","page":"MCP Client & Server","title":"Server Types","text":"","category":"section"},{"location":"api/mcp/#Server-Functions","page":"MCP Client & Server","title":"Server Functions","text":"","category":"section"},{"location":"api/mcp/#Registration","page":"MCP Client & Server","title":"Registration","text":"","category":"section"},{"location":"api/mcp/#Serving","page":"MCP Client & Server","title":"Serving","text":"","category":"section"},{"location":"api/mcp/#Macros","page":"MCP Client & Server","title":"Macros","text":"","category":"section"},{"location":"api/mcp/#Example","page":"MCP Client & Server","title":"Example","text":"using UniLM\nusing JSON\n\n# Construct client info types\ninfo = MCPToolInfo(Dict{String,Any}(\n    \"name\" => \"read_file\",\n    \"description\" => \"Read a file from disk\",\n    \"inputSchema\" => Dict{String,Any}(\n        \"type\" => \"object\",\n        \"properties\" => Dict{String,Any}(\n            \"path\" => Dict{String,Any}(\"type\" => \"string\")\n        )\n    )\n))\nprintln(\"Tool: \", info.name, \" — \", info.description)\n\n# Build and populate a server\nserver = MCPServer(\"demo\", \"1.0.0\")\nregister_tool!(server, \"add\", \"Add two numbers\",\n    Dict{String,Any}(\n        \"type\" => \"object\",\n        \"properties\" => Dict{String,Any}(\n            \"a\" => Dict{String,Any}(\"type\" => \"number\"),\n            \"b\" => Dict{String,Any}(\"type\" => \"number\")\n        ),\n        \"required\" => [\"a\", \"b\"]\n    ),\n    args -> string(args[\"a\"] + args[\"b\"]))\nprintln(\"Server: \", server.name, \" v\", server.version)\nprintln(\"Tools: \", collect(keys(server.tools)))","category":"section"},{"location":"api/mcp/#UniLM.MCPSession","page":"MCP Client & Server","title":"UniLM.MCPSession","text":"MCPSession\n\nA live connection to an MCP server. Manages lifecycle, transport, and cached tool/resource/prompt lists.\n\nCreate via mcp_connect. Disconnect via mcp_disconnect!.\n\n\n\n\n\n","category":"type"},{"location":"api/mcp/#UniLM.MCPToolInfo","page":"MCP Client & Server","title":"UniLM.MCPToolInfo","text":"MCPToolInfo\n\nA tool definition received from an MCP server via tools/list. Convert to CallableTool via mcp_tools or mcp_tools_respond.\n\n\n\n\n\n","category":"type"},{"location":"api/mcp/#UniLM.MCPResourceInfo","page":"MCP Client & Server","title":"UniLM.MCPResourceInfo","text":"MCPResourceInfo\n\nA resource definition received from an MCP server via resources/list.\n\n\n\n\n\n","category":"type"},{"location":"api/mcp/#UniLM.MCPPromptInfo","page":"MCP Client & Server","title":"UniLM.MCPPromptInfo","text":"MCPPromptInfo\n\nA prompt definition received from an MCP server via prompts/list.\n\n\n\n\n\n","category":"type"},{"location":"api/mcp/#UniLM.MCPServerCapabilities","page":"MCP Client & Server","title":"UniLM.MCPServerCapabilities","text":"MCPServerCapabilities\n\nCapabilities declared by an MCP server during initialization.\n\n\n\n\n\n","category":"type"},{"location":"api/mcp/#UniLM.MCPTransport","page":"MCP Client & Server","title":"UniLM.MCPTransport","text":"MCPTransport\n\nAbstract type for MCP transport implementations. Subtypes must implement:\n\n_transport_connect!(t) — establish connection\n_transport_send!(t, msg::String)::String — send JSON-RPC message, return response\n_transport_notify!(t, msg::String) — send notification (no response expected)\n_transport_disconnect!(t) — close connection\n_transport_isconnected(t)::Bool — check if connected\n\n\n\n\n\n","category":"type"},{"location":"api/mcp/#UniLM.StdioTransport","page":"MCP Client & Server","title":"UniLM.StdioTransport","text":"StdioTransport <: MCPTransport\n\nStdio transport: launches a subprocess and communicates via stdin/stdout. Messages are newline-delimited JSON-RPC 2.0.\n\n\n\n\n\n","category":"type"},{"location":"api/mcp/#UniLM.HTTPTransport","page":"MCP Client & Server","title":"UniLM.HTTPTransport","text":"HTTPTransport <: MCPTransport\n\nStreamable HTTP transport: communicates via POST requests to an MCP endpoint. Handles Mcp-Session-Id header for session management.\n\n\n\n\n\n","category":"type"},{"location":"api/mcp/#UniLM.MCPError","page":"MCP Client & Server","title":"UniLM.MCPError","text":"MCPError <: Exception\n\nError from MCP protocol operations. Contains the JSON-RPC error code, message, and optional data from the server.\n\n\n\n\n\n","category":"type"},{"location":"api/mcp/#UniLM.mcp_connect","page":"MCP Client & Server","title":"UniLM.mcp_connect","text":"mcp_connect(command::Cmd; client_name=\"UniLM.jl\", protocol_version=\"2025-11-25\") -> MCPSession\n\nConnect to an MCP server via stdio transport (subprocess).\n\nExample\n\nsession = mcp_connect(`npx -y @modelcontextprotocol/server-filesystem /tmp`)\ntools = mcp_tools(session)\n# ... use tools with tool_loop! ...\nmcp_disconnect!(session)\n\n\n\n\n\nmcp_connect(url::String; headers=[], kwargs...) -> MCPSession\n\nConnect to an MCP server via HTTP transport.\n\nExample\n\nsession = mcp_connect(\"https://mcp.example.com/mcp\";\n    headers=[\"Authorization\" => \"Bearer token\"])\n\n\n\n\n\nmcp_connect(transport::MCPTransport; client_name=\"UniLM.jl\", protocol_version=\"2025-11-25\") -> MCPSession\n\nConnect to an MCP server via the given transport. Performs initialization handshake and populates tool cache.\n\n\n\n\n\nmcp_connect(f::Function, args...; kwargs...)\n\nDo-block form: automatically disconnects after the block executes.\n\nExample\n\nmcp_connect(`npx server`) do session\n    tools = mcp_tools(session)\n    chat = Chat(tools=map(t -> t.tool, tools))\n    push!(chat, Message(Val(:user), \"List files\"))\n    tool_loop!(chat; tools)\nend\n\n\n\n\n\n","category":"function"},{"location":"api/mcp/#UniLM.mcp_disconnect!","page":"MCP Client & Server","title":"UniLM.mcp_disconnect!","text":"mcp_disconnect!(session::MCPSession)\n\nGracefully disconnect from the MCP server.\n\n\n\n\n\n","category":"function"},{"location":"api/mcp/#UniLM.list_tools!","page":"MCP Client & Server","title":"UniLM.list_tools!","text":"list_tools!(session::MCPSession) -> Vector{MCPToolInfo}\n\nFetch the tool list from the MCP server. Handles pagination via cursor. Stores result in session.tools.\n\n\n\n\n\n","category":"function"},{"location":"api/mcp/#UniLM.list_resources!","page":"MCP Client & Server","title":"UniLM.list_resources!","text":"list_resources!(session::MCPSession) -> Vector{MCPResourceInfo}\n\nFetch the resource list from the MCP server. Handles pagination.\n\n\n\n\n\n","category":"function"},{"location":"api/mcp/#UniLM.list_prompts!","page":"MCP Client & Server","title":"UniLM.list_prompts!","text":"list_prompts!(session::MCPSession) -> Vector{MCPPromptInfo}\n\nFetch the prompt list from the MCP server. Handles pagination.\n\n\n\n\n\n","category":"function"},{"location":"api/mcp/#UniLM.call_tool","page":"MCP Client & Server","title":"UniLM.call_tool","text":"call_tool(session::MCPSession, name::String, arguments::Dict{String,Any}) -> String\n\nCall a tool on the MCP server and return the result as a string. Concatenates text content parts; non-text content is JSON-encoded.\n\n\n\n\n\n","category":"function"},{"location":"api/mcp/#UniLM.read_resource","page":"MCP Client & Server","title":"UniLM.read_resource","text":"read_resource(session::MCPSession, uri::String) -> String\n\nRead a resource from the MCP server.\n\n\n\n\n\n","category":"function"},{"location":"api/mcp/#UniLM.get_prompt","page":"MCP Client & Server","title":"UniLM.get_prompt","text":"get_prompt(session::MCPSession, name::String, arguments::Dict{String,Any}=Dict()) -> Vector{Dict{String,Any}}\n\nGet a rendered prompt from the MCP server. Returns the messages array.\n\n\n\n\n\n","category":"function"},{"location":"api/mcp/#UniLM.ping","page":"MCP Client & Server","title":"UniLM.ping","text":"ping(session::MCPSession)\n\nSend a ping to the MCP server. Throws on error.\n\n\n\n\n\n","category":"function"},{"location":"api/mcp/#UniLM.mcp_tools","page":"MCP Client & Server","title":"UniLM.mcp_tools","text":"mcp_tools(session::MCPSession) -> Vector{CallableTool{GPTTool}}\n\nConvert all tools from an MCP session into CallableTool{GPTTool} instances that work directly with tool_loop! (Chat Completions API).\n\nEach tool's callable invokes call_tool(session, name, args) under the hood.\n\nExample\n\nsession = mcp_connect(`npx server`)\ntools = mcp_tools(session)\nchat = Chat(model=\"gpt-5.2\", tools=map(t -> t.tool, tools))\npush!(chat, Message(Val(:user), \"Do something\"))\nresult = tool_loop!(chat; tools)\n\n\n\n\n\n","category":"function"},{"location":"api/mcp/#UniLM.mcp_tools_respond","page":"MCP Client & Server","title":"UniLM.mcp_tools_respond","text":"mcp_tools_respond(session::MCPSession) -> Vector{CallableTool{FunctionTool}}\n\nConvert all tools from an MCP session into CallableTool{FunctionTool} instances that work directly with tool_loop (Responses API).\n\nExample\n\nsession = mcp_connect(\"https://mcp.example.com/mcp\")\ntools = mcp_tools_respond(session)\nresult = tool_loop(\"Do something\"; tools=tools)\n\n\n\n\n\n","category":"function"},{"location":"api/mcp/#UniLM.MCPServer","page":"MCP Client & Server","title":"UniLM.MCPServer","text":"MCPServer(name, version; description=nothing)\n\nAn MCP server that can host tools, resources, and prompts.\n\nRegister primitives via register_tool!, register_resource!, register_prompt!, or the @mcp_tool, @mcp_resource, @mcp_prompt macros.\n\nStart serving via serve.\n\nExample\n\nserver = MCPServer(\"my-server\", \"1.0.0\")\nregister_tool!(server, \"add\", \"Add two numbers\",\n    Dict(\"type\"=>\"object\", \"properties\"=>Dict(\"a\"=>Dict(\"type\"=>\"number\"),\"b\"=>Dict(\"type\"=>\"number\")), \"required\"=>[\"a\",\"b\"]),\n    args -> string(args[\"a\"] + args[\"b\"]))\nserve(server)  # stdio by default\n\n\n\n\n\n","category":"type"},{"location":"api/mcp/#UniLM.MCPServerPrimitive","page":"MCP Client & Server","title":"UniLM.MCPServerPrimitive","text":"MCPServerPrimitive\n\nAbstract supertype for MCP server-side primitives (tools, resources, prompts).\n\n\n\n\n\n","category":"type"},{"location":"api/mcp/#UniLM.MCPServerTool","page":"MCP Client & Server","title":"UniLM.MCPServerTool","text":"MCPServerTool <: MCPServerPrimitive\n\nA tool registered on an MCP server. The handler receives Dict{String,Any} arguments and returns any value (converted to text content by the server).\n\nFields\n\nname::String: Unique tool name\ndescription::Union{String,Nothing}: Human-readable description\ninput_schema::Dict{String,Any}: JSON Schema for the input parameters\nhandler::Function: (args::Dict{String,Any}) -> Any\n\n\n\n\n\n","category":"type"},{"location":"api/mcp/#UniLM.MCPServerResource","page":"MCP Client & Server","title":"UniLM.MCPServerResource","text":"MCPServerResource <: MCPServerPrimitive\n\nA static resource registered on an MCP server.\n\nFields\n\nuri::String: Resource URI\nname::String: Human-readable name\ndescription::Union{String,Nothing}: Description\nmime_type::String: MIME type (default \"text/plain\")\nhandler::Function: () -> Union{String, Vector{UInt8}}\n\n\n\n\n\n","category":"type"},{"location":"api/mcp/#UniLM.MCPServerResourceTemplate","page":"MCP Client & Server","title":"UniLM.MCPServerResourceTemplate","text":"MCPServerResourceTemplate <: MCPServerPrimitive\n\nA URI-templated resource. Template variables like {path} are extracted and passed to the handler.\n\nFields\n\nuri_template::String: URI template (e.g., \"file://{path}\")\nname::String: Human-readable name\ndescription::Union{String,Nothing}: Description\nmime_type::String: MIME type\nhandler::Function: (params::Dict{String,String}) -> Union{String, Vector{UInt8}}\n_pattern::Regex: Compiled regex from template\n_param_names::Vector{String}: Extracted parameter names\n\n\n\n\n\n","category":"type"},{"location":"api/mcp/#UniLM.MCPServerPrompt","page":"MCP Client & Server","title":"UniLM.MCPServerPrompt","text":"MCPServerPrompt <: MCPServerPrimitive\n\nA prompt template registered on an MCP server.\n\nFields\n\nname::String: Unique prompt name\ndescription::Union{String,Nothing}: Description\narguments::Vector{Dict{String,Any}}: Argument definitions\nhandler::Function: (args::Dict{String,Any}) -> Vector{Dict{String,Any}}\n\n\n\n\n\n","category":"type"},{"location":"api/mcp/#UniLM.register_tool!","page":"MCP Client & Server","title":"UniLM.register_tool!","text":"register_tool!(server, name, description, input_schema, handler)\n\nRegister a tool on the MCP server with an explicit JSON Schema.\n\n\n\n\n\nregister_tool!(server, name, description, handler)\n\nRegister a tool with schema auto-inferred from the handler's type signature.\n\n\n\n\n\nregister_tool!(server, ct::CallableTool{GPTTool})\n\nRegister a CallableTool{GPTTool} on the MCP server, bridging from UniLM's Chat Completions tool type.\n\n\n\n\n\nregister_tool!(server, ct::CallableTool{FunctionTool})\n\nRegister a CallableTool{FunctionTool} on the MCP server, bridging from UniLM's Responses API tool type.\n\n\n\n\n\n","category":"function"},{"location":"api/mcp/#UniLM.register_resource!","page":"MCP Client & Server","title":"UniLM.register_resource!","text":"register_resource!(server, uri, name, handler; mime_type=\"text/plain\", description=nothing)\n\nRegister a static resource on the MCP server.\n\n\n\n\n\n","category":"function"},{"location":"api/mcp/#UniLM.register_resource_template!","page":"MCP Client & Server","title":"UniLM.register_resource_template!","text":"register_resource_template!(server, uri_template, name, handler; mime_type=\"text/plain\", description=nothing)\n\nRegister a URI-templated resource on the MCP server.\n\n\n\n\n\n","category":"function"},{"location":"api/mcp/#UniLM.register_prompt!","page":"MCP Client & Server","title":"UniLM.register_prompt!","text":"register_prompt!(server, name, handler; description=nothing, arguments=Dict{String,Any}[])\n\nRegister a prompt template on the MCP server.\n\n\n\n\n\n","category":"function"},{"location":"api/mcp/#UniLM.serve","page":"MCP Client & Server","title":"UniLM.serve","text":"serve(server::MCPServer; transport=:stdio, kwargs...)\n\nStart the MCP server using the specified transport.\n\nTransports\n\n:stdio (default): Read from stdin, write to stdout. For Claude Desktop/CLI integration.\n:http: HTTP server. Accepts host (default \"127.0.0.1\") and port (default 8080).\n\nExamples\n\nserve(server)                            # stdio (default)\nserve(server; transport=:http, port=3000)  # HTTP on port 3000\n\n\n\n\n\n","category":"function"},{"location":"api/mcp/#UniLM.@mcp_tool","page":"MCP Client & Server","title":"UniLM.@mcp_tool","text":"@mcp_tool server function name(args...)::ReturnType body end\n\nRegister a tool on server with auto-generated JSON Schema from the function signature.\n\nExample\n\nserver = MCPServer(\"calc\", \"1.0.0\")\n@mcp_tool server function add(a::Float64, b::Float64)::String\n    string(a + b)\nend\n\n\n\n\n\n","category":"macro"},{"location":"api/mcp/#UniLM.@mcp_resource","page":"MCP Client & Server","title":"UniLM.@mcp_resource","text":"@mcp_resource server uri_or_template function(args...) body end\n\nRegister a resource or resource template on server. If the URI contains {...} placeholders, it is registered as a template.\n\nExamples\n\n@mcp_resource server \"config://app\" function()\n    read(\"config.toml\", String)\nend\n\n@mcp_resource server \"file://{path}\" function(path::String)\n    read(path, String)\nend\n\n\n\n\n\n","category":"macro"},{"location":"api/mcp/#UniLM.@mcp_prompt","page":"MCP Client & Server","title":"UniLM.@mcp_prompt","text":"@mcp_prompt server name function(args...) body end\n\nRegister a prompt on server. The handler should return a Vector of message Dicts.\n\nExample\n\n@mcp_prompt server \"review\" function(code::String)\n    [Dict(\"role\" => \"user\", \"content\" => Dict(\"type\" => \"text\", \"text\" => \"Review: $code\"))]\nend\n\n\n\n\n\n","category":"macro"},{"location":"api/embeddings/#embeddings_api","page":"Embeddings","title":"Embeddings API","text":"Types and functions for the Embeddings API.","category":"section"},{"location":"api/embeddings/#Embeddings-Object","page":"Embeddings","title":"Embeddings Object","text":"","category":"section"},{"location":"api/embeddings/#Construction","page":"Embeddings","title":"Construction","text":"using UniLM\n\n# Single input\nemb = Embeddings(\"Julia is a great language\")\nprintln(\"Model: \", emb.model)\nprintln(\"Embedding dims: \", length(emb.embeddings))\n\n# Batch input\nbatch = Embeddings([\"Hello\", \"World\", \"Julia\"])\nprintln(\"Batch size: \", length(batch.input))\nprintln(\"Each embedding dims: \", length(batch.embeddings[1]))","category":"section"},{"location":"api/embeddings/#Request-Function","page":"Embeddings","title":"Request Function","text":"","category":"section"},{"location":"api/embeddings/#Model-Constants","page":"Embeddings","title":"Model Constants","text":"println(\"Default embedding model: \", UniLM.GPTTextEmbedding3Small)","category":"section"},{"location":"api/embeddings/#Usage-Example","page":"Embeddings","title":"Usage Example","text":"julia> emb = Embeddings(\"Julia is a high-performance programming language for technical computing.\")\n\njulia> embeddingrequest!(emb)\n\njulia> emb.embeddings[1:5]  # first 5 dimensions\n5-element Vector{Float64}:\n  -0.039474\n  -0.009283\n  0.001706\n  -0.028087\n  0.063363\n\njulia> sqrt(sum(x^2 for x in emb.embeddings))  # L2 norm ≈ 1.0\n1.0","category":"section"},{"location":"api/embeddings/#UniLM.Embeddings","page":"Embeddings","title":"UniLM.Embeddings","text":"Embeddings(input::String)\nEmbeddings(input::Vector{String})\n\nCreate an embedding request for one or more text inputs. Uses the text-embedding-3-small model (1536-dimensional embeddings) by default.\n\nThe embeddings field is pre-allocated and filled in-place by embeddingrequest!.\n\nFields\n\nmodel::String: The embedding model name.\ninput::Union{String,Vector{String}}: Text(s) to embed.\nembeddings::Union{Vector{Float64},Vector{Vector{Float64}}}: Pre-allocated embedding vector(s).\nuser::Union{String,Nothing}: Optional end-user identifier.\n\nExample\n\nemb = Embeddings(\"Julia is a great language\")\nembeddingrequest!(emb)\nemb.embeddings  # => Float64[...] (1536 dims)\n\n\n\n\n\n","category":"type"},{"location":"api/embeddings/#UniLM.embeddingrequest!","page":"Embeddings","title":"UniLM.embeddingrequest!","text":"embeddingrequest!(emb::Embedding)\n\nSend a request to the OpenAI API to generate an embedding for the `input` in `emb`.\n\nResulting embedding is stored in the preallocated `embedding` field.  \n\n@kwdef struct Embedding\n    model::String = \"text-embedding-3-small\"\n    input::Union{String,Vector{String}}\n    embedding::Vector{Float64} = zeros(Float64, 1536)\n    user::Union{String,Nothing} = nothing\nend\n\n\n\n\n\n","category":"function"},{"location":"guide/chat_completions/#chat_guide","page":"Chat Completions","title":"Chat Completions","text":"The Chat Completions API is the classic way to interact with OpenAI's language models. UniLM.jl wraps it in a type-safe, stateful Chat object that tracks conversation history automatically.","category":"section"},{"location":"guide/chat_completions/#Creating-a-Chat","page":"Chat Completions","title":"Creating a Chat","text":"chat = Chat(\n    model=\"gpt-5.2\",        # model name\n    temperature=0.7,        # sampling temperature\n)\nprintln(\"Model: \", chat.model)\nprintln(\"Messages: \", length(chat))\n\nAll parameters are optional with sensible defaults. See Chat for the full list.","category":"section"},{"location":"guide/chat_completions/#Building-Conversations","page":"Chat Completions","title":"Building Conversations","text":"Messages are added with push!. UniLM.jl enforces conversation structure at the type level — you cannot create invalid message sequences:\n\n# System message must come first\npush!(chat, Message(Val(:system), \"You are a helpful Julia programming tutor.\"))\n\n# Then user messages\npush!(chat, Message(Val(:user), \"What are parametric types?\"))\n\nprintln(\"Conversation length: \", length(chat))\nprintln(\"First message role: \", chat[1].role)\nprintln(\"Last message role: \", chat[end].role)\n\nThe convenience Val(:system) and Val(:user) constructors keep things concise. You can also use the keyword constructor:\n\nchat2 = Chat()\npush!(chat2, Message(role=\"system\", content=\"Be helpful\"))\npush!(chat2, Message(role=\"user\", content=\"Tell me more\"))\nprintln(\"chat2 length: \", length(chat2))","category":"section"},{"location":"guide/chat_completions/#Conversation-Rules","page":"Chat Completions","title":"Conversation Rules","text":"The first message must have role system\nMessages must alternate roles (no two consecutive messages from the same role)\nAt least content, tool_calls, or refusal_message must be non-nothing\nAttempting to violate these rules logs a warning and the message is not added\n\n# Demonstrate validation\nchat3 = Chat()\npush!(chat3, Message(Val(:system), \"sys\"))\npush!(chat3, Message(Val(:user), \"hello\"))\npush!(chat3, Message(Val(:user), \"hello again\"))  # rejected — same role\nprintln(\"Length after duplicate push: \", length(chat3), \" (second user msg rejected)\")","category":"section"},{"location":"guide/chat_completions/#Sending-Requests","page":"Chat Completions","title":"Sending Requests","text":"result = chatrequest!(chat)\n\nThe ! suffix is a Julia convention — chatrequest! mutates chat by appending the assistant's response to the message history (when history=true).","category":"section"},{"location":"guide/chat_completions/#Result-Handling","page":"Chat Completions","title":"Result Handling","text":"result = chatrequest!(chat)\nif result isa LLMSuccess\n    println(result.message.content)\n    println(\"\\nFinish reason: \", result.message.finish_reason)\n    println(\"Conversation length: \", length(chat))\nelse\n    println(\"Request failed — see result for details\")\nend","category":"section"},{"location":"guide/chat_completions/#One-Shot-Requests-via-Keywords","page":"Chat Completions","title":"One-Shot Requests via Keywords","text":"Skip the Chat object entirely for simple one-off requests:\n\nresult = chatrequest!(\n    systemprompt=\"You are a calculator. Respond only with the number.\",\n    userprompt=\"What is 42 * 17?\",\n    model=\"gpt-4o-mini\",\n    temperature=0.0\n)\nif result isa LLMSuccess\n    println(result.message.content)\nelse\n    println(\"Request failed — see result for details\")\nend","category":"section"},{"location":"guide/chat_completions/#Multi-Turn-Conversations","page":"Chat Completions","title":"Multi-Turn Conversations","text":"Because chatrequest! appends the response, you can keep chatting:\n\nchat = Chat(model=\"gpt-4o-mini\")\npush!(chat, Message(Val(:system), \"You are a concise Julia programming tutor.\"))\npush!(chat, Message(Val(:user), \"What is multiple dispatch? Answer in 2-3 sentences.\"))\nresult = chatrequest!(chat)\nif result isa LLMSuccess\n    println(result.message.content)\nelse\n    println(\"Request failed — see result for details\")\nend\n\npush!(chat, Message(Val(:user), \"Give a short Julia code example of it.\"))\nresult = chatrequest!(chat)\nif result isa LLMSuccess\n    println(result.message.content)\n    println(\"\\nConversation length: \", length(chat))\nelse\n    println(\"Request failed — see result for details\")\nend","category":"section"},{"location":"guide/chat_completions/#Checking-Conversation-Validity","page":"Chat Completions","title":"Checking Conversation Validity","text":"println(\"Is chat valid? \", issendvalid(chat))  # true — system + user\n\nempty_chat = Chat()\nprintln(\"Is empty chat valid? \", issendvalid(empty_chat))  # false\n\nThis checks:\n\nAt least 2 messages\nFirst message is system\nLast message is user\nNo consecutive same-role messages","category":"section"},{"location":"guide/chat_completions/#Models","page":"Chat Completions","title":"Models","text":"UniLM.jl works with any model name string. Common choices:\n\nModel Usage\n\"gpt-5.2\" Best quality (default)\n\"gpt-4o-mini\" Fast and cheap\n\"gpt-4.1-mini\" Balanced performance\n\"o3\" Extended reasoning\n\"o4-mini\" Fast reasoning","category":"section"},{"location":"guide/chat_completions/#JSON-Serialization","page":"Chat Completions","title":"JSON Serialization","text":"The Chat object serializes cleanly to JSON for the API:\n\nprintln(JSON.json(chat))","category":"section"},{"location":"guide/chat_completions/#Retry-Behaviour","page":"Chat Completions","title":"Retry Behaviour","text":"chatrequest! automatically retries on HTTP 429, 500, and 503 errors with exponential backoff and jitter (up to 30 attempts, max 60s delay). On 429 responses, the Retry-After header is respected. This is transparent and requires no configuration.","category":"section"},{"location":"guide/chat_completions/#Parameter-Validation","page":"Chat Completions","title":"Parameter Validation","text":"The Chat constructor validates parameter ranges at construction time:\n\nParameter Valid Range\ntemperature 0.0–2.0\ntop_p 0.0–1.0\nn 1–10\npresence_penalty -2.0–2.0\nfrequency_penalty -2.0–2.0\n\nOut-of-range values throw ArgumentError. Additionally, temperature and top_p are mutually exclusive.","category":"section"},{"location":"guide/chat_completions/#See-Also","page":"Chat Completions","title":"See Also","text":"Chat — full type reference\nMessage — message type reference\nTool Calling — function calling with Chat Completions\nStreaming — real-time streaming\nStructured Output — JSON-constrained generation","category":"section"},{"location":"guide/tool_calling/#tools_guide","page":"Tool Calling","title":"Tool Calling","text":"Both the Chat Completions and Responses APIs support function/tool calling — the model can decide to invoke functions you define, and you return the results.","category":"section"},{"location":"guide/tool_calling/#Chat-Completions-Tool-Calling","page":"Tool Calling","title":"Chat Completions Tool Calling","text":"","category":"section"},{"location":"guide/tool_calling/#Defining-Tools","page":"Tool Calling","title":"Defining Tools","text":"Wrap your function schema in a GPTTool:\n\nusing UniLM\nusing JSON\n\nweather_tool = GPTTool(\n    func=GPTFunctionSignature(\n        name=\"get_weather\",\n        description=\"Get current weather for a location\",\n        parameters=Dict(\n            \"type\" => \"object\",\n            \"properties\" => Dict(\n                \"location\" => Dict(\"type\" => \"string\", \"description\" => \"City name\"),\n                \"unit\" => Dict(\"type\" => \"string\", \"enum\" => [\"celsius\", \"fahrenheit\"])\n            ),\n            \"required\" => [\"location\"]\n        )\n    )\n)\nprintln(\"Tool type: \", weather_tool.type)\nprintln(\"Function name: \", weather_tool.func.name)\nprintln(\"Tool JSON:\")\nprintln(JSON.json(JSON.lower(weather_tool)))","category":"section"},{"location":"guide/tool_calling/#Making-Tool-Enabled-Requests","page":"Tool Calling","title":"Making Tool-Enabled Requests","text":"chat = Chat(model=\"gpt-5.2\", tools=[weather_tool])\npush!(chat, Message(Val(:system), \"You are a helpful assistant with access to weather data.\"))\npush!(chat, Message(Val(:user), \"What's the weather in Paris?\"))\nprintln(\"Chat has \", length(chat.tools), \" tool(s) registered\")\nprintln(\"Request body:\")\nprintln(JSON.json(chat))","category":"section"},{"location":"guide/tool_calling/#Handling-Tool-Calls","page":"Tool Calling","title":"Handling Tool Calls","text":"When the model wants to call a function, the result message will have finish_reason == \"tool_calls\":\n\nchat = Chat(\n    model=\"gpt-5.2\",\n    tools=[weather_tool],\n    tool_choice=UniLM.GPTToolChoice(func=:get_weather)\n)\npush!(chat, Message(Val(:system), \"Use the provided tools to answer.\"))\npush!(chat, Message(Val(:user), \"What's the weather in Paris?\"))\nresult = chatrequest!(chat)\nif result isa LLMSuccess\n    println(\"Finish reason: \", result.message.finish_reason)\n    tc = result.message.tool_calls[1]\n    println(\"Function: \", tc.func.name)\n    println(\"Arguments: \", JSON.json(tc.func.arguments, 2))\nelse\n    println(\"Request failed — see result for details\")\nend","category":"section"},{"location":"guide/tool_calling/#Controlling-Tool-Choice","page":"Tool Calling","title":"Controlling Tool Choice","text":"# Let the model decide\nchat = Chat(tools=[weather_tool], tool_choice=\"auto\")\n\n# Force the model to use a tool\nchat = Chat(tools=[weather_tool], tool_choice=\"required\")\n\n# Prevent tool use\nchat = Chat(tools=[weather_tool], tool_choice=\"none\")","category":"section"},{"location":"guide/tool_calling/#Responses-API-Tool-Calling","page":"Tool Calling","title":"Responses API Tool Calling","text":"The Responses API makes tool calling more ergonomic with dedicated types.","category":"section"},{"location":"guide/tool_calling/#Function-Tools","page":"Tool Calling","title":"Function Tools","text":"tool = function_tool(\n    \"calculate\",\n    \"Evaluate a math expression\",\n    parameters=Dict(\n        \"type\" => \"object\",\n        \"properties\" => Dict(\n            \"expression\" => Dict(\"type\" => \"string\")\n        ),\n        \"required\" => [\"expression\"]\n    ),\n    strict=true\n)\nprintln(\"Tool: \", tool.name, \" (strict=\", tool.strict, \")\")\nprintln(\"JSON: \", JSON.json(JSON.lower(tool)))\n\nweather_fn = function_tool(\n    \"get_weather\",\n    \"Get current weather for a location\",\n    parameters=Dict(\n        \"type\" => \"object\",\n        \"properties\" => Dict(\n            \"location\" => Dict(\"type\" => \"string\", \"description\" => \"City name\"),\n            \"unit\" => Dict(\"type\" => \"string\", \"enum\" => [\"celsius\", \"fahrenheit\"])\n        ),\n        \"required\" => [\"location\"]\n    )\n)\nresult = respond(\"What's the weather in Tokyo? Use celsius.\", tools=[weather_fn])\ncalls = function_calls(result)\nif !isempty(calls)\n    println(\"Function: \", calls[1][\"name\"])\n    println(\"Arguments: \", JSON.json(JSON.parse(calls[1][\"arguments\"]), 2))\nelse\n    println(\"No function calls — \", output_text(result))\nend","category":"section"},{"location":"guide/tool_calling/#Web-Search","page":"Tool Calling","title":"Web Search","text":"The model can search the web — no function implementation needed:\n\nws = web_search(context_size=\"high\")\nprintln(\"Web search tool type: \", typeof(ws))\nprintln(\"Context size: \", ws.search_context_size)\n\nresult = respond(\n    \"What is the latest stable release of the Julia programming language?\",\n    tools=[web_search()]\n)\nif result isa ResponseSuccess\n    println(output_text(result))\nelse\n    println(\"Request failed — \", output_text(result))\nend","category":"section"},{"location":"guide/tool_calling/#File-Search","page":"Tool Calling","title":"File Search","text":"Search over your uploaded vector stores:\n\nresult = respond(\n    \"Find the error handling policy\",\n    tools=[file_search([\"vs_store_id_123\"], max_results=5)]\n)","category":"section"},{"location":"guide/tool_calling/#Combining-Tools","page":"Tool Calling","title":"Combining Tools","text":"Mix different tool types freely:\n\ntools = [\n    web_search(),\n    function_tool(\"save_summary\", \"Save a summary to the database\",\n        parameters=Dict(\n            \"type\" => \"object\",\n            \"properties\" => Dict(\n                \"title\" => Dict(\"type\" => \"string\"),\n                \"content\" => Dict(\"type\" => \"string\")\n            )\n        )\n    )\n]\nprintln(\"Number of tools: \", length(tools))\nfor t in tools\n    println(\"  - \", typeof(t))\nend","category":"section"},{"location":"guide/tool_calling/#Automated-Tool-Loop","page":"Tool Calling","title":"Automated Tool Loop","text":"Instead of manually handling tool calls, use tool_loop! (Chat Completions) or tool_loop (Responses API) for automatic dispatch:","category":"section"},{"location":"guide/tool_calling/#Chat-Completions","page":"Tool Calling","title":"Chat Completions","text":"ct = CallableTool(weather_tool, (name, args) -> \"22C, sunny in $(args[\"location\"])\")\nprintln(\"Callable tool wrapping: \", ct.tool.func.name)\n\nchat = Chat(model=\"gpt-5.2\", tools=[ct.tool])\npush!(chat, Message(Val(:user), \"What's the weather in Paris?\"))\nresult = tool_loop!(chat; tools=[ct])\n# result.completed == true when the model gives a text response","category":"section"},{"location":"guide/tool_calling/#Responses-API","page":"Tool Calling","title":"Responses API","text":"ct = CallableTool(\n    function_tool(\"get_weather\", \"Get weather\", parameters=Dict(...)),\n    (name, args) -> \"22C, sunny\")\nresult = tool_loop(\"What's the weather?\"; tools=[ct])","category":"section"},{"location":"guide/tool_calling/#MCP-Tool-Integration","page":"Tool Calling","title":"MCP Tool Integration","text":"MCP servers expose tools that integrate directly with the tool loop via mcp_tools and mcp_tools_respond. See the MCP Guide for full details.\n\n# Chat Completions + MCP\nsession = mcp_connect(`npx server`)\ntools = mcp_tools(session)\nchat = Chat(model=\"gpt-5.2\", tools=map(t -> t.tool, tools))\npush!(chat, Message(Val(:user), \"Do something\"))\nresult = tool_loop!(chat; tools)\n\n# Responses API + MCP\ntools = mcp_tools_respond(session)\nresult = tool_loop(\"Do something\"; tools=tools)","category":"section"},{"location":"guide/tool_calling/#See-Also","page":"Tool Calling","title":"See Also","text":"GPTTool, GPTFunctionSignature — Chat Completions tool types\nFunctionTool, WebSearchTool, FileSearchTool — Responses API tool types\nfunction_tool, web_search, file_search — convenience constructors\nCallableTool, ToolCallOutcome, ToolLoopResult — tool loop types\ntool_loop!, tool_loop — automated tool dispatch\nMCP Guide — MCP server integration","category":"section"},{"location":"api/images/#Image-Generation-API","page":"Images","title":"Image Generation API","text":"Types and functions for the Image Generation API (/v1/images/generations).","category":"section"},{"location":"api/images/#Request-Type","page":"Images","title":"Request Type","text":"","category":"section"},{"location":"api/images/#Construction","page":"Images","title":"Construction","text":"using UniLM\nusing JSON\n\n# Minimal request\nig = ImageGeneration(prompt=\"A watercolor painting of a sunset\")\nprintln(\"Model: \", ig.model)\nprintln(\"Prompt: \", ig.prompt)\n\n# Full options\nig2 = ImageGeneration(\n    prompt=\"A minimalist logo for a Julia package\",\n    size=\"1024x1024\",\n    quality=\"high\",\n    background=\"transparent\",\n    output_format=\"png\",\n    n=2\n)\nprintln(\"\\nFull options:\")\nprintln(\"  Size: \", ig2.size)\nprintln(\"  Quality: \", ig2.quality)\nprintln(\"  Background: \", ig2.background)\nprintln(\"  Format: \", ig2.output_format)\nprintln(\"  Count: \", ig2.n)","category":"section"},{"location":"api/images/#JSON-Serialization","page":"Images","title":"JSON Serialization","text":"ig = ImageGeneration(prompt=\"A cute robot\", quality=\"high\", size=\"1024x1024\")\nprintln(JSON.json(ig))","category":"section"},{"location":"api/images/#Response-Types","page":"Images","title":"Response Types","text":"","category":"section"},{"location":"api/images/#Result-Types","page":"Images","title":"Result Types","text":"","category":"section"},{"location":"api/images/#Request-Function","page":"Images","title":"Request Function","text":"","category":"section"},{"location":"api/images/#Usage-Examples","page":"Images","title":"Usage Examples","text":"julia> result = generate_image(\n           \"A watercolor painting of a friendly robot reading a Julia programming book\",\n           size=\"1024x1024\", quality=\"medium\"\n       )\n\njulia> result isa ImageSuccess\ntrue\n\njulia> length(image_data(result))\n1\n\njulia> save_image(image_data(result)[1], \"robot_julia.png\")\n\"robot_julia.png\"","category":"section"},{"location":"api/images/#Accessor-Functions","page":"Images","title":"Accessor Functions","text":"","category":"section"},{"location":"api/images/#Saving-Images","page":"Images","title":"Saving Images","text":"result = generate_image(\"A sunset over mountains\", n=3)\nif result isa ImageSuccess\n    for (i, img) in enumerate(image_data(result))\n        save_image(img, \"sunset_$i.png\")\n    end\nend","category":"section"},{"location":"api/images/#Parameters-Reference","page":"Images","title":"Parameters Reference","text":"Parameter Type Default Description\nmodel String \"gpt-image-1.5\" Image generation model\nprompt String (required) Text description of the image\nn Int 1 Number of images (1–10)\nsize String \"auto\" \"1024x1024\", \"1536x1024\", etc.\nquality String \"auto\" \"low\", \"medium\", \"high\"\nbackground String \"auto\" \"transparent\", \"opaque\"\noutput_format String \"png\" \"png\", \"webp\", \"jpeg\"\noutput_compression Int — 0–100, for webp/jpeg\nuser String — End-user identifier","category":"section"},{"location":"api/images/#UniLM.ImageGeneration","page":"Images","title":"UniLM.ImageGeneration","text":"ImageGeneration(; prompt, model=\"gpt-image-1.5\", kwargs...)\n\nConfiguration struct for an OpenAI Image Generation API request.\n\nKey Fields\n\nmodel::String: Model to use (default: \"gpt-image-1.5\")\nprompt::String: A text description of the desired image\nn::Union{Int,Nothing}: Number of images to generate (1–10)\nsize::Union{String,Nothing}: Size (\"1024x1024\", \"1536x1024\", \"1024x1536\", \"auto\")\nquality::Union{String,Nothing}: Quality level (\"low\", \"medium\", \"high\", \"auto\")\nbackground::Union{String,Nothing}: Background (\"transparent\", \"opaque\", \"auto\")\noutput_format::Union{String,Nothing}: File format (\"png\", \"webp\", \"jpeg\")\noutput_compression::Union{Int,Nothing}: Compression (0–100, for \"webp\" and \"jpeg\")\nuser::Union{String,Nothing}: End-user identifier\n\nExamples\n\n# Simple prompt\nImageGeneration(prompt=\"A watercolor painting of a mountain sunset\")\n\n# With all options\nImageGeneration(\n    prompt=\"A minimalist logo for a Julia package\",\n    size=\"1024x1024\",\n    quality=\"high\",\n    background=\"transparent\",\n    output_format=\"png\"\n)\n\n\n\n\n\n","category":"type"},{"location":"api/images/#UniLM.ImageObject","page":"Images","title":"UniLM.ImageObject","text":"ImageObject\n\nA single generated image from the API response.\n\nFields\n\nb64_json::Union{String,Nothing}: Base64-encoded image data\nrevised_prompt::Union{String,Nothing}: The prompt as revised by the model\n\n\n\n\n\n","category":"type"},{"location":"api/images/#UniLM.ImageResponse","page":"Images","title":"UniLM.ImageResponse","text":"ImageResponse\n\nParsed response from the Image Generation API.\n\nAccessors\n\nimage_data(r) — extract base64-encoded image data\nr.created, r.data, r.usage — basic fields\nr.raw — the complete raw JSON dict\n\nFields\n\ncreated::Int64: Timestamp when the response was created\ndata::Vector{ImageObject}: Generated images\nusage::Union{Dict{String,Any},Nothing}: Token usage information\nraw::Dict{String,Any}: Complete raw JSON response\n\n\n\n\n\n","category":"type"},{"location":"api/images/#UniLM.ImageSuccess","page":"Images","title":"UniLM.ImageSuccess","text":"ImageSuccess <: LLMRequestResponse\n\nSuccessful image generation. Access the parsed response via .response.\n\nExamples\n\nresult = generate_image(\"A cute robot\")\nif result isa ImageSuccess\n    imgs = image_data(result)   # Vector{String} of base64 images\n    save_image(imgs[1], \"robot.png\")\nend\n\n\n\n\n\n","category":"type"},{"location":"api/images/#UniLM.ImageFailure","page":"Images","title":"UniLM.ImageFailure","text":"ImageFailure <: LLMRequestResponse\n\nHTTP-level failure from the Image Generation API. Contains the response body and status code.\n\n\n\n\n\n","category":"type"},{"location":"api/images/#UniLM.ImageCallError","page":"Images","title":"UniLM.ImageCallError","text":"ImageCallError <: LLMRequestResponse\n\nException-level error during an Image Generation API call (network, parsing, etc.).\n\n\n\n\n\n","category":"type"},{"location":"api/images/#UniLM.generate_image","page":"Images","title":"UniLM.generate_image","text":"generate_image(ig::ImageGeneration; retries=0)\n\nSend a request to the OpenAI Image Generation API.\n\nReturns ImageSuccess, ImageFailure, or ImageCallError.\n\nExamples\n\nig = ImageGeneration(prompt=\"A cute robot learning Julia\", quality=\"high\")\nresult = generate_image(ig)\nif result isa ImageSuccess\n    println(\"Generated $(length(result.response.data)) image(s)\")\n    save_image(image_data(result)[1], \"robot.png\")\nend\n\n\n\n\n\ngenerate_image(prompt::String; kwargs...)\n\nConvenience method: create an ImageGeneration from a prompt + keyword arguments and send it.\n\nExamples\n\n# Simple generation\nresult = generate_image(\"A watercolor painting of a Julia butterfly\")\n\n# With options\nresult = generate_image(\n    \"A minimalist logo\",\n    size=\"1024x1024\",\n    quality=\"high\",\n    background=\"transparent\"\n)\n\n# Save to file\nif result isa ImageSuccess\n    save_image(image_data(result)[1], \"logo.png\")\nend\n\n\n\n\n\n","category":"function"},{"location":"api/images/#UniLM.image_data","page":"Images","title":"UniLM.image_data","text":"image_data(r::ImageResponse)::Vector{String}\nimage_data(r::ImageSuccess)::Vector{String}\n\nExtract base64-encoded image data from a response. Returns a vector of base64 strings, one per generated image.\n\nExamples\n\nresult = generate_image(\"A sunset over mountains\")\nimgs = image_data(result)       # Vector{String}\nlength(imgs)                     # number of images generated\n\n\n\n\n\n","category":"function"},{"location":"api/images/#UniLM.save_image","page":"Images","title":"UniLM.save_image","text":"save_image(img_b64::String, filepath::String)\n\nDecode a base64-encoded image and save it to a file.\n\nExamples\n\nresult = generate_image(\"A watercolor landscape\")\nif result isa ImageSuccess\n    save_image(image_data(result)[1], \"landscape.png\")\nend\n\n\n\n\n\n","category":"function"},{"location":"guide/embeddings/#Embeddings","page":"Embeddings","title":"Embeddings","text":"UniLM.jl supports text embeddings via the OpenAI Embeddings API using the text-embedding-3-small model (1536 dimensions) by default.","category":"section"},{"location":"guide/embeddings/#Basic-Usage","page":"Embeddings","title":"Basic Usage","text":"using UniLM\n\n# Single text\nemb = Embeddings(\"Julia is a high-performance programming language\")\nprintln(\"Model: \", emb.model)\nprintln(\"Embedding dimensions: \", length(emb.embeddings))\nprintln(\"Pre-allocated (all zeros): \", all(x -> x == 0.0, emb.embeddings))\n\nAfter calling the API, the embeddings are filled in-place:\n\nemb = Embeddings(\"Julia is a high-performance programming language for technical computing.\")\nembeddingrequest!(emb)\nprintln(\"First 5 dimensions:\")\nfor v in emb.embeddings[1:5]\n    println(\"  \", round(v, digits=6))\nend\nprintln(\"L2 norm: \", round(sqrt(sum(x^2 for x in emb.embeddings)), digits=4))","category":"section"},{"location":"guide/embeddings/#Batch-Embeddings","page":"Embeddings","title":"Batch Embeddings","text":"Embed multiple texts in a single API call:\n\ntexts = [\n    \"Julia is fast\",\n    \"Python is popular\",\n    \"Rust is safe\"\n]\n\nemb = Embeddings(texts)\nprintln(\"Model: \", emb.model)\nprintln(\"Number of texts: \", length(emb.input))\nprintln(\"Embeddings per text: \", length(emb.embeddings[1]), \" dimensions\")\n\nembeddingrequest!(emb)\nprintln(\"Embedding dimensions per text: \", length(emb.embeddings[1]))","category":"section"},{"location":"guide/embeddings/#Computing-Similarity","page":"Embeddings","title":"Computing Similarity","text":"A common use case is computing cosine similarity between embeddings:\n\nusing LinearAlgebra\n\nemb = Embeddings([\"Julia\", \"Python\", \"Rust\", \"Fortran\"])\nembeddingrequest!(emb)\n\nsim = dot(emb.embeddings[1], emb.embeddings[4]) /\n      (norm(emb.embeddings[1]) * norm(emb.embeddings[4]))\nprintln(\"Cosine similarity (Julia vs Fortran): \", round(sim, digits=4))","category":"section"},{"location":"guide/embeddings/#Available-Models","page":"Embeddings","title":"Available Models","text":"Model Dimensions Notes\ntext-embedding-3-small 1536 Default, good balance\ntext-embedding-3-large 3072 Higher quality, more dimensions\n\nnote: Note\nThe default Embeddings constructor pre-allocates for 1536 dimensions (text-embedding-3-small). To use text-embedding-3-large, you would need to adjust the embedding vector size accordingly.","category":"section"},{"location":"guide/embeddings/#In-Place-Design","page":"Embeddings","title":"In-Place Design","text":"The Embeddings struct pre-allocates the embedding vectors at construction time. embeddingrequest! fills them in-place — no allocation on the hot path. This is idiomatic Julia for performance-sensitive workloads.\n\nemb = Embeddings(\"test\")\nprintln(\"Pre-allocated length: \", length(emb.embeddings))\nprintln(\"All zeros before API call: \", all(x -> x == 0.0, emb.embeddings))","category":"section"},{"location":"guide/embeddings/#Retry-Behaviour","page":"Embeddings","title":"Retry Behaviour","text":"embeddingrequest! automatically retries on HTTP 429, 500, and 503 errors with exponential backoff and jitter (up to 30 attempts, max 60s delay). On 429 responses, the Retry-After header is respected.","category":"section"},{"location":"guide/embeddings/#API-Reference","page":"Embeddings","title":"API Reference","text":"See the Embeddings API page for full type documentation.","category":"section"},{"location":"guide/structured_output/#structured_guide","page":"Structured Output","title":"Structured Output","text":"Force the model to produce valid JSON conforming to a schema. Both APIs support this.","category":"section"},{"location":"guide/structured_output/#Chat-Completions","page":"Structured Output","title":"Chat Completions","text":"Use ResponseFormat to control the output format:","category":"section"},{"location":"guide/structured_output/#Free-Form-JSON","page":"Structured Output","title":"Free-Form JSON","text":"using UniLM\nusing JSON\n\nchat = Chat(\n    model=\"gpt-5.2\",\n    response_format=ResponseFormat()  # type=\"json_object\"\n)\npush!(chat, Message(Val(:system), \"You output JSON. Always respond with valid JSON.\"))\npush!(chat, Message(Val(:user), \"List 3 programming languages with their year of creation.\"))\nprintln(\"Response format type: \", chat.response_format.type)\nprintln(\"Request body:\")\nprintln(JSON.json(chat))\n\nresult = chatrequest!(chat)\nif result isa LLMSuccess\n    println(JSON.json(JSON.parse(result.message.content), 2))\nelse\n    println(\"Request failed — see result for details\")\nend","category":"section"},{"location":"guide/structured_output/#JSON-Schema-(Strict)","page":"Structured Output","title":"JSON Schema (Strict)","text":"schema = ResponseFormat(UniLM.JsonSchemaAPI(\n    name=\"languages\",\n    description=\"A list of programming languages\",\n    schema=Dict(\n        \"type\" => \"object\",\n        \"properties\" => Dict(\n            \"languages\" => Dict(\n                \"type\" => \"array\",\n                \"items\" => Dict(\n                    \"type\" => \"object\",\n                    \"properties\" => Dict(\n                        \"name\" => Dict(\"type\" => \"string\"),\n                        \"year\" => Dict(\"type\" => \"integer\")\n                    ),\n                    \"required\" => [\"name\", \"year\"]\n                )\n            )\n        ),\n        \"required\" => [\"languages\"]\n    )\n))\n\nchat = Chat(model=\"gpt-5.2\", response_format=schema)\npush!(chat, Message(Val(:system), \"Return structured data about programming languages.\"))\npush!(chat, Message(Val(:user), \"List Julia, Python, and Rust\"))\nprintln(\"Schema name: \", schema.json_schema.name)\nprintln(\"Response format type: \", schema.type)\n\nresult = chatrequest!(chat)\nif result isa LLMSuccess\n    println(JSON.json(JSON.parse(result.message.content), 2))\nelse\n    println(\"Request failed — see result for details\")\nend","category":"section"},{"location":"guide/structured_output/#Responses-API","page":"Structured Output","title":"Responses API","text":"The Responses API uses TextConfig with convenience constructors:","category":"section"},{"location":"guide/structured_output/#JSON-Object","page":"Structured Output","title":"JSON Object","text":"result = respond(\"List 3 colors as a JSON object\", text=json_object_format())\nif result isa ResponseSuccess\n    println(output_text(result))\nelse\n    println(\"Request failed — \", output_text(result))\nend","category":"section"},{"location":"guide/structured_output/#JSON-Schema","page":"Structured Output","title":"JSON Schema","text":"fmt = json_schema_format(\n    \"colors\",\n    \"A structured list of colors\",\n    Dict(\n        \"type\" => \"object\",\n        \"properties\" => Dict(\n            \"colors\" => Dict(\n                \"type\" => \"array\",\n                \"items\" => Dict(\n                    \"type\" => \"object\",\n                    \"properties\" => Dict(\n                        \"name\" => Dict(\"type\" => \"string\"),\n                        \"hex\" => Dict(\"type\" => \"string\")\n                    ),\n                    \"required\" => [\"name\", \"hex\"],\n                    \"additionalProperties\" => false\n                )\n            )\n        ),\n        \"required\" => [\"colors\"],\n        \"additionalProperties\" => false\n    ),\n    strict=true\n)\nprintln(\"Format type: \", fmt.format.type)\nprintln(\"Schema strict: \", fmt.format.strict)\n\nresult = respond(\"List red, green, and blue with their hex codes\", text=fmt)\nif result isa ResponseSuccess\n    println(JSON.json(JSON.parse(output_text(result)), 2))\nelse\n    println(\"Request failed — \", output_text(result))\nend","category":"section"},{"location":"guide/structured_output/#Plain-Text-Format","page":"Structured Output","title":"Plain Text Format","text":"tc = text_format()\nprintln(\"Default format type: \", tc.format.type)","category":"section"},{"location":"guide/structured_output/#Convenience-Constructors","page":"Structured Output","title":"Convenience Constructors","text":"Constructor Format\njson_object_format() Unstructured JSON\njson_schema_format(name, desc, schema) Schema-constrained JSON\ntext_format() Plain text (default)","category":"section"},{"location":"guide/structured_output/#See-Also","page":"Structured Output","title":"See Also","text":"ResponseFormat — Chat Completions format type\nTextConfig, TextFormatSpec — Responses API format types","category":"section"},{"location":"guide/multi_backend/#backend_guide","page":"Multi-Backend","title":"Multi-Backend Support","text":"UniLM.jl supports multiple LLM service backends through the ServiceEndpoint type hierarchy. Switching backends requires only changing the service parameter.","category":"section"},{"location":"guide/multi_backend/#Available-Backends","page":"Multi-Backend","title":"Available Backends","text":"Backend Type Env Variables\nOpenAI (default) OPENAIServiceEndpoint OPENAI_API_KEY\nAzure OpenAI AZUREServiceEndpoint AZURE_OPENAI_BASE_URL, AZURE_OPENAI_API_KEY, AZURE_OPENAI_API_VERSION\nGoogle Gemini GEMINIServiceEndpoint GEMINI_API_KEY","category":"section"},{"location":"guide/multi_backend/#OpenAI-(Default)","page":"Multi-Backend","title":"OpenAI (Default)","text":"using UniLM\nusing JSON\n\n# OpenAI is the default — no need to specify service\nchat = Chat(model=\"gpt-5.2\")\nprintln(\"Service: \", chat.service)\nprintln(\"Model: \", chat.model)","category":"section"},{"location":"guide/multi_backend/#Azure-OpenAI","page":"Multi-Backend","title":"Azure OpenAI","text":"# Set environment variables\nENV[\"AZURE_OPENAI_BASE_URL\"] = \"https://your-resource.openai.azure.com\"\nENV[\"AZURE_OPENAI_API_KEY\"] = \"your-key\"\nENV[\"AZURE_OPENAI_API_VERSION\"] = \"2024-02-01\"\nENV[\"AZURE_OPENAI_DEPLOY_NAME_GPT_5_2\"] = \"your-gpt52-deployment\"\n\n# Use Azure\nchat = Chat(service=AZUREServiceEndpoint, model=\"gpt-5.2\")\npush!(chat, Message(Val(:system), \"Hello from Azure!\"))\npush!(chat, Message(Val(:user), \"Hi!\"))\nresult = chatrequest!(chat)","category":"section"},{"location":"guide/multi_backend/#Custom-Deployment-Names","page":"Multi-Backend","title":"Custom Deployment Names","text":"If your Azure deployment has a custom name:\n\nUniLM.add_azure_deploy_name!(\"my-custom-model\", \"my-deployment-name\")\nprintln(\"Registered deployments: \", collect(keys(UniLM._MODEL_ENDPOINTS_AZURE_OPENAI)))\ndelete!(UniLM._MODEL_ENDPOINTS_AZURE_OPENAI, \"my-custom-model\")  # cleanup","category":"section"},{"location":"guide/multi_backend/#Google-Gemini","page":"Multi-Backend","title":"Google Gemini","text":"ENV[\"GEMINI_API_KEY\"] = \"your-gemini-key\"\n\nchat = Chat(service=GEMINIServiceEndpoint, model=\"gemini-2.5-flash\")\npush!(chat, Message(Val(:system), \"You are a helpful assistant.\"))\npush!(chat, Message(Val(:user), \"Hello!\"))\nresult = chatrequest!(chat)\n\nAvailable Gemini models:\n\n\"gemini-2.5-flash\"\n\"gemini-2.5-pro\"","category":"section"},{"location":"guide/multi_backend/#Responses-API-Backend","page":"Multi-Backend","title":"Responses API Backend","text":"The Responses API also supports the service parameter:\n\nr = Respond(\n    service=UniLM.OPENAIServiceEndpoint,\n    model=\"gpt-5.2\",\n    input=\"Hello!\",\n)\nprintln(\"Service: \", r.service)\nprintln(\"Model: \", r.model)","category":"section"},{"location":"guide/multi_backend/#OpenAI-Compatible-Providers-(Generic-Endpoint)","page":"Multi-Backend","title":"OpenAI-Compatible Providers (Generic Endpoint)","text":"Any provider that implements the OpenAI-compatible /v1/chat/completions endpoint can be used with GenericOpenAIEndpoint. This includes Ollama, vLLM, LM Studio, Mistral, and many others.","category":"section"},{"location":"guide/multi_backend/#Ollama-(local)","page":"Multi-Backend","title":"Ollama (local)","text":"ep = OllamaEndpoint()  # defaults to http://localhost:11434\nchat = Chat(service=ep, model=\"llama3.1\")\nprintln(\"URL: \", UniLM.get_url(chat))","category":"section"},{"location":"guide/multi_backend/#Mistral","page":"Multi-Backend","title":"Mistral","text":"chat = Chat(service=MistralEndpoint(), model=\"mistral-large-latest\")\nresult = chatrequest!(chat)","category":"section"},{"location":"guide/multi_backend/#DeepSeek","page":"Multi-Backend","title":"DeepSeek","text":"chat = Chat(service=DeepSeekEndpoint(), model=\"deepseek-chat\")       # V3.2\nchat = Chat(service=DeepSeekEndpoint(), model=\"deepseek-reasoner\")   # V3.2 thinking mode","category":"section"},{"location":"guide/multi_backend/#vLLM-/-LM-Studio","page":"Multi-Backend","title":"vLLM / LM Studio","text":"# vLLM\nchat = Chat(service=GenericOpenAIEndpoint(\"http://localhost:8000\", \"\"), model=\"meta-llama/Llama-3.1-8B\")\n\n# LM Studio\nchat = Chat(service=GenericOpenAIEndpoint(\"http://localhost:1234\", \"\"), model=\"loaded-model\")","category":"section"},{"location":"guide/multi_backend/#Anthropic-(compatibility-layer)","page":"Multi-Backend","title":"Anthropic (compatibility layer)","text":"Anthropic provides an OpenAI-compatible endpoint for evaluation purposes. Note: Anthropic considers this \"not a long-term or production-ready solution\" — features like response_format and strict are ignored.\n\nchat = Chat(\n    service=GenericOpenAIEndpoint(\"https://api.anthropic.com/v1\", ENV[\"ANTHROPIC_API_KEY\"]),\n    model=\"claude-sonnet-4-6\"\n)","category":"section"},{"location":"guide/multi_backend/#Custom-Provider","page":"Multi-Backend","title":"Custom Provider","text":"ep = GenericOpenAIEndpoint(\"https://my-llm-server.example.com\", \"sk-my-key\")\nchat = Chat(service=ep, model=\"my-model\")\nprintln(\"URL: \", UniLM.get_url(chat))\nprintln(\"Has auth: \", any(p -> p.first == \"Authorization\", UniLM.auth_header(ep)))","category":"section"},{"location":"guide/multi_backend/#Embeddings-with-Generic-Endpoint","page":"Multi-Backend","title":"Embeddings with Generic Endpoint","text":"Embeddings also support the service parameter:\n\nemb = Embeddings(\"test\"; service=OllamaEndpoint(), model=\"nomic-embed-text\")\nprintln(\"URL: \", UniLM.get_url(emb))","category":"section"},{"location":"guide/multi_backend/#API-Compatibility-Tiers","page":"Multi-Backend","title":"API Compatibility Tiers","text":"API Surface Standard Status Supported Providers\nChat Completions De facto standard OpenAI, Azure, Gemini, Mistral, DeepSeek, Ollama, vLLM, LM Studio, Anthropic*\nEmbeddings Widely adopted OpenAI, Gemini, Mistral, Ollama, vLLM\nResponses API Emerging (Open Responses) OpenAI, Ollama, vLLM, Amazon Bedrock\nFIM Completion Provider-specific DeepSeek (beta), Ollama, vLLM\nImage Generation Limited OpenAI, Gemini, Ollama\n\n*Anthropic compat layer is not production-recommended by Anthropic.","category":"section"},{"location":"guide/multi_backend/#Querying-Provider-Capabilities","page":"Multi-Backend","title":"Querying Provider Capabilities","text":"Use has_capability to check what a provider supports before making requests:\n\nfor (name, svc) in [\n    (\"OpenAI\", OPENAIServiceEndpoint),\n    (\"DeepSeek\", DeepSeekEndpoint(\"k\")),\n    (\"Ollama\", OllamaEndpoint())\n]\n    caps = join(sort(collect(provider_capabilities(svc))), \", \")\n    println(\"$name: $caps\")\nend\n\n# Check specific capabilities\nprintln(\"DeepSeek FIM: \", has_capability(DeepSeekEndpoint(\"k\"), :fim))\nprintln(\"OpenAI FIM: \", has_capability(OPENAIServiceEndpoint, :fim))","category":"section"},{"location":"guide/multi_backend/#See-Also","page":"Multi-Backend","title":"See Also","text":"ServiceEndpoint, GenericOpenAIEndpoint — endpoint types\nOllamaEndpoint, MistralEndpoint — convenience constructors\nOPENAIServiceEndpoint, AZUREServiceEndpoint, GEMINIServiceEndpoint — built-in backends","category":"section"},{"location":"api/chat/#chat_api","page":"Chat Types","title":"Chat Completions API","text":"Types and functions for the Chat Completions API.","category":"section"},{"location":"api/chat/#Chat-Object","page":"Chat Types","title":"Chat Object","text":"","category":"section"},{"location":"api/chat/#Messages","page":"Chat Types","title":"Messages","text":"","category":"section"},{"location":"api/chat/#Convenience-Constructors","page":"Chat Types","title":"Convenience Constructors","text":"using UniLM\n\nsys = Message(Val(:system), \"You are a helpful assistant\")\nusr = Message(Val(:user), \"Hello!\")\nprintln(\"System role: \", sys.role)\nprintln(\"User role: \", usr.role)\nprintln(\"User content: \", usr.content)","category":"section"},{"location":"api/chat/#Conversation-Management","page":"Chat Types","title":"Conversation Management","text":"","category":"section"},{"location":"api/chat/#Building-a-Conversation","page":"Chat Types","title":"Building a Conversation","text":"chat = Chat(model=\"gpt-5.2\")\npush!(chat, Message(Val(:system), \"You are a helpful assistant\"))\npush!(chat, Message(Val(:user), \"What is Julia?\"))\nprintln(\"Messages: \", length(chat))\nprintln(\"Valid for sending: \", issendvalid(chat))","category":"section"},{"location":"api/chat/#Tools","page":"Chat Types","title":"Tools","text":"","category":"section"},{"location":"api/chat/#Output-Format","page":"Chat Types","title":"Output Format","text":"using JSON\n\n# JSON object format\nfmt = ResponseFormat()\nprintln(\"Type: \", fmt.type)\nprintln(\"JSON: \", JSON.json(fmt))","category":"section"},{"location":"api/chat/#Request-Function","page":"Chat Types","title":"Request Function","text":"","category":"section"},{"location":"api/chat/#Role-Constants","page":"Chat Types","title":"Role Constants","text":"","category":"section"},{"location":"api/chat/#Tool-Loop","page":"Chat Types","title":"Tool Loop","text":"","category":"section"},{"location":"api/chat/#Model-Constants","page":"Chat Types","title":"Model Constants","text":"println(\"GPT5_2: \", UniLM.GPT5_2)","category":"section"},{"location":"api/chat/#UniLM.Chat","page":"Chat Types","title":"UniLM.Chat","text":"chat = Chat()\n\nCreates a new Chat object with default settings:\n\nmodel is set to gpt-5.2\nmessages is set to an empty Vector{Message}\nhistory is set to true\n\n\n\n\n\n","category":"type"},{"location":"api/chat/#UniLM.Message","page":"Chat Types","title":"UniLM.Message","text":"Message(; role, content=nothing, name=nothing, finish_reason=nothing, refusal_message=nothing, tool_calls=nothing, tool_call_id=nothing)\n\nRepresents a single message in a Chat Completions conversation.\n\nFields\n\nrole::String: One of RoleSystem, RoleUser, RoleAssistant, or RoleTool.\ncontent::Union{String,Nothing}: The text content of the message.\nname::Union{String,Nothing}: Optional name for the participant.\nfinish_reason::Union{String,Nothing}: Why the model stopped generating (e.g. \"stop\", \"tool_calls\").\nrefusal_message::Union{String,Nothing}: Refusal text when content is filtered.\ntool_calls::Union{Nothing,Vector{GPTToolCall}}: Tool calls requested by the assistant.\ntool_call_id::Union{String,Nothing}: Required when role is \"tool\" — the ID of the tool call being responded to.\n\nValidation\n\nAt least one of content, tool_calls, or refusal_message must be non-nothing.\ntool_call_id is required when role == \"tool\".\n\nConvenience Constructors\n\nMessage(Val(:system), \"You are a helpful assistant\")\nMessage(Val(:user), \"Hello!\")\n\n\n\n\n\n","category":"type"},{"location":"api/chat/#UniLM.issendvalid","page":"Chat Types","title":"UniLM.issendvalid","text":"is_send_valid(chat::Chat)::Bool\n\nCheck if the conversation is valid for sending to the API.\n\nThis check employs a rough heuristic that works for practical purposes. \n        \nIt checks if the conversation has at least two messages, the first message is from the system, the last message is from the user, and there are no consecutive messages from the same role. However, this is not a foolproof check and may not work in all cases (e.g. imagine that you passed another system message in the middle of the conversation).\n\n\n\n\n\n","category":"function"},{"location":"api/chat/#UniLM.update!","page":"Chat Types","title":"UniLM.update!","text":"update!(chat::Chat, msg::Message)\n\nUpdate the chat with a new message.\n\n\n\n\n\n","category":"function"},{"location":"api/chat/#UniLM.GPTTool","page":"Chat Types","title":"UniLM.GPTTool","text":"GPTTool(; type=\"function\", func)\n\nWraps a GPTFunctionSignature for use in the tools parameter of a Chat.\n\nExample\n\ntool = GPTTool(func=GPTFunctionSignature(\n    name=\"get_weather\",\n    description=\"Get the current weather\",\n    parameters=Dict(\"type\" => \"object\", \"properties\" => Dict())\n))\nchat = Chat(tools=[tool])\n\n\n\n\n\n","category":"type"},{"location":"api/chat/#UniLM.GPTFunctionSignature","page":"Chat Types","title":"UniLM.GPTFunctionSignature","text":"GPTFunctionSignature(; name, description=nothing, parameters=nothing)\n\nDescribes a function that can be called by the model in the Chat Completions API.\n\nFields\n\nname::String: The name of the function.\ndescription::Union{String,Nothing}: A description of what the function does.\nparameters::Union{AbstractDict,Nothing}: JSON Schema object describing the function parameters.\n\nExample\n\nsig = GPTFunctionSignature(\n    name=\"get_weather\",\n    description=\"Get the current weather in a given location\",\n    parameters=Dict(\n        \"type\" => \"object\",\n        \"properties\" => Dict(\n            \"location\" => Dict(\"type\" => \"string\", \"description\" => \"The city\")\n        ),\n        \"required\" => [\"location\"]\n    )\n)\n\n\n\n\n\n","category":"type"},{"location":"api/chat/#UniLM.GPTToolCall","page":"Chat Types","title":"UniLM.GPTToolCall","text":"GPTToolCall(; id, type=\"function\", func)\n\nRepresents a tool call returned by the model. Contains the call id (used to match results back), the tool type, and the [GPTFunction] with name and parsed arguments.\n\n\n\n\n\n","category":"type"},{"location":"api/chat/#UniLM.GPTFunctionCallResult","page":"Chat Types","title":"UniLM.GPTFunctionCallResult","text":"GPTFunctionCallResult{T}\n\nHolds the result of executing a function that was requested by the model via a tool call.\n\nFields\n\nname::Union{String,Symbol}: The function name.\norigincall::GPTFunction: The original [GPTFunction] call from the model.\nresult::T: The result of executing the function.\n\n\n\n\n\n","category":"type"},{"location":"api/chat/#UniLM.ResponseFormat","page":"Chat Types","title":"UniLM.ResponseFormat","text":"ResponseFormat(; type=\"json_object\", json_schema=nothing)\nResponseFormat(json_schema)\n\nSpecifies the output format for Chat Completions.\n\nFields\n\ntype::String: \"json_object\" or \"json_schema\".\njson_schema::Union{JsonSchemaAPI,AbstractDict,Nothing}: Schema definition when type is \"json_schema\".\n\nExamples\n\n# Free-form JSON\nfmt = ResponseFormat()\n\n# Structured JSON via schema\nfmt = ResponseFormat(JsonSchemaAPI(\n    name=\"result\",\n    description=\"A structured result\",\n    schema=Dict(\"type\" => \"object\", \"properties\" => Dict())\n))\n\nnote: Note\nUse the convenience constructors json_object() and json_schema() for cleaner code.\n\n\n\n\n\n","category":"type"},{"location":"api/chat/#UniLM.chatrequest!","page":"Chat Types","title":"UniLM.chatrequest!","text":"chatrequest!(chat::Chat, retries=0, callback=nothing)\n\nSend a request to the OpenAI API to generate a response to the messages in conv.\n\nThe callback function is called for each chunk of the response. The close Ref is also passed to the callback function, which can be used to close the stream (for example when not satisfied with the intermediate results and want to stop the stream).\n\nThe signature of the callback function is:\n    `callback(chunk::Union{String, Message}, close::Ref{Bool})`\n\n\n\n\n\nFlexible keyword arguments usage\n\nchatrequest!(; kwargs...) Send a request to the OpenAI API to generate a response to the messages in conv.\n\nKeyword Arguments\n\nservice::Type{<:ServiceEndpoint} = AZUREServiceEndpoint: The service endpoint to use (e.g., AZUREServiceEndpoint, OPENAIServiceEndpoint).\nmodel::String = \"gpt-5.2\": The model to use for the chat completion.\nsystemprompt::Union{Message,String}: The system prompt message.\nuserprompt::Union{Message,String}: The user prompt message.\nmessages::Conversation = Message[]: The conversation history or the system/prompt messages.\nhistory::Bool = true: Whether to include the conversation history in the request.\ntools::Union{Vector{GPTTool},Nothing} = nothing: A list of tools the model may call.\ntool_choice::Union{String,GPTToolChoice,Nothing} = nothing: Controls which (if any) function is called by the model. e.g. \"auto\", \"none\", GPTToolChoice.\nparallel_tool_calls::Union{Bool,Nothing} = false: Whether to enable parallel function calling.\ntemperature::Union{Float64,Nothing} = nothing: Sampling temperature (0.0-2.0). Higher values make output more random. Mutually exclusive with top_p.\ntop_p::Union{Float64,Nothing} = nothing: Nucleus sampling parameter (0.0-1.0). Mutually exclusive with temperature.\nn::Union{Int64,Nothing} = nothing: How many chat completion choices to generate for each input message (1-10).\nstream::Union{Bool,Nothing} = nothing: If set, partial message deltas will be sent, like in ChatGPT.\nstop::Union{Vector{String},String,Nothing} = nothing: Up to 4 sequences where the API will stop generating further tokens.\nmax_tokens::Union{Int64,Nothing} = nothing: The maximum number of tokens to generate in the chat completion.\npresence_penalty::Union{Float64,Nothing} = nothing: Number between -2.0 and 2.0. Positive values penalize new tokens based on whether they appear in the text so far.\nresponse_format::Union{ResponseFormat,Nothing} = nothing: An object specifying the format that the model must output. e.g., ResponseFormat(type=\"json_object\").\nfrequency_penalty::Union{Float64,Nothing} = nothing: Number between -2.0 and 2.0. Positive values penalize new tokens based on their existing frequency in the text so far.\nlogit_bias::Union{AbstractDict{String,Float64},Nothing} = nothing: Modify the likelihood of specified tokens appearing in the completion.\nuser::Union{String,Nothing} = nothing: A unique identifier representing your end-user, which can help OpenAI to monitor and detect abuse.\nseed::Union{Int64,Nothing} = nothing: This feature is in Beta. If specified, the system will make a best effort to sample deterministically.\n\n\n\n\n\n","category":"function"},{"location":"api/chat/#UniLM.RoleSystem","page":"Chat Types","title":"UniLM.RoleSystem","text":"RoleSystem\n\nRole constant \"system\" — used for system-level instructions.\n\n\n\n\n\n","category":"constant"},{"location":"api/chat/#UniLM.RoleUser","page":"Chat Types","title":"UniLM.RoleUser","text":"RoleUser\n\nRole constant \"user\" — used for user messages.\n\n\n\n\n\n","category":"constant"},{"location":"api/chat/#UniLM.RoleAssistant","page":"Chat Types","title":"UniLM.RoleAssistant","text":"RoleAssistant\n\nRole constant \"assistant\" — used for model-generated messages.\n\n\n\n\n\n","category":"constant"},{"location":"api/chat/#UniLM.CallableTool","page":"Chat Types","title":"UniLM.CallableTool","text":"CallableTool{T}(tool, callable)\n\nWraps a tool schema T (GPTTool or FunctionTool) with a callable. JSON serialization delegates to the inner tool, preserving backward compatibility.\n\nFields\n\ntool::T: The tool schema.\ncallable::Function: (name::String, args::Dict{String,Any}) -> String\n\nExample\n\ntool = GPTTool(func=GPTFunctionSignature(name=\"add\", description=\"Add two numbers\",\n    parameters=Dict(\"type\"=>\"object\",\"properties\"=>Dict(\"a\"=>Dict(\"type\"=>\"number\"),\"b\"=>Dict(\"type\"=>\"number\")))))\nct = CallableTool(tool, (name, args) -> string(args[\"a\"] + args[\"b\"]))\n\n\n\n\n\n","category":"type"},{"location":"api/chat/#UniLM.ToolCallOutcome","page":"Chat Types","title":"UniLM.ToolCallOutcome","text":"ToolCallOutcome\n\nPer-call record from a tool dispatch.\n\nFields\n\ntool_name::String: Name of the tool that was called.\narguments::Dict{String,Any}: Arguments passed to the tool.\nresult::Union{GPTFunctionCallResult,Nothing}: The result wrapper, or nothing on failure.\nsuccess::Bool: Whether the dispatch succeeded.\nerror::Union{String,Nothing}: Error message on failure.\n\n\n\n\n\n","category":"type"},{"location":"api/chat/#UniLM.ToolLoopResult","page":"Chat Types","title":"UniLM.ToolLoopResult","text":"ToolLoopResult\n\nResult of a tool dispatch loop.\n\nFields\n\nresponse::LLMRequestResponse: The final API response.\ntool_calls::Vector{ToolCallOutcome}: History of all tool dispatches.\nturns_used::Int: Number of API round-trips.\ncompleted::Bool: Whether the loop terminated normally (text response).\nllm_error::Union{String,Nothing}: Error message if not completed.\n\n\n\n\n\n","category":"type"},{"location":"api/chat/#UniLM.tool_loop!","page":"Chat Types","title":"UniLM.tool_loop!","text":"tool_loop!(chat::Chat, dispatcher::Function; max_turns=10, retries=0, callback=nothing, on_tool_call=nothing) -> ToolLoopResult\n\nRun a tool-calling loop on a Chat. Repeatedly calls chatrequest!, dispatches tool calls via dispatcher(name, args), pushes tool-role messages back, and repeats until a text response, API error, or max_turns.\n\nArguments\n\ndispatcher: (name::String, args::Dict{String,Any}) -> String\nmax_turns: Maximum API round-trips (default 10).\nretries: Retry count passed to chatrequest!.\ncallback: Streaming callback passed to chatrequest!.\non_tool_call: Tool call notification callback passed to chatrequest!.\n\nExample\n\nchat = Chat(model=\"gpt-5-mini\", tools=[tool])\npush!(chat, Message(Val(:system), \"You are a calculator\"))\npush!(chat, Message(Val(:user), \"What is 3+5?\"))\nresult = tool_loop!(chat, (name, args) -> string(args[\"a\"] + args[\"b\"]))\n\n\n\n\n\ntool_loop!(chat::Chat; tools::Vector{<:CallableTool}, kwargs...) -> ToolLoopResult\n\nNo-dispatcher variant: builds a dispatcher from CallableTool entries.\n\n\n\n\n\n","category":"function"},{"location":"api/chat/#UniLM.tool_loop","page":"Chat Types","title":"UniLM.tool_loop","text":"tool_loop(r::Respond, dispatcher::Function; max_turns=10, retries=0) -> ToolLoopResult\n\nRun a tool-calling loop on a Respond request. Dispatches function calls via dispatcher(name, args), builds function_call_output input items, and chains via previous_response_id.\n\n\n\n\n\ntool_loop(r::Respond; max_turns=10, retries=0) -> ToolLoopResult\n\nNo-dispatcher variant: extracts callables from CallableTool entries in r.tools.\n\n\n\n\n\ntool_loop(input, dispatcher::Function; tools, kwargs...) -> ToolLoopResult\n\nConvenience form: creates a Respond and runs the tool loop.\n\n\n\n\n\n","category":"function"},{"location":"api/chat/#UniLM.to_tool","page":"Chat Types","title":"UniLM.to_tool","text":"to_tool(x)\n\nOverloadable conversion protocol. Identity for GPTTool, FunctionTool, CallableTool. Converts AbstractDict to GPTTool. Package extensions can add methods for other types.\n\n\n\n\n\nConvert an MCPServerTool to a FunctionTool for use with the Responses API.\n\n\n\n\n\n","category":"function"},{"location":"api/completions/#fim_api","page":"FIM Types","title":"FIM Types","text":"Types and functions for FIM (Fill-in-the-Middle) Completion and Chat Prefix Completion.","category":"section"},{"location":"api/completions/#Request-Type","page":"FIM Types","title":"Request Type","text":"","category":"section"},{"location":"api/completions/#Response-Types","page":"FIM Types","title":"Response Types","text":"","category":"section"},{"location":"api/completions/#Result-Types","page":"FIM Types","title":"Result Types","text":"","category":"section"},{"location":"api/completions/#Request-Functions","page":"FIM Types","title":"Request Functions","text":"","category":"section"},{"location":"api/completions/#Example","page":"FIM Types","title":"Example","text":"using UniLM\nusing JSON\n\nfim = FIMCompletion(\n    service=DeepSeekEndpoint(\"demo\"),\n    prompt=\"def add(a, b):\",\n    suffix=\"    return result\",\n    max_tokens=64\n)\nprintln(\"JSON body:\")\nprintln(JSON.json(fim, 2))","category":"section"},{"location":"api/completions/#UniLM.FIMCompletion","page":"FIM Types","title":"UniLM.FIMCompletion","text":"FIMCompletion(; service, model, prompt, suffix=nothing, max_tokens=128, ...)\n\nA Fill-in-the-Middle completion request. The model generates text between prompt (prefix) and suffix.\n\nSupported by DeepSeekEndpoint (beta), Ollama, vLLM.\n\nExample\n\nfim = FIMCompletion(service=DeepSeekEndpoint(), prompt=\"def fib(a):\",\n    suffix=\"    return fib(a-1) + fib(a-2)\", max_tokens=128)\nresult = fim_complete(fim)\nprintln(fim_text(result))\n\n\n\n\n\n","category":"type"},{"location":"api/completions/#UniLM.FIMChoice","page":"FIM Types","title":"UniLM.FIMChoice","text":"FIMChoice\n\nA single completion choice from a FIM response.\n\nFields\n\ntext::String: The generated text\nindex::Int: Choice index (default 0)\nfinish_reason::Union{String,Nothing}: Why generation stopped (e.g. \"stop\", \"length\")\n\n\n\n\n\n","category":"type"},{"location":"api/completions/#UniLM.FIMResponse","page":"FIM Types","title":"UniLM.FIMResponse","text":"FIMResponse\n\nParsed FIM completion response containing choices, usage, and raw data.\n\nFields\n\nchoices::Vector{FIMChoice}: Generated completions\nusage::Union{TokenUsage,Nothing}: Token usage statistics\nmodel::String: Model that generated the response\nraw::Dict{String,Any}: Complete raw JSON response\n\n\n\n\n\n","category":"type"},{"location":"api/completions/#UniLM.FIMSuccess","page":"FIM Types","title":"UniLM.FIMSuccess","text":"Successful FIM completion result.\n\n\n\n\n\n","category":"type"},{"location":"api/completions/#UniLM.FIMFailure","page":"FIM Types","title":"UniLM.FIMFailure","text":"HTTP-level failure from FIM completion.\n\n\n\n\n\n","category":"type"},{"location":"api/completions/#UniLM.FIMCallError","page":"FIM Types","title":"UniLM.FIMCallError","text":"Exception-level error during FIM completion.\n\n\n\n\n\n","category":"type"},{"location":"api/completions/#UniLM.fim_complete","page":"FIM Types","title":"UniLM.fim_complete","text":"fim_complete(fim::FIMCompletion; retries=0) -> LLMRequestResponse\n\nExecute a FIM (Fill-in-the-Middle) completion request. Returns FIMSuccess, FIMFailure, or FIMCallError.\n\n\n\n\n\nfim_complete(prompt::String; suffix=nothing, kwargs...) -> LLMRequestResponse\n\nConvenience form: creates a FIMCompletion and executes it.\n\n\n\n\n\n","category":"function"},{"location":"api/completions/#UniLM.fim_text","page":"FIM Types","title":"UniLM.fim_text","text":"fim_text(result) -> String\n\nExtract the generated text from a FIM completion result.\n\n\n\n\n\n","category":"function"},{"location":"api/completions/#UniLM.prefix_complete","page":"FIM Types","title":"UniLM.prefix_complete","text":"prefix_complete(chat::Chat; retries=0) -> LLMRequestResponse\n\nChat prefix completion: the model continues from a partial assistant message. The last message in chat must be role=assistant containing the text prefix to continue from.\n\nSupported by DeepSeekEndpoint (beta).\n\nExample\n\nchat = Chat(service=DeepSeekEndpoint(), model=\"deepseek-chat\")\npush!(chat, Message(Val(:user), \"Write a quicksort in Python\"))\npush!(chat, Message(role=RoleAssistant, content=\"```python\\n\"))\nresult = prefix_complete(chat)\n\n\n\n\n\n","category":"function"},{"location":"guide/completions/#completions_guide","page":"FIM & Prefix Completion","title":"FIM & Prefix Completion","text":"UniLM.jl supports Fill-in-the-Middle (FIM) completion and Chat Prefix Completion — features for code completion and controlled text generation.\n\nFIM is supported by DeepSeekEndpoint (beta), Ollama, and vLLM. Prefix completion is supported by DeepSeekEndpoint (beta).\n\n","category":"section"},{"location":"guide/completions/#FIM-Completion","page":"FIM & Prefix Completion","title":"FIM Completion","text":"FIM generates text between a prompt (prefix) and an optional suffix. This is the standard pattern for code completion — the model fills in the gap.","category":"section"},{"location":"guide/completions/#Basic-Usage","page":"FIM & Prefix Completion","title":"Basic Usage","text":"fim = FIMCompletion(\n    service=DeepSeekEndpoint(\"demo-key\"),\n    model=\"deepseek-chat\",\n    prompt=\"def fib(a):\",\n    suffix=\"    return fib(a-1) + fib(a-2)\",\n    max_tokens=128,\n    stop=[\"\\n\\n\"]\n)\nprintln(\"Model: \", fim.model)\nprintln(\"Prompt: \", fim.prompt)\nprintln(\"Suffix: \", fim.suffix)\nprintln(\"JSON body:\")\nprintln(JSON.json(fim, 2))","category":"section"},{"location":"guide/completions/#Making-Requests","page":"FIM & Prefix Completion","title":"Making Requests","text":"# Struct form\nresult = fim_complete(fim)\nif result isa FIMSuccess\n    println(fim_text(result))\nend\n\n# Convenience form\nresult = fim_complete(\"def hello():\",\n    service=DeepSeekEndpoint(),\n    suffix=\"    print('done')\",\n    max_tokens=64,\n    stop=[\"\\n\\n\"])","category":"section"},{"location":"guide/completions/#Result-Types","page":"FIM & Prefix Completion","title":"Result Types","text":"FIM returns FIMSuccess, FIMFailure, or FIMCallError:\n\n# Accessor works on all result types\nprintln(fim_text(FIMFailure(response=\"err\", status=400)))\nprintln(fim_text(FIMCallError(error=\"network\")))","category":"section"},{"location":"guide/completions/#Provider-Support","page":"FIM & Prefix Completion","title":"Provider Support","text":"Provider Endpoint Notes\nDeepSeek DeepSeekEndpoint() Beta — uses api.deepseek.com/beta internally\nOllama OllamaEndpoint() Via /v1/completions\nvLLM GenericOpenAIEndpoint(url, \"\") Via /v1/completions\n\n# URL routing adapts per provider\nprintln(\"DeepSeek: \", UniLM.get_url(DeepSeekEndpoint(\"k\"), fim))\nprintln(\"Ollama:   \", UniLM.get_url(OllamaEndpoint(), fim))\n\n","category":"section"},{"location":"guide/completions/#Chat-Prefix-Completion","page":"FIM & Prefix Completion","title":"Chat Prefix Completion","text":"Prefix completion lets you provide a partial assistant message that the model continues from. Useful for forcing specific output formats (e.g., starting with a code block).","category":"section"},{"location":"guide/completions/#Usage","page":"FIM & Prefix Completion","title":"Usage","text":"The last message in the chat must be role=assistant with the partial text:\n\nchat = Chat(service=DeepSeekEndpoint(), model=\"deepseek-chat\")\npush!(chat, Message(Val(:system), \"You are a coding assistant.\"))\npush!(chat, Message(Val(:user), \"Write a Python quicksort\"))\npush!(chat, Message(role=RoleAssistant, content=\"```python\\n\"))\n\nresult = prefix_complete(chat)\n# The model continues from \"```python\\n\"\nprintln(result.message.content)","category":"section"},{"location":"guide/completions/#Validation","page":"FIM & Prefix Completion","title":"Validation","text":"prefix_complete validates that:\n\nThe chat is not empty\nThe last message has role=assistant\n\nchat = Chat(service=DeepSeekEndpoint(\"k\"))\npush!(chat, Message(Val(:system), \"sys\"))\npush!(chat, Message(Val(:user), \"hello\"))\n# This would throw — last message is not assistant:\n# prefix_complete(chat)  # ArgumentError\n\n","category":"section"},{"location":"guide/completions/#Capability-Validation","page":"FIM & Prefix Completion","title":"Capability Validation","text":"Both fim_complete and prefix_complete check provider capabilities before making requests. If a provider doesn't support the feature, you get a clear error:\n\n# OpenAI does not support FIM\nprintln(has_capability(OPENAIServiceEndpoint, :fim))       # false\nprintln(has_capability(DeepSeekEndpoint(\"k\"), :fim))        # true\nprintln(has_capability(DeepSeekEndpoint(\"k\"), :prefix_completion))  # true","category":"section"},{"location":"guide/completions/#See-Also","page":"FIM & Prefix Completion","title":"See Also","text":"FIM API Reference — full type and function reference\nProvider Capabilities — capability system\nMulti-Backend Guide — all supported providers","category":"section"},{"location":"api/responses/#Responses-API","page":"Responses Types","title":"Responses API","text":"Types and functions for the Responses API — the newer, more flexible alternative to Chat Completions.","category":"section"},{"location":"api/responses/#Request-Type","page":"Responses Types","title":"Request Type","text":"","category":"section"},{"location":"api/responses/#Construction","page":"Responses Types","title":"Construction","text":"using UniLM\nusing JSON\n\n# Simple text request\nr = Respond(input=\"Tell me a joke\")\nprintln(\"Model: \", r.model)\nprintln(\"Input: \", r.input)\n\n# With instructions and tools\nr2 = Respond(\n    input=\"What's the weather in Paris?\",\n    instructions=\"You are a helpful weather assistant\",\n    tools=[web_search()]\n)\nprintln(\"Has instructions: \", !isnothing(r2.instructions))\nprintln(\"Tools: \", length(r2.tools))","category":"section"},{"location":"api/responses/#Response-Object","page":"Responses Types","title":"Response Object","text":"","category":"section"},{"location":"api/responses/#Result-Types","page":"Responses Types","title":"Result Types","text":"","category":"section"},{"location":"api/responses/#Accessor-Functions","page":"Responses Types","title":"Accessor Functions","text":"","category":"section"},{"location":"api/responses/#Request-Functions","page":"Responses Types","title":"Request Functions","text":"","category":"section"},{"location":"api/responses/#Input-Helpers","page":"Responses Types","title":"Input Helpers","text":"","category":"section"},{"location":"api/responses/#Multimodal-Input","page":"Responses Types","title":"Multimodal Input","text":"# Text-only input\nmsg = InputMessage(role=\"user\", content=\"What is Julia?\")\nprintln(\"Role: \", msg.role)\n\n# Multimodal input\nparts = [\n    input_text(\"Describe this image:\"),\n    input_image(\"https://example.com/photo.jpg\", detail=\"high\")\n]\nprintln(\"Parts: \", length(parts))\nprintln(\"Part types: \", [p[:type] for p in parts])","category":"section"},{"location":"api/responses/#Tool-Types","page":"Responses Types","title":"Tool Types","text":"","category":"section"},{"location":"api/responses/#Tool-Constructors","page":"Responses Types","title":"Tool Constructors","text":"# Function tool\nft = function_tool(\"calculate\", \"Evaluate a math expression\",\n    parameters=Dict(\"type\" => \"object\", \"properties\" => Dict(\n        \"expr\" => Dict(\"type\" => \"string\")\n    ))\n)\nprintln(\"Function tool: \", ft.name)\n\n# Web search\nws = web_search(context_size=\"high\")\nprintln(\"Web search context: \", ws.search_context_size)","category":"section"},{"location":"api/responses/#Text-Format","page":"Responses Types","title":"Text Format","text":"tf = text_format()\nprintln(\"Default format: \", tf.format.type)\n\njf = json_object_format()\nprintln(\"JSON format: \", jf.format.type)","category":"section"},{"location":"api/responses/#Reasoning","page":"Responses Types","title":"Reasoning","text":"reasoning = UniLM.Reasoning(effort=\"high\")\nprintln(\"Effort: \", reasoning.effort)","category":"section"},{"location":"api/responses/#UniLM.Respond","page":"Responses Types","title":"UniLM.Respond","text":"Respond(; model=\"gpt-5.2\", input, kwargs...)\n\nConfiguration struct for an OpenAI Responses API request.\n\nKey Fields\n\nmodel::String: Model to use (default: \"gpt-5.2\")\ninput::Any: A String or Vector{InputMessage} — the prompt input\ninstructions::String: System-level instructions\ntools::Vector: Available tools (FunctionTool, WebSearchTool, FileSearchTool)\nprevious_response_id::String: Chain to a previous response for multi-turn\nreasoning::Reasoning: Reasoning config for O-series models\ntext::TextConfig: Output format (text, json, json_schema)\ntemperature::Float64: Sampling temperature (0.0–2.0), mutually exclusive with top_p\ntop_p::Float64: Nucleus sampling (0.0–1.0), mutually exclusive with temperature\nmax_output_tokens::Int64: Max tokens in the response\nstream::Bool: Enable streaming\ntruncation::String: \"auto\" or \"disabled\"\nstore::Bool: Whether to store the response for later retrieval\nmetadata::AbstractDict: Arbitrary metadata to attach\nuser::String: End-user identifier\n\nExamples\n\n# Simple text\nRespond(input=\"Tell me a joke\")\n\n# With instructions\nRespond(input=\"Translate to French: Hello\", instructions=\"You are a translator\")\n\n# Multi-turn via chaining\nRespond(input=\"Tell me more\", previous_response_id=\"resp_abc123\")\n\n# With tools\nRespond(\n    input=\"What's the weather in NYC?\",\n    tools=ResponseTool[function_tool(\"get_weather\", \"Get weather\", parameters=Dict(\"type\"=>\"object\", \"properties\"=>Dict(\"location\"=>Dict(\"type\"=>\"string\"))))]\n)\n\n# Reasoning (O-series models)\nRespond(input=\"Solve this math problem...\", model=\"o3\", reasoning=Reasoning(effort=\"high\"))\n\n\n\n\n\n","category":"type"},{"location":"api/responses/#UniLM.ResponseObject","page":"Responses Types","title":"UniLM.ResponseObject","text":"ResponseObject\n\nParsed response from the Responses API.\n\nAccessors\n\noutput_text(r) — extract concatenated text output\nfunction_calls(r) — extract function call outputs\nr.id, r.status, r.model — basic metadata\nr.output — full output array (raw dicts)\nr.usage — token usage info\nr.raw — the complete raw JSON dict\n\n\n\n\n\n","category":"type"},{"location":"api/responses/#UniLM.ResponseSuccess","page":"Responses Types","title":"UniLM.ResponseSuccess","text":"ResponseSuccess <: LLMRequestResponse\n\nSuccessful response from the Responses API. Access the parsed response via .response.\n\n\n\n\n\n","category":"type"},{"location":"api/responses/#UniLM.ResponseFailure","page":"Responses Types","title":"UniLM.ResponseFailure","text":"ResponseFailure <: LLMRequestResponse\n\nHTTP-level failure from the Responses API. Contains the response body and status code.\n\n\n\n\n\n","category":"type"},{"location":"api/responses/#UniLM.ResponseCallError","page":"Responses Types","title":"UniLM.ResponseCallError","text":"ResponseCallError <: LLMRequestResponse\n\nException-level error during a Responses API call (network, parsing, etc.).\n\n\n\n\n\n","category":"type"},{"location":"api/responses/#UniLM.output_text","page":"Responses Types","title":"UniLM.output_text","text":"output_text(r::ResponseObject)::String\noutput_text(r::ResponseSuccess)::String\n\nExtract the concatenated text output from a response.\n\nExamples\n\nresult = respond(\"Hello!\")\noutput_text(result)  # => \"Hi there! How can I help?\"\n\n\n\n\n\n","category":"function"},{"location":"api/responses/#UniLM.function_calls","page":"Responses Types","title":"UniLM.function_calls","text":"function_calls(r::ResponseObject)::Vector{Dict{String,Any}}\nfunction_calls(r::ResponseSuccess)::Vector{Dict{String,Any}}\n\nExtract function call outputs from a response.\n\nEach dict contains: \"id\", \"call_id\", \"name\", \"arguments\" (JSON string), \"status\".\n\nExamples\n\nresult = respond(\"What's the weather?\", tools=[function_tool(\"get_weather\", ...)])\nfor call in function_calls(result)\n    name = call[\"name\"]\n    args = JSON.parse(call[\"arguments\"])\n    # dispatch to your function...\nend\n\n\n\n\n\n","category":"function"},{"location":"api/responses/#UniLM.respond","page":"Responses Types","title":"UniLM.respond","text":"respond(r::Respond; retries=0, callback=nothing)\n\nSend a request to the OpenAI Responses API.\n\nReturns ResponseSuccess, ResponseFailure, or ResponseCallError.\n\nFor streaming, set stream=true and pass a callback:\n\ncallback(chunk::Union{String, ResponseObject}, close::Ref{Bool})\n\nExamples\n\nr = Respond(input=\"Tell me a joke\")\nresult = respond(r)\nif result isa ResponseSuccess\n    println(output_text(result))\nend\n\n\n\n\n\nrespond(input; kwargs...)\n\nConvenience method: create a Respond from input + keyword arguments and send it.\n\nExamples\n\n# Simple text\nresult = respond(\"Tell me a joke\")\n\n# With instructions and model\nresult = respond(\"Translate: Hello\", instructions=\"You are a translator\", model=\"gpt-5.2\")\n\n# With tools\nresult = respond(\"Search for Julia news\", tools=[web_search()])\n\n# Multi-turn\nr1 = respond(\"Tell me a joke\")\nr2 = respond(\"Tell me another\", previous_response_id=r1.response.id)\n\n# Streaming\nrespond(\"Tell me a story\", stream=true) do chunk, close\n    if chunk isa String\n        print(chunk)  # partial text delta\n    end\nend\n\n\n\n\n\nrespond(callback::Function, input; kwargs...)\n\ndo-block form for streaming. Automatically sets stream=true.\n\nExamples\n\nrespond(\"Tell me a story\") do chunk, close\n    if chunk isa String\n        print(chunk)\n    elseif chunk isa ResponseObject\n        println(\"\\nDone! Status: \", chunk.status)\n    end\nend\n\n\n\n\n\n","category":"function"},{"location":"api/responses/#UniLM.get_response","page":"Responses Types","title":"UniLM.get_response","text":"get_response(response_id::String; service=OPENAIServiceEndpoint)\n\nRetrieve an existing response by its ID.\n\nExamples\n\nresult = get_response(\"resp_abc123\")\nif result isa ResponseSuccess\n    println(output_text(result))\nend\n\n\n\n\n\n","category":"function"},{"location":"api/responses/#UniLM.delete_response","page":"Responses Types","title":"UniLM.delete_response","text":"delete_response(response_id::String; service=OPENAIServiceEndpoint)\n\nDelete a stored response by its ID. Returns a Dict with \"id\", \"object\", \"deleted\" keys.\n\nExamples\n\nresult = delete_response(\"resp_abc123\")\nresult[\"deleted\"]  # => true\n\n\n\n\n\n","category":"function"},{"location":"api/responses/#UniLM.list_input_items","page":"Responses Types","title":"UniLM.list_input_items","text":"list_input_items(response_id::String; limit=20, order=\"desc\", after=nothing, service=OPENAIServiceEndpoint)\n\nList input items for a stored response. Returns a Dict with \"data\", \"first_id\", \"last_id\", \"has_more\".\n\nExamples\n\nitems = list_input_items(\"resp_abc123\")\nfor item in items[\"data\"]\n    println(item[\"type\"], \": \", item)\nend\n\n\n\n\n\n","category":"function"},{"location":"api/responses/#UniLM.cancel_response","page":"Responses Types","title":"UniLM.cancel_response","text":"cancel_response(response_id::String; service=OPENAIServiceEndpoint)\n\nCancel an in-progress response by its ID. Returns ResponseSuccess on success.\n\nExamples\n\n# Start a background response, then cancel it\nresult = respond(\"Write a very long essay\", background=true)\ncancel_result = cancel_response(result.response.id)\nif cancel_result isa ResponseSuccess\n    println(\"Cancelled: \", cancel_result.response.status)\nend\n\n\n\n\n\n","category":"function"},{"location":"api/responses/#UniLM.compact_response","page":"Responses Types","title":"UniLM.compact_response","text":"compact_response(; model, input, kwargs...)\n\nCompact a conversation by running a compaction pass. Returns opaque, encrypted items that can be passed as input to subsequent requests, reducing token usage in long conversations.\n\nFields\n\nmodel::String: Model to use for compaction\ninput::Any: The conversation items to compact (typically the full conversation history)\n\nReturns a Dict with \"id\", \"object\", \"output\", and \"usage\" keys.\n\nExamples\n\ncompacted = compact_response(model=\"gpt-5.2\", input=[\n    InputMessage(role=\"user\", content=\"Hello\"),\n    Dict(\"type\" => \"message\", \"role\" => \"assistant\", \"status\" => \"completed\",\n         \"content\" => [Dict(\"type\" => \"output_text\", \"text\" => \"Hi there!\")])\n])\n# Use compacted[\"output\"] as input to the next request\n\n\n\n\n\n","category":"function"},{"location":"api/responses/#UniLM.count_input_tokens","page":"Responses Types","title":"UniLM.count_input_tokens","text":"count_input_tokens(; model, input, kwargs...)\n\nCount the number of input tokens a request would use without actually generating a response. Useful for estimating costs or checking whether input fits within the context window.\n\nReturns a Dict with \"object\" (\"response.input_tokens\") and \"input_tokens\" keys.\n\nExamples\n\nresult = count_input_tokens(model=\"gpt-5.2\", input=\"Tell me a joke\")\nprintln(\"Input tokens: \", result[\"input_tokens\"])\n\n\n\n\n\n","category":"function"},{"location":"api/responses/#UniLM.InputMessage","page":"Responses Types","title":"UniLM.InputMessage","text":"InputMessage(; role, content)\n\nA structured input message for the Responses API.\n\nFields\n\nrole::String: \"user\", \"assistant\", \"system\", or \"developer\"\ncontent::Any: String or a vector of content parts (see input_text, input_image, input_file)\n\nExamples\n\nInputMessage(role=\"user\", content=\"What is 2+2?\")\nInputMessage(role=\"user\", content=[input_text(\"Describe this:\"), input_image(\"https://example.com/img.png\")])\n\n\n\n\n\n","category":"type"},{"location":"api/responses/#UniLM.input_text","page":"Responses Types","title":"UniLM.input_text","text":"input_text(text::String)\n\nCreate an input_text content part for multimodal input messages.\n\n\n\n\n\n","category":"function"},{"location":"api/responses/#UniLM.input_image","page":"Responses Types","title":"UniLM.input_image","text":"input_image(url::String; detail=nothing)\n\nCreate an input_image content part. detail can be \"auto\", \"low\", or \"high\".\n\n\n\n\n\n","category":"function"},{"location":"api/responses/#UniLM.input_file","page":"Responses Types","title":"UniLM.input_file","text":"input_file(; url=nothing, id=nothing)\n\nCreate an input_file content part. Provide either a url or a file_id.\n\n\n\n\n\n","category":"function"},{"location":"api/responses/#UniLM.ResponseTool","page":"Responses Types","title":"UniLM.ResponseTool","text":"ResponseTool\n\nAbstract supertype for Responses API tools. Subtypes:\n\nFunctionTool\nWebSearchTool\nFileSearchTool\n\n\n\n\n\n","category":"type"},{"location":"api/responses/#UniLM.FunctionTool","page":"Responses Types","title":"UniLM.FunctionTool","text":"FunctionTool(; name, description=nothing, parameters=nothing, strict=nothing)\n\nA function tool for the Responses API.\n\nExamples\n\nFunctionTool(\n    name=\"get_weather\",\n    description=\"Get current weather for a location\",\n    parameters=Dict(\n        \"type\" => \"object\",\n        \"properties\" => Dict(\n            \"location\" => Dict(\"type\" => \"string\", \"description\" => \"City name\")\n        ),\n        \"required\" => [\"location\"]\n    )\n)\n\n\n\n\n\n","category":"type"},{"location":"api/responses/#UniLM.WebSearchTool","page":"Responses Types","title":"UniLM.WebSearchTool","text":"WebSearchTool(; search_context_size=\"medium\", user_location=nothing)\n\nA web search tool for the Responses API. Allows the model to search the web.\n\nsearch_context_size: \"low\", \"medium\", or \"high\"\nuser_location: Dict with keys like \"country\", \"city\", \"region\", \"timezone\"\n\n\n\n\n\n","category":"type"},{"location":"api/responses/#UniLM.FileSearchTool","page":"Responses Types","title":"UniLM.FileSearchTool","text":"FileSearchTool(; vector_store_ids, max_num_results=nothing, ranking_options=nothing, filters=nothing)\n\nA file search tool for the Responses API. Searches over uploaded vector stores.\n\n\n\n\n\n","category":"type"},{"location":"api/responses/#UniLM.MCPTool","page":"Responses Types","title":"UniLM.MCPTool","text":"MCPTool(; server_label, server_url, require_approval=\"never\", allowed_tools=nothing, headers=nothing)\n\nA Model Context Protocol (MCP) tool for the Responses API. Connects the model to an external MCP server for tool execution.\n\n\n\n\n\n","category":"type"},{"location":"api/responses/#UniLM.ComputerUseTool","page":"Responses Types","title":"UniLM.ComputerUseTool","text":"ComputerUseTool(; display_width=1024, display_height=768, environment=nothing)\n\nA computer use tool for the Responses API. Allows the model to interact with a virtual display via screenshots, mouse, and keyboard.\n\n\n\n\n\n","category":"type"},{"location":"api/responses/#UniLM.ImageGenerationTool","page":"Responses Types","title":"UniLM.ImageGenerationTool","text":"ImageGenerationTool(; background=nothing, output_format=nothing, output_compression=nothing, quality=nothing, size=nothing)\n\nAn image generation tool for the Responses API. Allows the model to generate images inline during a response.\n\n\n\n\n\n","category":"type"},{"location":"api/responses/#UniLM.CodeInterpreterTool","page":"Responses Types","title":"UniLM.CodeInterpreterTool","text":"CodeInterpreterTool(; container=nothing, file_ids=nothing)\n\nA code interpreter tool for the Responses API. Allows the model to execute code in a sandboxed environment.\n\n\n\n\n\n","category":"type"},{"location":"api/responses/#UniLM.function_tool","page":"Responses Types","title":"UniLM.function_tool","text":"function_tool(name, description=nothing; parameters=nothing, strict=nothing)\n\nShorthand constructor for FunctionTool.\n\n\n\n\n\nfunction_tool(d::AbstractDict)\n\nConstruct a FunctionTool from a dict. Accepts both the bare format {\"name\": ...} and the wrapped format {\"type\": \"function\", \"function\": {\"name\": ...}}.\n\n\n\n\n\n","category":"function"},{"location":"api/responses/#UniLM.web_search","page":"Responses Types","title":"UniLM.web_search","text":"web_search(; context_size=\"medium\", location=nothing)\n\nShorthand constructor for WebSearchTool.\n\n\n\n\n\n","category":"function"},{"location":"api/responses/#UniLM.file_search","page":"Responses Types","title":"UniLM.file_search","text":"file_search(store_ids::Vector{String}; max_results=nothing, ranking=nothing, filters=nothing)\n\nShorthand constructor for FileSearchTool.\n\n\n\n\n\n","category":"function"},{"location":"api/responses/#UniLM.mcp_tool","page":"Responses Types","title":"UniLM.mcp_tool","text":"mcp_tool(label, url; require_approval=\"never\", allowed_tools=nothing, headers=nothing)\n\nShorthand constructor for MCPTool.\n\n\n\n\n\n","category":"function"},{"location":"api/responses/#UniLM.computer_use","page":"Responses Types","title":"UniLM.computer_use","text":"computer_use(; display_width=1024, display_height=768, environment=nothing)\n\nShorthand constructor for ComputerUseTool.\n\n\n\n\n\n","category":"function"},{"location":"api/responses/#UniLM.image_generation_tool","page":"Responses Types","title":"UniLM.image_generation_tool","text":"image_generation_tool(; kwargs...)\n\nShorthand constructor for ImageGenerationTool.\n\n\n\n\n\n","category":"function"},{"location":"api/responses/#UniLM.code_interpreter","page":"Responses Types","title":"UniLM.code_interpreter","text":"code_interpreter(; container=nothing, file_ids=nothing)\n\nShorthand constructor for CodeInterpreterTool.\n\n\n\n\n\n","category":"function"},{"location":"api/responses/#UniLM.TextConfig","page":"Responses Types","title":"UniLM.TextConfig","text":"TextConfig(; format=TextFormatSpec())\n\nWrapper for the text field in the Responses API request body.\n\n\n\n\n\n","category":"type"},{"location":"api/responses/#UniLM.TextFormatSpec","page":"Responses Types","title":"UniLM.TextFormatSpec","text":"TextFormatSpec(; type=\"text\", name=nothing, description=nothing, schema=nothing, strict=nothing)\n\nOutput text format specification.\n\ntype: \"text\" (default), \"json_object\", or \"json_schema\"\nFor \"json_schema\": provide name, description, schema, and optionally strict\n\n\n\n\n\n","category":"type"},{"location":"api/responses/#UniLM.text_format","page":"Responses Types","title":"UniLM.text_format","text":"text_format(; kwargs...)\n\nCreate a TextConfig with the given format options.\n\n\n\n\n\n","category":"function"},{"location":"api/responses/#UniLM.json_schema_format","page":"Responses Types","title":"UniLM.json_schema_format","text":"json_schema_format(name, description, schema; strict=nothing)\n\nCreate a JSON Schema output format for structured output.\n\n\n\n\n\njson_schema_format(d::AbstractDict)\n\nConstruct a JSON Schema TextConfig from a dict with keys \"name\", \"description\", and \"schema\".\n\n\n\n\n\n","category":"function"},{"location":"api/responses/#UniLM.json_object_format","page":"Responses Types","title":"UniLM.json_object_format","text":"json_object_format()\n\nCreate a JSON object output format (unstructured).\n\n\n\n\n\n","category":"function"},{"location":"api/responses/#UniLM.Reasoning","page":"Responses Types","title":"UniLM.Reasoning","text":"Reasoning(; effort=nothing, summary=nothing)\n\nReasoning configuration for O-series models (o3, o4-mini, etc.).\n\neffort: \"none\", \"low\", \"medium\", or \"high\"\ngenerate_summary: \"auto\", \"concise\", or \"detailed\" — configures summary generation\nsummary: \"auto\", \"concise\", or \"detailed\" (deprecated alias for generate_summary)\n\n\n\n\n\n","category":"type"},{"location":"guide/mcp/#mcp_guide","page":"MCP (Model Context Protocol)","title":"Model Context Protocol (MCP)","text":"UniLM.jl provides native MCP support — both as a client (connect to MCP servers) and a server (build your own). MCP tools integrate seamlessly with tool_loop! and tool_loop via the CallableTool bridge.\n\nProtocol: JSON-RPC 2.0 over stdio or Streamable HTTP (MCP spec 2025-11-25). Zero external dependencies.\n\n","category":"section"},{"location":"guide/mcp/#MCP-Client","page":"MCP (Model Context Protocol)","title":"MCP Client","text":"","category":"section"},{"location":"guide/mcp/#Transports","page":"MCP (Model Context Protocol)","title":"Transports","text":"Two transport types are available:\n\nStdioTransport — launches a subprocess, communicates via stdin/stdout (newline-delimited JSON-RPC)\nHTTPTransport — communicates via POST requests with Mcp-Session-Id session management\n\n# Transport types are constructed but not connected until mcp_connect\nt1 = StdioTransport(`echo hello`)\nprintln(\"Stdio transport for: \", t1.command)\n\nt2 = HTTPTransport(\"https://mcp.example.com/mcp\";\n    headers=[\"Authorization\" => \"Bearer token\"])\nprintln(\"HTTP transport for: \", t2.url)","category":"section"},{"location":"guide/mcp/#Connecting-to-an-MCP-Server","page":"MCP (Model Context Protocol)","title":"Connecting to an MCP Server","text":"Use mcp_connect with a Cmd (stdio), URL string (HTTP), or transport object:\n\n# Stdio — launches subprocess\nsession = mcp_connect(`npx -y @modelcontextprotocol/server-filesystem /tmp`)\n\n# HTTP\nsession = mcp_connect(\"https://mcp.example.com/mcp\";\n    headers=[\"Authorization\" => \"Bearer token\"])\n\n# Custom transport\nsession = mcp_connect(StdioTransport(`my-server`))\n\nThe do-block form automatically disconnects when done:\n\nmcp_connect(`npx server`) do session\n    tools = mcp_tools(session)\n    # ... use tools ...\nend  # session is disconnected here","category":"section"},{"location":"guide/mcp/#Discovering-Tools,-Resources,-and-Prompts","page":"MCP (Model Context Protocol)","title":"Discovering Tools, Resources, and Prompts","text":"After connecting, the session auto-populates tool/resource/prompt caches. You can also refresh them manually:\n\ntools    = list_tools!(session)     # -> Vector{MCPToolInfo}\nresources = list_resources!(session) # -> Vector{MCPResourceInfo}\nprompts  = list_prompts!(session)   # -> Vector{MCPPromptInfo}\n\n# MCPToolInfo fields\ninfo = MCPToolInfo(Dict{String,Any}(\n    \"name\" => \"read_file\",\n    \"description\" => \"Read a file from disk\",\n    \"inputSchema\" => Dict{String,Any}(\n        \"type\" => \"object\",\n        \"properties\" => Dict{String,Any}(\n            \"path\" => Dict{String,Any}(\"type\" => \"string\", \"description\" => \"File path\")\n        ),\n        \"required\" => [\"path\"]\n    )\n))\nprintln(\"Tool: \", info.name)\nprintln(\"Description: \", info.description)\nprintln(\"Schema: \", JSON.json(info.input_schema, 2))","category":"section"},{"location":"guide/mcp/#Calling-Tools-Directly","page":"MCP (Model Context Protocol)","title":"Calling Tools Directly","text":"result = call_tool(session, \"read_file\", Dict{String,Any}(\"path\" => \"/tmp/data.txt\"))\ncontent = read_resource(session, \"config://app\")\nmessages = get_prompt(session, \"review\", Dict{String,Any}(\"code\" => \"x + 1\"))\nping(session)","category":"section"},{"location":"guide/mcp/#Bridging-to-tool_loop!-(Chat-Completions)","page":"MCP (Model Context Protocol)","title":"Bridging to tool_loop! (Chat Completions)","text":"mcp_tools converts MCP tools into Vector{CallableTool{GPTTool}} for use with tool_loop!:\n\nsession = mcp_connect(`npx server`)\ntools = mcp_tools(session)\n\nchat = Chat(model=\"gpt-5.2\", tools=map(t -> t.tool, tools))\npush!(chat, Message(Val(:user), \"List files in /tmp\"))\nresult = tool_loop!(chat; tools)\n\nmcp_disconnect!(session)","category":"section"},{"location":"guide/mcp/#Bridging-to-tool_loop-(Responses-API)","page":"MCP (Model Context Protocol)","title":"Bridging to tool_loop (Responses API)","text":"mcp_tools_respond converts MCP tools into Vector{CallableTool{FunctionTool}} for use with tool_loop:\n\nsession = mcp_connect(\"https://mcp.example.com/mcp\")\ntools = mcp_tools_respond(session)\nresult = tool_loop(\"List files in /tmp\"; tools=tools)\nmcp_disconnect!(session)\n\n","category":"section"},{"location":"guide/mcp/#MCP-Server","page":"MCP (Model Context Protocol)","title":"MCP Server","text":"","category":"section"},{"location":"guide/mcp/#Creating-a-Server","page":"MCP (Model Context Protocol)","title":"Creating a Server","text":"server = MCPServer(\"calc\", \"1.0.0\"; description=\"A calculator server\")\nprintln(\"Server: \", server.name, \" v\", server.version)","category":"section"},{"location":"guide/mcp/#Registering-Tools","page":"MCP (Model Context Protocol)","title":"Registering Tools","text":"Register tools with explicit JSON Schema or auto-inferred schema:\n\n# Explicit schema\nregister_tool!(server, \"add\", \"Add two numbers\",\n    Dict{String,Any}(\n        \"type\" => \"object\",\n        \"properties\" => Dict{String,Any}(\n            \"a\" => Dict{String,Any}(\"type\" => \"number\"),\n            \"b\" => Dict{String,Any}(\"type\" => \"number\")\n        ),\n        \"required\" => [\"a\", \"b\"]\n    ),\n    args -> string(args[\"a\"] + args[\"b\"]))\n\nprintln(\"Registered tools: \", collect(keys(server.tools)))\n\n# Auto-inferred schema from function signature\nregister_tool!(server, \"greet\", \"Greet someone\",\n    (args::Dict{String,Any}) -> \"Hello, $(args[\"name\"])!\")\n\nprintln(\"Tools now: \", collect(keys(server.tools)))\n\nYou can also register existing CallableTool instances:\n\n# From Chat Completions tool\nregister_tool!(server, my_callable_gpt_tool)\n\n# From Responses API tool\nregister_tool!(server, my_callable_function_tool)","category":"section"},{"location":"guide/mcp/#Registering-Resources","page":"MCP (Model Context Protocol)","title":"Registering Resources","text":"# Static resource\nregister_resource!(server, \"config://app\", \"App Config\",\n    () -> \"{\\\"debug\\\": true}\";\n    mime_type=\"application/json\",\n    description=\"Application configuration\")\n\nprintln(\"Resources: \", collect(keys(server.resources)))\n\n# URI-templated resource\nregister_resource_template!(server, \"file://{path}\", \"File Reader\",\n    (params::Dict{String,String}) -> \"Contents of $(params[\"path\"])\";\n    description=\"Read files by path\")\n\nprintln(\"Templates: \", length(server.resource_templates))","category":"section"},{"location":"guide/mcp/#Registering-Prompts","page":"MCP (Model Context Protocol)","title":"Registering Prompts","text":"register_prompt!(server, \"review\", (args::Dict{String,Any}) ->\n    [Dict{String,Any}(\"role\" => \"user\",\n        \"content\" => Dict{String,Any}(\"type\" => \"text\",\n            \"text\" => \"Review this code:\\n$(args[\"code\"])\"))];\n    description=\"Code review prompt\",\n    arguments=[Dict{String,Any}(\"name\" => \"code\", \"required\" => true)])\n\nprintln(\"Prompts: \", collect(keys(server.prompts)))","category":"section"},{"location":"guide/mcp/#Macros","page":"MCP (Model Context Protocol)","title":"Macros","text":"The @mcp_tool, @mcp_resource, and @mcp_prompt macros provide a more ergonomic registration API with automatic JSON Schema generation from Julia type annotations:\n\nserver = MCPServer(\"calc\", \"1.0.0\")\n\n@mcp_tool server function add(a::Float64, b::Float64)::String\n    string(a + b)\nend\n\n@mcp_resource server \"config://app\" function()\n    read(\"config.toml\", String)\nend\n\n@mcp_resource server \"file://{path}\" function(path::String)\n    read(path, String)\nend\n\n@mcp_prompt server \"review\" function(code::String)\n    [Dict(\"role\" => \"user\",\n        \"content\" => Dict(\"type\" => \"text\", \"text\" => \"Review: $code\"))]\nend","category":"section"},{"location":"guide/mcp/#Serving","page":"MCP (Model Context Protocol)","title":"Serving","text":"Start the server with serve:\n\nserve(server)                             # stdio (default) — for Claude Desktop/CLI\nserve(server; transport=:http, port=3000)  # HTTP on port 3000\n\n","category":"section"},{"location":"guide/mcp/#MCP-Tool-in-Responses-API","page":"MCP (Model Context Protocol)","title":"MCP Tool in Responses API","text":"Separately from the client/server above, OpenAI's Responses API has a built-in MCPTool type for server-side MCP integration. This tells the model to connect to an external MCP server during response generation:\n\ntool = mcp_tool(\"my-server\", \"https://mcp.example.com/sse\";\n    require_approval=\"never\",\n    allowed_tools=[\"read_file\", \"list_dir\"])\nprintln(\"Type: \", typeof(tool))\nprintln(\"Label: \", tool.server_label)\nprintln(\"URL: \", tool.server_url)\nprintln(\"JSON: \", JSON.json(JSON.lower(tool)))\n\nThis is distinct from the UniLM.jl MCP client — MCPTool delegates tool execution to OpenAI's servers, while mcp_connect runs tools locally.\n\n","category":"section"},{"location":"guide/mcp/#See-Also","page":"MCP (Model Context Protocol)","title":"See Also","text":"Tool Calling Guide — function tools and automated tool loop\nMCP API Reference — full type and function reference\nCallableTool, tool_loop!, tool_loop — tool loop integration","category":"section"},{"location":"api/results/#Result-Types","page":"Result Types","title":"Result Types","text":"Abstract and concrete types for handling API call outcomes. All result types are subtypes of LLMRequestResponse.","category":"section"},{"location":"api/results/#Abstract-Type","page":"Result Types","title":"Abstract Type","text":"","category":"section"},{"location":"api/results/#Chat-Completions-Results","page":"Result Types","title":"Chat Completions Results","text":"","category":"section"},{"location":"api/results/#Pattern-Matching","page":"Result Types","title":"Pattern Matching","text":"result = chatrequest!(chat)\n\nif result isa LLMSuccess\n    println(result.message.content)\n    println(result.message.finish_reason)  # \"stop\"\nelseif result isa LLMFailure\n    @warn \"HTTP $(result.status): $(result.response)\"\nelseif result isa LLMCallError\n    @error \"Call error: $(result.error)\"\nend","category":"section"},{"location":"api/results/#Responses-API-Results","page":"Result Types","title":"Responses API Results","text":"See also the Responses API reference.\n\nResponseSuccess\nResponseFailure\nResponseCallError","category":"section"},{"location":"api/results/#Pattern-Matching-2","page":"Result Types","title":"Pattern Matching","text":"result = respond(\"Tell me a joke\")\n\nif result isa ResponseSuccess\n    println(output_text(result))\n    println(result.response.status)  # \"completed\"\nelseif result isa ResponseFailure\n    @warn \"HTTP $(result.status)\"\nelseif result isa ResponseCallError\n    @error result.error\nend","category":"section"},{"location":"api/results/#Image-Generation-Results","page":"Result Types","title":"Image Generation Results","text":"See also the Images API reference.\n\nImageSuccess\nImageFailure\nImageCallError","category":"section"},{"location":"api/results/#Pattern-Matching-3","page":"Result Types","title":"Pattern Matching","text":"result = generate_image(\"A robot writing Julia code\")\n\nif result isa ImageSuccess\n    save_image(image_data(result)[1], \"robot.png\")\nelseif result isa ImageFailure\n    @warn \"HTTP $(result.status): $(result.response)\"\nelseif result isa ImageCallError\n    @error result.error\nend","category":"section"},{"location":"api/results/#Type-Hierarchy","page":"Result Types","title":"Type Hierarchy","text":"All result types share the abstract parent LLMRequestResponse:\n\nLLMRequestResponse\n├── LLMSuccess          (Chat Completions)\n├── LLMFailure          (Chat Completions)\n├── LLMCallError        (Chat Completions)\n├── ResponseSuccess     (Responses API)\n├── ResponseFailure     (Responses API)\n├── ResponseCallError   (Responses API)\n├── ImageSuccess        (Image Generation)\n├── ImageFailure        (Image Generation)\n├── ImageCallError      (Image Generation)\n├── FIMSuccess          (FIM Completion)\n├── FIMFailure          (FIM Completion)\n└── FIMCallError        (FIM Completion)","category":"section"},{"location":"api/results/#UniLM.LLMRequestResponse","page":"Result Types","title":"UniLM.LLMRequestResponse","text":"LLMRequestResponse\n\nAbstract supertype for all API call results. Pattern-match on subtypes to handle outcomes:\n\nLLMSuccess — successful response\nLLMFailure — HTTP-level failure (non-200 status)\nLLMCallError — exception during the call (network error, etc.)\nResponseSuccess — successful Responses API result\nResponseFailure — Responses API HTTP failure\nResponseCallError — Responses API exception\n\n\n\n\n\n","category":"type"},{"location":"api/results/#UniLM.LLMSuccess","page":"Result Types","title":"UniLM.LLMSuccess","text":"LLMSuccess(; message, self, usage=nothing)\n\nSuccessful Chat Completions API response.\n\nFields\n\nmessage::Message: The assistant's reply message.\nself::Chat: The updated Chat object (with the new message appended if history=true).\nusage::Union{TokenUsage, Nothing}: Token usage statistics from the API.\n\n\n\n\n\n","category":"type"},{"location":"api/results/#UniLM.LLMFailure","page":"Result Types","title":"UniLM.LLMFailure","text":"LLMFailure(; response, status, self)\n\nHTTP-level failure from the Chat Completions API. The server returned a non-200 status.\n\nFields\n\nresponse::String: The raw response body.\nstatus::Int: The HTTP status code.\nself::Chat: The Chat object (unchanged).\n\n\n\n\n\n","category":"type"},{"location":"api/results/#UniLM.LLMCallError","page":"Result Types","title":"UniLM.LLMCallError","text":"LLMCallError(; error, status=nothing, self)\n\nException-level error during a Chat Completions API call (network failure, JSON parse error, etc.).\n\nFields\n\nerror::String: The stringified exception.\nstatus::Union{Int,Nothing}: HTTP status if available.\nself::Chat: The Chat object (unchanged).\n\n\n\n\n\n","category":"type"},{"location":"getting_started/#Getting-Started","page":"Getting Started","title":"Getting Started","text":"","category":"section"},{"location":"getting_started/#Prerequisites","page":"Getting Started","title":"Prerequisites","text":"Julia 1.12+ (as specified in Project.toml)\nAn OpenAI API key (or Azure/Gemini credentials for those backends)","category":"section"},{"location":"getting_started/#Installation","page":"Getting Started","title":"Installation","text":"using Pkg\nPkg.add(url=\"https://github.com/algunion/UniLM.jl\")","category":"section"},{"location":"getting_started/#Configuration","page":"Getting Started","title":"Configuration","text":"UniLM.jl reads API credentials from environment variables. Set them before making any requests:","category":"section"},{"location":"getting_started/#OpenAI-(default)","page":"Getting Started","title":"OpenAI (default)","text":"ENV[\"OPENAI_API_KEY\"] = \"sk-...\"\n\nOr via your shell:\n\nexport OPENAI_API_KEY=\"sk-...\"","category":"section"},{"location":"getting_started/#Azure-OpenAI","page":"Getting Started","title":"Azure OpenAI","text":"export AZURE_OPENAI_BASE_URL=\"https://your-resource.openai.azure.com\"\nexport AZURE_OPENAI_API_KEY=\"your-key\"\nexport AZURE_OPENAI_API_VERSION=\"2024-02-01\"\nexport AZURE_OPENAI_DEPLOY_NAME_GPT_5_2=\"your-gpt52-deployment\"","category":"section"},{"location":"getting_started/#Google-Gemini","page":"Getting Started","title":"Google Gemini","text":"export GEMINI_API_KEY=\"your-gemini-key\"","category":"section"},{"location":"getting_started/#Your-First-Request","page":"Getting Started","title":"Your First Request","text":"","category":"section"},{"location":"getting_started/#Using-the-Responses-API","page":"Getting Started","title":"Using the Responses API","text":"The simplest way to get started — one function call:\n\nresult = respond(\"Explain Julia's type system in 3 bullet points\")\nif result isa ResponseSuccess\n    println(output_text(result))\nelse\n    println(\"Request failed — \", output_text(result))\nend","category":"section"},{"location":"getting_started/#Using-Chat-Completions","page":"Getting Started","title":"Using Chat Completions","text":"For stateful, multi-turn conversations:\n\nchat = Chat(model=\"gpt-4o-mini\")\npush!(chat, Message(Val(:system), \"You are a concise Julia programming tutor.\"))\npush!(chat, Message(Val(:user), \"What is multiple dispatch? Answer in 2-3 sentences.\"))\nresult = chatrequest!(chat)\nif result isa LLMSuccess\n    println(result.message.content)\n    println(\"\\nFinish reason: \", result.message.finish_reason)\n    println(\"Conversation length: \", length(chat))\nelse\n    println(\"Request failed — see result for details\")\nend","category":"section"},{"location":"getting_started/#Generating-Images","page":"Getting Started","title":"Generating Images","text":"result = generate_image(\n    \"A watercolor painting of a friendly robot reading a Julia programming book\",\n    size=\"1024x1024\", quality=\"medium\"\n)\nif result isa ImageSuccess\n    println(\"Success: true\")\n    println(\"Images: \", length(image_data(result)))\nelse\n    println(\"Success: false\")\n    println(\"Images: 0\")\nend","category":"section"},{"location":"getting_started/#Using-Keyword-Arguments","page":"Getting Started","title":"Using Keyword Arguments","text":"For one-shot requests without managing Chat objects:\n\nresult = chatrequest!(\n    systemprompt=\"You are a calculator. Respond only with the number.\",\n    userprompt=\"What is 42 * 17?\",\n    model=\"gpt-4o-mini\",\n    temperature=0.0\n)\nif result isa LLMSuccess\n    println(result.message.content)\nelse\n    println(\"Request failed — see result for details\")\nend","category":"section"},{"location":"getting_started/#Handling-Results","page":"Getting Started","title":"Handling Results","text":"All API calls return subtypes of LLMRequestResponse. Use Julia's pattern matching:\n\nusing UniLM\nusing InteractiveUtils\n\n# Construct a chat to show the result type hierarchy\nchat = Chat()\npush!(chat, Message(Val(:system), \"You are helpful.\"))\npush!(chat, Message(Val(:user), \"Hello!\"))\n\n# Show the type hierarchy:\nprintln(\"LLMRequestResponse subtypes:\")\nfor T in subtypes(UniLM.LLMRequestResponse)\n    println(\"  \", T)\nend\n\nresult = chatrequest!(chat)\n\nif result isa LLMSuccess\n    println(\"Assistant: \", result.message.content)\n    println(\"Finish reason: \", result.message.finish_reason)\nelseif result isa LLMFailure\n    @warn \"API returned HTTP $(result.status): $(result.response)\"\nelseif result isa LLMCallError\n    @error \"Call failed: $(result.error)\"\nend\n\nFor the Responses API:\n\nresult = respond(\"Hello!\")\n\nif result isa ResponseSuccess\n    println(output_text(result))\n    println(\"Status: \", result.response.status)\n    println(\"Model: \", result.response.model)\nelseif result isa ResponseFailure\n    @warn \"HTTP $(result.status)\"\nelseif result isa ResponseCallError\n    @error result.error\nend","category":"section"},{"location":"getting_started/#What's-Next?","page":"Getting Started","title":"What's Next?","text":"Want to... Read...\nBuild multi-turn conversations Chat Completions Guide\nUse the newer Responses API Responses API Guide\nGenerate images from prompts Image Generation Guide\nCall functions from the model Tool Calling Guide\nStream tokens in real-time Streaming Guide\nGet structured JSON output Structured Output Guide\nUse Azure or Gemini Multi-Backend Guide","category":"section"},{"location":"llm/#UniLM.jl-—-LLM-Reference","page":"LLM Reference","title":"UniLM.jl — LLM Reference","text":"Single-file reference for LLM code-generation systems. UniLM.jl v0.8.0 · Julia ≥ 1.12 · Deps: HTTP.jl, JSON.jl, Base64 Repo: https://github.com/algunion/UniLM.jl","category":"section"},{"location":"llm/#Installation","page":"LLM Reference","title":"Installation","text":"using Pkg\nPkg.add(\"UniLM\")\nusing UniLM","category":"section"},{"location":"llm/#Environment-Variables","page":"LLM Reference","title":"Environment Variables","text":"Variable Required by Description\nOPENAI_API_KEY OPENAIServiceEndpoint (default) OpenAI API key\nAZURE_OPENAI_BASE_URL AZUREServiceEndpoint Azure deployment base URL\nAZURE_OPENAI_API_KEY AZUREServiceEndpoint Azure API key\nAZURE_OPENAI_API_VERSION AZUREServiceEndpoint Azure API version string\nAZURE_OPENAI_DEPLOY_NAME_GPT_5_2 AZUREServiceEndpoint Auto-registers Azure deployment for \"gpt-5.2\"\nGEMINI_API_KEY GEMINIServiceEndpoint Google Gemini API key","category":"section"},{"location":"llm/#Four-APIs","page":"LLM Reference","title":"Four APIs","text":"UniLM.jl wraps four OpenAI API surfaces:\n\nChat Completions (Chat + chatrequest!) — stateful, message-based conversations with tool calling, streaming, structured output. Supports OpenAI, Azure, and Gemini backends.\nResponses API (Respond + respond) — newer, more flexible API with built-in tools (web search, file search), multi-turn chaining via previous_response_id, reasoning support for O-series models, structured output. OpenAI only.\nImage Generation (ImageGeneration + generate_image) — text-to-image with gpt-image-1.5. OpenAI only.\nEmbeddings (Embeddings + embeddingrequest!) — vector embeddings with text-embedding-3-small.\n\n","category":"section"},{"location":"llm/#Service-Endpoints","page":"LLM Reference","title":"Service Endpoints","text":"abstract type ServiceEndpoint end\nstruct OPENAIServiceEndpoint <: ServiceEndpoint end   # default — uses OPENAI_API_KEY\nstruct AZUREServiceEndpoint  <: ServiceEndpoint end   # uses AZURE_OPENAI_* env vars\nstruct GEMINIServiceEndpoint <: ServiceEndpoint end   # uses GEMINI_API_KEY\nstruct GenericOpenAIEndpoint <: ServiceEndpoint       # any OpenAI-compatible provider\n    base_url::String\n    api_key::String\nend\n\n# Convenience constructors\nOllamaEndpoint(; base_url=\"http://localhost:11434\")   # Ollama local\nMistralEndpoint(; api_key=ENV[\"MISTRAL_API_KEY\"])     # Mistral AI\nDeepSeekEndpoint(; api_key=ENV[\"DEEPSEEK_API_KEY\"])   # DeepSeek","category":"section"},{"location":"llm/#Provider-Compatibility","page":"LLM Reference","title":"Provider Compatibility","text":"API Surface Status Providers\nChat Completions De facto standard OpenAI, Azure, Gemini, Mistral, Ollama, vLLM, LM Studio, Anthropic*\nEmbeddings Widely adopted OpenAI, Gemini, Mistral, Ollama, vLLM\nResponses API Emerging (Open Responses) OpenAI, Ollama, vLLM, Amazon Bedrock\nImage Generation Limited OpenAI, Gemini, Ollama\n\n*Anthropic compat layer not production-recommended by Anthropic.\n\nRegister additional Azure deployments at runtime:\n\nadd_azure_deploy_name!(model::String, deploy_name::String)\n# e.g. add_azure_deploy_name!(\"gpt-5.2\", \"my-deployment\")\n\nPass the backend via the service keyword on Chat, Respond, or ImageGeneration:\n\nChat(service=AZUREServiceEndpoint, model=\"gpt-5.2\")\nRespond(service=OPENAIServiceEndpoint, input=\"Hello\")\n\n","category":"section"},{"location":"llm/#Chat-Completions-API","page":"LLM Reference","title":"Chat Completions API","text":"","category":"section"},{"location":"llm/#Chat","page":"LLM Reference","title":"Chat","text":"@kwdef struct Chat\n    service::Type{<:ServiceEndpoint} = OPENAIServiceEndpoint\n    model::String = \"gpt-5.2\"\n    messages::Vector{Message} = Message[]\n    history::Bool = true\n    tools::Union{Vector{GPTTool},Nothing} = nothing\n    tool_choice::Union{String,GPTToolChoice,Nothing} = nothing\n    parallel_tool_calls::Union{Bool,Nothing} = false\n    temperature::Union{Float64,Nothing} = nothing       # 0.0–2.0, mutually exclusive with top_p\n    top_p::Union{Float64,Nothing} = nothing              # 0.0–1.0, mutually exclusive with temperature\n    n::Union{Int64,Nothing} = nothing\n    stream::Union{Bool,Nothing} = nothing\n    stop::Union{Vector{String},String,Nothing} = nothing # max 4 sequences\n    max_tokens::Union{Int64,Nothing} = nothing\n    presence_penalty::Union{Float64,Nothing} = nothing   # -2.0 to 2.0\n    response_format::Union{ResponseFormat,Nothing} = nothing\n    frequency_penalty::Union{Float64,Nothing} = nothing  # -2.0 to 2.0\n    logit_bias::Union{AbstractDict{String,Float64},Nothing} = nothing\n    user::Union{String,Nothing} = nothing\n    seed::Union{Int64,Nothing} = nothing\nend\n\nhistory=true: responses are automatically appended to messages.\ntemperature and top_p are mutually exclusive (constructor throws ArgumentError).\nparallel_tool_calls is auto-set to nothing when tools is nothing.\nParameter validation: the constructor validates ranges at construction time — temperature ∈ [0.0, 2.0], top_p ∈ [0.0, 1.0], n ∈ [1, 10], presence_penalty ∈ [-2.0, 2.0], frequency_penalty ∈ [-2.0, 2.0]. Out-of-range values throw ArgumentError.","category":"section"},{"location":"llm/#Message","page":"LLM Reference","title":"Message","text":"@kwdef struct Message\n    role::String                                          # RoleSystem, RoleUser, RoleAssistant, or \"tool\"\n    content::Union{String,Nothing} = nothing\n    name::Union{String,Nothing} = nothing\n    finish_reason::Union{String,Nothing} = nothing        # \"stop\", \"tool_calls\", \"content_filter\"\n    refusal_message::Union{String,Nothing} = nothing\n    tool_calls::Union{Nothing,Vector{GPTToolCall}} = nothing\n    tool_call_id::Union{String,Nothing} = nothing         # required when role == \"tool\"\nend\n\nValidation: at least one of content, tool_calls, or refusal_message must be non-nothing. tool_call_id is required when role == \"tool\".\n\nConvenience constructors:\n\nMessage(Val(:system), \"You are a helpful assistant\")\nMessage(Val(:user), \"Hello!\")\n\nRole constants: RoleSystem = \"system\", RoleUser = \"user\", RoleAssistant = \"assistant\".","category":"section"},{"location":"llm/#chatrequest!","page":"LLM Reference","title":"chatrequest!","text":"# Mutating form — sends chat.messages, appends response when history=true\nchatrequest!(chat::Chat; retries::Int=0, callback=nothing) -> LLMSuccess | LLMFailure | LLMCallError | Task\n\n# Keyword-argument convenience form — builds a Chat internally\nchatrequest!(; service=OPENAIServiceEndpoint, model=\"gpt-5.2\",\n    systemprompt, userprompt, messages=Message[], history=true,\n    tools=nothing, tool_choice=nothing, temperature=nothing, ...) -> same\n\nNon-streaming: returns LLMSuccess, LLMFailure, or LLMCallError.\nStreaming (stream=true): returns a Task. Pass a callback(chunk::Union{String,Message}, close::Ref{Bool}).\nAuto-retries on HTTP 429/500/503 with exponential backoff and jitter (up to 30 attempts). Respects Retry-After headers on 429 responses.","category":"section"},{"location":"llm/#Conversation-Management","page":"LLM Reference","title":"Conversation Management","text":"push!(chat, message)       # append a Message\npop!(chat)                 # remove last message\nupdate!(chat, message)     # append if history=true\nissendvalid(chat) -> Bool  # check conversation rules (≥1 message, system first if present, etc.)\nlength(chat)               # number of messages\nisempty(chat)              # true if no messages\nchat[i]                    # index into messages","category":"section"},{"location":"llm/#Tool-Calling-Types","page":"LLM Reference","title":"Tool Calling Types","text":"# Define a function the model can call\n@kwdef struct GPTFunctionSignature\n    name::String\n    description::Union{String,Nothing} = nothing\n    parameters::Union{AbstractDict,Nothing} = nothing   # JSON Schema dict\nend\n\n# Wrap it for the tools parameter\n@kwdef struct GPTTool\n    type::String = \"function\"\n    func::GPTFunctionSignature\nend\nGPTTool(d::AbstractDict)   # construct from dict with keys \"name\", \"description\", \"parameters\"\n\n# Returned by model when it wants to call a function\n@kwdef struct GPTToolCall\n    id::String\n    type::String = \"function\"\n    func::GPTFunction       # has .name::String and .arguments::AbstractDict\nend\n\n# Your result after executing the function\nstruct GPTFunctionCallResult{T}\n    name::Union{String,Symbol}\n    origincall::GPTFunction\n    result::T\nend","category":"section"},{"location":"llm/#ResponseFormat-(Structured-Output)","page":"LLM Reference","title":"ResponseFormat (Structured Output)","text":"@kwdef struct ResponseFormat\n    type::String = \"json_object\"                               # \"json_object\" or \"json_schema\"\n    json_schema::Union{JsonSchemaAPI,AbstractDict,Nothing} = nothing\nend\nResponseFormat(json_schema)  # shorthand, sets type=\"json_schema\"","category":"section"},{"location":"llm/#Chat-Completions-Example","page":"LLM Reference","title":"Chat Completions Example","text":"using UniLM\n\n# Build conversation\nchat = Chat(model=\"gpt-5.2\")\npush!(chat, Message(Val(:system), \"You are a helpful assistant.\"))\npush!(chat, Message(Val(:user), \"What is the capital of France?\"))\n\nresult = chatrequest!(chat)\nif result isa LLMSuccess\n    println(result.message.content)     # \"Paris...\"\n    # chat.messages already has the response appended (history=true)\nend\n\n# One-shot via keywords\nresult = chatrequest!(\n    systemprompt=\"You are a translator.\",\n    userprompt=\"Translate 'hello' to French.\",\n    model=\"gpt-5.2\"\n)","category":"section"},{"location":"llm/#Tool-Calling-Example-(Chat)","page":"LLM Reference","title":"Tool Calling Example (Chat)","text":"weather_tool = GPTTool(func=GPTFunctionSignature(\n    name=\"get_weather\",\n    description=\"Get current weather\",\n    parameters=Dict(\n        \"type\" => \"object\",\n        \"properties\" => Dict(\"location\" => Dict(\"type\" => \"string\")),\n        \"required\" => [\"location\"]\n    )\n))\n\nchat = Chat(model=\"gpt-5.2\", tools=[weather_tool])\npush!(chat, Message(Val(:system), \"You help with weather.\"))\npush!(chat, Message(Val(:user), \"Weather in Paris?\"))\n\nresult = chatrequest!(chat)\nif result isa LLMSuccess && result.message.finish_reason == \"tool_calls\"\n    for tc in result.message.tool_calls\n        # tc.func.name == \"get_weather\", tc.func.arguments == Dict(\"location\" => \"Paris\")\n        answer = \"22°C, sunny\"  # your function result\n        push!(chat, Message(role=\"tool\", content=answer, tool_call_id=tc.id))\n    end\n    result2 = chatrequest!(chat)\n    println(result2.message.content)\nend","category":"section"},{"location":"llm/#Streaming-Example-(Chat)","page":"LLM Reference","title":"Streaming Example (Chat)","text":"chat = Chat(model=\"gpt-5.2\", stream=true)\npush!(chat, Message(Val(:system), \"You are helpful.\"))\npush!(chat, Message(Val(:user), \"Tell me a story.\"))\n\ntask = chatrequest!(chat) do chunk, close_ref\n    if chunk isa String\n        print(chunk)            # partial text delta\n    elseif chunk isa Message\n        println(\"\\n[Done]\")     # final assembled message\n        # close_ref[] = true    # to stop early\n    end\nend\n\nresult = fetch(task)  # LLMSuccess when complete\n\n","category":"section"},{"location":"llm/#Responses-API","page":"LLM Reference","title":"Responses API","text":"","category":"section"},{"location":"llm/#Respond","page":"LLM Reference","title":"Respond","text":"@kwdef struct Respond\n    service::Type{<:ServiceEndpoint} = OPENAIServiceEndpoint\n    model::String = \"gpt-5.2\"\n    input::Union{String, Vector}                             # String or Vector{InputMessage}\n    instructions::Union{String,Nothing} = nothing\n    tools::Union{Vector,Nothing} = nothing                  # Vector of ResponseTool subtypes\n    tool_choice::Union{String,Nothing} = nothing            # \"auto\", \"none\", \"required\"\n    parallel_tool_calls::Union{Bool,Nothing} = nothing\n    temperature::Union{Float64,Nothing} = nothing           # 0.0–2.0, mutually exclusive with top_p\n    top_p::Union{Float64,Nothing} = nothing                 # 0.0–1.0\n    max_output_tokens::Union{Int64,Nothing} = nothing\n    stream::Union{Bool,Nothing} = nothing\n    text::Union{TextConfig,Nothing} = nothing               # output format\n    reasoning::Union{Reasoning,Nothing} = nothing           # O-series models\n    truncation::Union{String,Nothing} = nothing             # \"auto\" or \"disabled\"\n    store::Union{Bool,Nothing} = nothing                    # store for later retrieval\n    metadata::Union{AbstractDict,Nothing} = nothing\n    previous_response_id::Union{String,Nothing} = nothing   # multi-turn chaining\n    user::Union{String,Nothing} = nothing\n    background::Union{Bool,Nothing} = nothing\n    include::Union{Vector{String},Nothing} = nothing\n    max_tool_calls::Union{Int64,Nothing} = nothing\n    service_tier::Union{String,Nothing} = nothing           # \"auto\",\"default\",\"flex\",\"priority\"\n    top_logprobs::Union{Int64,Nothing} = nothing            # 0–20\n    prompt::Union{AbstractDict,Nothing} = nothing\n    prompt_cache_key::Union{String,Nothing} = nothing\n    prompt_cache_retention::Union{String,Nothing} = nothing  # \"in-memory\",\"24h\"\n    safety_identifier::Union{String,Nothing} = nothing\n    conversation::Union{Any,Nothing} = nothing\n    context_management::Union{Vector,Nothing} = nothing\n    stream_options::Union{AbstractDict,Nothing} = nothing\nend","category":"section"},{"location":"llm/#Input-Helpers","page":"LLM Reference","title":"Input Helpers","text":"# Structured input messages\nInputMessage(role=\"user\", content=\"Hello\")\nInputMessage(role=\"user\", content=[input_text(\"Describe:\"), input_image(\"https://...\")])\n\n# Content part constructors\ninput_text(text::String)                                    # → Dict(:type=>\"input_text\", :text=>...)\ninput_image(url::String; detail=nothing)                    # → Dict(:type=>\"input_image\", ...) detail: \"auto\",\"low\",\"high\"\ninput_file(; url=nothing, id=nothing)                       # → Dict(:type=>\"input_file\", ...) provide url or file id","category":"section"},{"location":"llm/#Tool-Types","page":"LLM Reference","title":"Tool Types","text":"abstract type ResponseTool end\n\n@kwdef struct FunctionTool <: ResponseTool\n    name::String\n    description::Union{String,Nothing} = nothing\n    parameters::Union{AbstractDict,Nothing} = nothing\n    strict::Union{Bool,Nothing} = nothing\nend\n\n@kwdef struct WebSearchTool <: ResponseTool\n    search_context_size::String = \"medium\"                  # \"low\",\"medium\",\"high\"\n    user_location::Union{AbstractDict,Nothing} = nothing\nend\n\n@kwdef struct FileSearchTool <: ResponseTool\n    vector_store_ids::Vector{String}\n    max_num_results::Union{Int,Nothing} = nothing\n    ranking_options::Union{AbstractDict,Nothing} = nothing\n    filters::Union{AbstractDict,Nothing} = nothing\nend\n\n@kwdef struct MCPTool <: ResponseTool\n    server_label::String\n    server_url::String\n    require_approval::Union{String, AbstractDict, Nothing} = \"never\"\n    allowed_tools::Union{Vector{String}, Nothing} = nothing\n    headers::Union{AbstractDict, Nothing} = nothing\nend\n\n@kwdef struct ComputerUseTool <: ResponseTool\n    display_width::Int = 1024\n    display_height::Int = 768\n    environment::Union{String, Nothing} = nothing\nend\n\n@kwdef struct ImageGenerationTool <: ResponseTool\n    background::Union{String, Nothing} = nothing\n    output_format::Union{String, Nothing} = nothing\n    output_compression::Union{Int, Nothing} = nothing\n    quality::Union{String, Nothing} = nothing\n    size::Union{String, Nothing} = nothing\nend\n\n@kwdef struct CodeInterpreterTool <: ResponseTool\n    container::Union{AbstractDict, Nothing} = nothing\n    file_ids::Union{Vector{String}, Nothing} = nothing\nend\n\nConvenience constructors:\n\nfunction_tool(name, description=nothing; parameters=nothing, strict=nothing)\nfunction_tool(d::AbstractDict)           # from dict with keys \"name\", \"description\", \"parameters\"\nweb_search(; context_size=\"medium\", location=nothing)\nfile_search(store_ids; max_results=nothing, ranking=nothing, filters=nothing)\nmcp_tool(label, url; require_approval=\"never\", allowed_tools=nothing, headers=nothing)\ncomputer_use(; display_width=1024, display_height=768, environment=nothing)\nimage_generation_tool(; kwargs...)\ncode_interpreter(; container=nothing, file_ids=nothing)","category":"section"},{"location":"llm/#Text-Format-/-Structured-Output","page":"LLM Reference","title":"Text Format / Structured Output","text":"@kwdef struct TextFormatSpec\n    type::String = \"text\"                                   # \"text\",\"json_object\",\"json_schema\"\n    name::Union{String,Nothing} = nothing\n    description::Union{String,Nothing} = nothing\n    schema::Union{AbstractDict,Nothing} = nothing\n    strict::Union{Bool,Nothing} = nothing\nend\n\n@kwdef struct TextConfig\n    format::TextFormatSpec = TextFormatSpec()\nend\n\nConvenience constructors:\n\ntext_format(; kwargs...)                                     # generic TextConfig\njson_schema_format(name, description, schema; strict=nothing) # JSON Schema output\njson_schema_format(d::AbstractDict)                          # from dict with keys \"name\", \"description\", \"schema\"\njson_object_format()                                         # unstructured JSON","category":"section"},{"location":"llm/#Reasoning-(O-series-models)","page":"LLM Reference","title":"Reasoning (O-series models)","text":"@kwdef struct Reasoning\n    effort::Union{String,Nothing} = nothing                 # \"none\",\"low\",\"medium\",\"high\"\n    generate_summary::Union{String,Nothing} = nothing       # \"auto\",\"concise\",\"detailed\"\n    summary::Union{String,Nothing} = nothing                # deprecated alias\nend\n\nRespond(input=\"Hard math problem\", model=\"o3\", reasoning=Reasoning(effort=\"high\"))","category":"section"},{"location":"llm/#respond","page":"LLM Reference","title":"respond","text":"# Struct form\nrespond(r::Respond; retries=0, callback=nothing) -> ResponseSuccess | ResponseFailure | ResponseCallError | Task\n\n# Convenience — builds Respond internally\nrespond(input; kwargs...) -> same\n\n# do-block streaming — auto-sets stream=true\nrespond(callback::Function, input; kwargs...) -> Task\n\nStreaming callback signature: callback(chunk::Union{String, ResponseObject}, close::Ref{Bool})\nAuto-retries on HTTP 429/500/503 with exponential backoff and jitter (up to 30 attempts). Respects Retry-After headers.\nParameter validation: temperature ∈ [0.0, 2.0], top_p ∈ [0.0, 1.0], max_output_tokens ≥ 1, top_logprobs ∈ [0, 20]. Out-of-range values throw ArgumentError.","category":"section"},{"location":"llm/#Response-Accessors","page":"LLM Reference","title":"Response Accessors","text":"output_text(result::ResponseSuccess)::String                # concatenated text output\noutput_text(result::ResponseFailure)::String                # error message\noutput_text(result::ResponseCallError)::String              # error message\n\nfunction_calls(result::ResponseSuccess)::Vector{Dict{String,Any}}\n# Each dict has: \"id\", \"call_id\", \"name\", \"arguments\" (JSON string), \"status\"","category":"section"},{"location":"llm/#Response-Management-Functions","page":"LLM Reference","title":"Response Management Functions","text":"get_response(id::String; service=OPENAIServiceEndpoint)           -> ResponseSuccess | ResponseFailure | ResponseCallError\ndelete_response(id::String; service=OPENAIServiceEndpoint)        -> Dict | ResponseFailure | ResponseCallError\nlist_input_items(id::String; limit=20, order=\"desc\", after=nothing, service=OPENAIServiceEndpoint) -> Dict | ...\ncancel_response(id::String; service=OPENAIServiceEndpoint)        -> ResponseSuccess | ...\ncompact_response(; model=\"gpt-5.2\", input, service=OPENAIServiceEndpoint) -> Dict | ...\ncount_input_tokens(; model=\"gpt-5.2\", input, instructions=nothing, tools=nothing, service=OPENAIServiceEndpoint) -> Dict | ...","category":"section"},{"location":"llm/#ResponseObject","page":"LLM Reference","title":"ResponseObject","text":"@kwdef struct ResponseObject\n    id::String\n    status::String\n    model::String\n    output::Vector{Any}\n    usage::Union{Dict{String,Any},Nothing} = nothing\n    error::Union{Any,Nothing} = nothing\n    metadata::Union{Dict{String,Any},Nothing} = nothing\n    raw::Dict{String,Any}\nend","category":"section"},{"location":"llm/#Responses-API-Examples","page":"LLM Reference","title":"Responses API Examples","text":"using UniLM\n\n# Basic\nresult = respond(\"Tell me a joke\")\nif result isa ResponseSuccess\n    println(output_text(result))\nend\n\n# With instructions\nresult = respond(\"Hello\", instructions=\"You are a pirate. Respond in pirate speak.\")\n\n# Multi-turn via chaining\nr1 = respond(\"Tell me a joke\")\nr2 = respond(\"Tell me another\", previous_response_id=r1.response.id)\n\n# Structured output\nschema = Dict(\n    \"type\" => \"object\",\n    \"properties\" => Dict(\n        \"name\" => Dict(\"type\" => \"string\"),\n        \"age\" => Dict(\"type\" => \"integer\")\n    ),\n    \"required\" => [\"name\", \"age\"],\n    \"additionalProperties\" => false\n)\nresult = respond(\"Extract: John is 30 years old\",\n    text=json_schema_format(\"person\", \"A person\", schema, strict=true))\nparsed = JSON.parse(output_text(result))\n\n# Web search\nresult = respond(\"Latest Julia language news\", tools=[web_search()])\n\n# Function calling\ntool = function_tool(\"get_weather\", \"Get weather\",\n    parameters=Dict(\n        \"type\" => \"object\",\n        \"properties\" => Dict(\"location\" => Dict(\"type\" => \"string\")),\n        \"required\" => [\"location\"]\n    ))\nresult = respond(\"Weather in NYC?\", tools=ResponseTool[tool])\nfor call in function_calls(result)\n    println(call[\"name\"], \": \", call[\"arguments\"])\nend\n\n# Streaming (do-block)\nrespond(\"Tell me a story\") do chunk, close_ref\n    if chunk isa String\n        print(chunk)\n    elseif chunk isa ResponseObject\n        println(\"\\nDone: \", chunk.status)\n    end\nend\n\n# Reasoning (O-series)\nresult = respond(\"Prove that √2 is irrational\", model=\"o3\",\n    reasoning=Reasoning(effort=\"high\", generate_summary=\"concise\"))\n\n# Multimodal input\nresult = respond([\n    InputMessage(role=\"user\", content=[\n        input_text(\"What's in this image?\"),\n        input_image(\"https://example.com/photo.jpg\")\n    ])\n])\n\n# Count tokens without generating\ntokens = count_input_tokens(model=\"gpt-5.2\", input=\"Hello world\")\nprintln(tokens[\"input_tokens\"])\n\n","category":"section"},{"location":"llm/#Image-Generation-API","page":"LLM Reference","title":"Image Generation API","text":"","category":"section"},{"location":"llm/#ImageGeneration","page":"LLM Reference","title":"ImageGeneration","text":"@kwdef struct ImageGeneration\n    service::Type{<:ServiceEndpoint} = OPENAIServiceEndpoint\n    model::String = \"gpt-image-1.5\"\n    prompt::String\n    n::Union{Int,Nothing} = nothing                         # 1–10\n    size::Union{String,Nothing} = nothing                   # \"1024x1024\",\"1536x1024\",\"1024x1536\",\"auto\"\n    quality::Union{String,Nothing} = nothing                # \"low\",\"medium\",\"high\",\"auto\"\n    background::Union{String,Nothing} = nothing             # \"transparent\",\"opaque\",\"auto\"\n    output_format::Union{String,Nothing} = nothing          # \"png\",\"webp\",\"jpeg\"\n    output_compression::Union{Int,Nothing} = nothing        # 0–100 (webp/jpeg only)\n    user::Union{String,Nothing} = nothing\nend","category":"section"},{"location":"llm/#generate_image","page":"LLM Reference","title":"generate_image","text":"generate_image(ig::ImageGeneration; retries=0) -> ImageSuccess | ImageFailure | ImageCallError\ngenerate_image(prompt::String; kwargs...)       -> same   # convenience\n\nAuto-retries on 429/500/503 with exponential backoff and jitter (up to 30 attempts). Respects Retry-After headers.","category":"section"},{"location":"llm/#Response-Types","page":"LLM Reference","title":"Response Types","text":"struct ImageObject\n    b64_json::Union{String,Nothing}\n    revised_prompt::Union{String,Nothing}\nend\n\nstruct ImageResponse\n    created::Int64\n    data::Vector{ImageObject}\n    usage::Union{Dict{String,Any},Nothing}\n    raw::Dict{String,Any}\nend","category":"section"},{"location":"llm/#Accessors","page":"LLM Reference","title":"Accessors","text":"image_data(result::ImageSuccess)::Vector{String}       # base64-encoded image strings\nimage_data(result::ImageFailure)::String[]              # empty\nimage_data(result::ImageCallError)::String[]            # empty\nsave_image(img_b64::String, filepath::String)           # decode + write to disk, returns filepath","category":"section"},{"location":"llm/#Image-Generation-Example","page":"LLM Reference","title":"Image Generation Example","text":"using UniLM\n\nresult = generate_image(\"A watercolor painting of a Julia butterfly\",\n    size=\"1024x1024\", quality=\"high\")\n\nif result isa ImageSuccess\n    imgs = image_data(result)\n    save_image(imgs[1], \"butterfly.png\")\n    println(\"Saved! Revised prompt: \", result.response.data[1].revised_prompt)\nend\n\n# Multiple images with transparent background\nresult = generate_image(\"Minimalist logo\",\n    n=3, background=\"transparent\", output_format=\"png\")\n\n","category":"section"},{"location":"llm/#Embeddings-API","page":"LLM Reference","title":"Embeddings API","text":"","category":"section"},{"location":"llm/#Embeddings","page":"LLM Reference","title":"Embeddings","text":"struct Embeddings\n    model::String             # \"text-embedding-3-small\" (1536 dims)\n    input::Union{String,Vector{String}}\n    embeddings::Union{Vector{Float64},Vector{Vector{Float64}}}\n    user::Union{String,Nothing}\nend\n\nEmbeddings(input::String)           # single input, pre-allocates 1536-dim vector\nEmbeddings(input::Vector{String})   # batch input, pre-allocates one vector per input","category":"section"},{"location":"llm/#embeddingrequest!","page":"LLM Reference","title":"embeddingrequest!","text":"embeddingrequest!(emb::Embeddings; retries=0) -> (response_dict, emb) | nothing\n\nFills emb.embeddings in-place. Auto-retries on 429/500/503 with exponential backoff and jitter (up to 30 attempts). Respects Retry-After headers.","category":"section"},{"location":"llm/#Embeddings-Example","page":"LLM Reference","title":"Embeddings Example","text":"using UniLM, LinearAlgebra\n\nemb = Embeddings(\"What is Julia?\")\nembeddingrequest!(emb)\nprintln(emb.embeddings[1:5])  # first 5 dimensions\n\n# Batch + cosine similarity\nemb = Embeddings([\"cat\", \"dog\", \"airplane\"])\nembeddingrequest!(emb)\nsimilarity = dot(emb.embeddings[1], emb.embeddings[2]) /\n    (norm(emb.embeddings[1]) * norm(emb.embeddings[2]))\n\n","category":"section"},{"location":"llm/#Cost-Tracking","page":"LLM Reference","title":"Cost Tracking","text":"","category":"section"},{"location":"llm/#TokenUsage","page":"LLM Reference","title":"TokenUsage","text":"@kwdef struct TokenUsage\n    prompt_tokens::Int = 0\n    completion_tokens::Int = 0\n    total_tokens::Int = 0\nend","category":"section"},{"location":"llm/#Functions","page":"LLM Reference","title":"Functions","text":"token_usage(result::LLMSuccess)::Union{TokenUsage, Nothing}      # extract TokenUsage from a Chat result\ntoken_usage(result::ResponseSuccess)::Union{TokenUsage, Nothing}  # extract from Responses API result\n\nestimated_cost(result; model=nothing, pricing=DEFAULT_PRICING)     # per-call cost estimate (Float64)\ncumulative_cost(chat::Chat)::Float64                               # running total for a Chat instance\n\nDEFAULT_PRICING   # Dict{String, Tuple{Float64, Float64}} — model → (input_price, output_price) per token","category":"section"},{"location":"llm/#Cost-Tracking-Example","page":"LLM Reference","title":"Cost Tracking Example","text":"chat = Chat(model=\"gpt-5.2\")\npush!(chat, Message(Val(:system), \"You are helpful.\"))\npush!(chat, Message(Val(:user), \"Hello!\"))\n\nresult = chatrequest!(chat)\nif result isa LLMSuccess\n    usage = token_usage(result)\n    cost = estimated_cost(result)\n    println(\"Tokens: $(usage.total_tokens), Cost: \\$$(round(cost; digits=6))\")\n    println(\"Cumulative: \\$$(round(cumulative_cost(chat); digits=6))\")\nend\n\n","category":"section"},{"location":"llm/#Conversation-Forking","page":"LLM Reference","title":"Conversation Forking","text":"fork(chat::Chat)::Chat          # deep-copy a Chat, resetting cumulative cost\nfork(chat::Chat, n::Int)::Vector{Chat}  # create n independent forks","category":"section"},{"location":"llm/#Fork-Example","page":"LLM Reference","title":"Fork Example","text":"chat = Chat(model=\"gpt-5.2\")\npush!(chat, Message(Val(:system), \"You are a creative writer.\"))\npush!(chat, Message(Val(:user), \"Start a story about a robot.\"))\nchatrequest!(chat)\n\n# Fork into 3 independent continuations\nforks = fork(chat, 3)\nfor (i, f) in enumerate(forks)\n    push!(f, Message(Val(:user), \"Continue the story with ending $i.\"))\n    chatrequest!(f)\nend\n\n","category":"section"},{"location":"llm/#Tool-Loop","page":"LLM Reference","title":"Tool Loop","text":"Automated tool dispatch for both APIs. Wraps a tool schema with a callable function.","category":"section"},{"location":"llm/#CallableTool","page":"LLM Reference","title":"CallableTool","text":"struct CallableTool{T}\n    tool::T              # GPTTool or FunctionTool\n    callable::Function   # (name::String, args::Dict{String,Any}) -> String\nend","category":"section"},{"location":"llm/#to_tool","page":"LLM Reference","title":"to_tool","text":"to_tool(x)  # identity for GPTTool, FunctionTool, CallableTool; converts AbstractDict to GPTTool","category":"section"},{"location":"llm/#ToolCallOutcome-/-ToolLoopResult","page":"LLM Reference","title":"ToolCallOutcome / ToolLoopResult","text":"# Per-call record\nstruct ToolCallOutcome\n    tool_name::String\n    arguments::Dict{String,Any}\n    result::Union{GPTFunctionCallResult,Nothing}\n    success::Bool\n    error::Union{String,Nothing}\nend\n\n# Loop result\nstruct ToolLoopResult\n    response::LLMRequestResponse\n    tool_calls::Vector{ToolCallOutcome}\n    turns_used::Int\n    completed::Bool\n    llm_error::Union{String,Nothing}\nend","category":"section"},{"location":"llm/#tool_loop!-(Chat-Completions)","page":"LLM Reference","title":"tool_loop! (Chat Completions)","text":"tool_loop!(chat, dispatcher; max_turns=10, retries=0) -> ToolLoopResult\ntool_loop!(chat; tools::Vector{<:CallableTool}, kwargs...) -> ToolLoopResult","category":"section"},{"location":"llm/#tool_loop-(Responses-API)","page":"LLM Reference","title":"tool_loop (Responses API)","text":"tool_loop(r::Respond, dispatcher; max_turns=10, retries=0) -> ToolLoopResult\ntool_loop(r::Respond; max_turns=10, retries=0) -> ToolLoopResult   # extracts callables from r.tools\ntool_loop(input, dispatcher; tools, kwargs...) -> ToolLoopResult    # convenience form\n\n","category":"section"},{"location":"llm/#MCP-Client","page":"LLM Reference","title":"MCP Client","text":"Native MCP client (JSON-RPC 2.0 over stdio or HTTP, spec 2025-11-25).","category":"section"},{"location":"llm/#Types","page":"LLM Reference","title":"Types","text":"MCPSession            # live connection — manages transport + cached tools/resources/prompts\nMCPToolInfo           # tool definition from tools/list\nMCPResourceInfo       # resource definition from resources/list\nMCPPromptInfo         # prompt definition from prompts/list\nMCPServerCapabilities # capabilities from initialize\nMCPTransport          # abstract (subtypes: StdioTransport, HTTPTransport)\nMCPError <: Exception # JSON-RPC error (code, message, data)","category":"section"},{"location":"llm/#Lifecycle","page":"LLM Reference","title":"Lifecycle","text":"mcp_connect(command::Cmd; ...) -> MCPSession     # stdio subprocess\nmcp_connect(url::String; headers=[], ...) -> MCPSession  # HTTP\nmcp_connect(f::Function, args...; ...)            # do-block, auto-disconnect\nmcp_disconnect!(session)","category":"section"},{"location":"llm/#Discovery","page":"LLM Reference","title":"Discovery","text":"list_tools!(session) -> Vector{MCPToolInfo}\nlist_resources!(session) -> Vector{MCPResourceInfo}\nlist_prompts!(session) -> Vector{MCPPromptInfo}","category":"section"},{"location":"llm/#Operations","page":"LLM Reference","title":"Operations","text":"call_tool(session, name, arguments) -> String\nread_resource(session, uri) -> String\nget_prompt(session, name, arguments) -> Vector{Dict}\nping(session)","category":"section"},{"location":"llm/#Tool-Bridge","page":"LLM Reference","title":"Tool Bridge","text":"mcp_tools(session) -> Vector{CallableTool{GPTTool}}         # for tool_loop!\nmcp_tools_respond(session) -> Vector{CallableTool{FunctionTool}}  # for tool_loop","category":"section"},{"location":"llm/#Client-Example","page":"LLM Reference","title":"Client Example","text":"session = mcp_connect(`npx -y @modelcontextprotocol/server-filesystem /tmp`)\ntools = mcp_tools(session)\nchat = Chat(model=\"gpt-5.2\", tools=map(t -> t.tool, tools))\npush!(chat, Message(Val(:user), \"List files\"))\nresult = tool_loop!(chat; tools)\nmcp_disconnect!(session)\n\n","category":"section"},{"location":"llm/#MCP-Server","page":"LLM Reference","title":"MCP Server","text":"Build MCP servers that expose tools, resources, and prompts.","category":"section"},{"location":"llm/#Types-2","page":"LLM Reference","title":"Types","text":"MCPServer(name, version; description=nothing)\nMCPServerPrimitive    # abstract (MCPServerTool, MCPServerResource, MCPServerResourceTemplate, MCPServerPrompt)","category":"section"},{"location":"llm/#Registration","page":"LLM Reference","title":"Registration","text":"register_tool!(server, name, description, schema, handler)\nregister_tool!(server, name, description, handler)           # auto-schema from signature\nregister_tool!(server, ct::CallableTool{GPTTool})            # bridge from Chat API\nregister_tool!(server, ct::CallableTool{FunctionTool})       # bridge from Responses API\nregister_resource!(server, uri, name, handler; mime_type=\"text/plain\", description=nothing)\nregister_resource_template!(server, uri_template, name, handler; ...)\nregister_prompt!(server, name, handler; description=nothing, arguments=[])","category":"section"},{"location":"llm/#Macros","page":"LLM Reference","title":"Macros","text":"@mcp_tool server function name(args...) body end\n@mcp_resource server uri function(args...) body end\n@mcp_prompt server name function(args...) body end","category":"section"},{"location":"llm/#Serving","page":"LLM Reference","title":"Serving","text":"serve(server; transport=:stdio)                         # default — stdio\nserve(server; transport=:http, host=\"127.0.0.1\", port=8080)  # HTTP","category":"section"},{"location":"llm/#Server-Example","page":"LLM Reference","title":"Server Example","text":"server = MCPServer(\"calc\", \"1.0.0\")\n@mcp_tool server function add(a::Float64, b::Float64)::String\n    string(a + b)\nend\nserve(server)\n\n","category":"section"},{"location":"llm/#FIM-Completion","page":"LLM Reference","title":"FIM Completion","text":"Fill-in-the-Middle: generate text between a prompt (prefix) and suffix. Supported by DeepSeek (beta), Ollama, vLLM.\n\n@kwdef struct FIMCompletion\n    service::ServiceEndpointSpec\n    model::String = \"deepseek-chat\"\n    prompt::String\n    suffix::Union{String,Nothing} = nothing\n    max_tokens::Union{Int,Nothing} = 128\n    # temperature, top_p, stream, stop, echo, logprobs, frequency_penalty, presence_penalty\nend\n\nstruct FIMChoice; text, index, finish_reason; end\nstruct FIMResponse; choices, usage, model, raw; end\nstruct FIMSuccess <: LLMRequestResponse; response::FIMResponse; end\nstruct FIMFailure <: LLMRequestResponse; response, status; end\nstruct FIMCallError <: LLMRequestResponse; error, status; end\n\nfim_complete(fim::FIMCompletion; retries=0) -> LLMRequestResponse\nfim_complete(prompt; suffix=nothing, kwargs...) -> LLMRequestResponse  # convenience\nfim_text(result) -> String  # extract generated text","category":"section"},{"location":"llm/#FIM-Example","page":"LLM Reference","title":"FIM Example","text":"result = fim_complete(\"def fib(a):\",\n    service=DeepSeekEndpoint(), suffix=\"    return fib(a-1) + fib(a-2)\",\n    max_tokens=128, stop=[\"\\n\\n\"])\nprintln(fim_text(result))\n\n","category":"section"},{"location":"llm/#Chat-Prefix-Completion","page":"LLM Reference","title":"Chat Prefix Completion","text":"Continue from a partial assistant message. The model generates text continuing from the assistant's prefix. DeepSeek beta feature.\n\nprefix_complete(chat::Chat; retries=0) -> LLMRequestResponse\n# Last message must be role=assistant with the prefix text","category":"section"},{"location":"llm/#Prefix-Example","page":"LLM Reference","title":"Prefix Example","text":"chat = Chat(service=DeepSeekEndpoint(), model=\"deepseek-chat\")\npush!(chat, Message(Val(:system), \"You are a coding assistant.\"))\npush!(chat, Message(Val(:user), \"Write quicksort in Python\"))\npush!(chat, Message(role=RoleAssistant, content=\"```python\\n\"))\nresult = prefix_complete(chat)\n\n","category":"section"},{"location":"llm/#Provider-Capabilities","page":"LLM Reference","title":"Provider Capabilities","text":"Each endpoint declares supported features. Request functions validate before dispatch.\n\nprovider_capabilities(service) -> Set{Symbol}\nhas_capability(service, cap::Symbol) -> Bool","category":"section"},{"location":"llm/#Capabilities-by-Provider","page":"LLM Reference","title":"Capabilities by Provider","text":"Provider Capabilities\nOpenAI :chat, :responses, :embeddings, :images, :tools, :json_output\nAzure :chat, :tools\nGemini :chat, :embeddings, :tools, :json_output\nDeepSeek :chat, :tools, :fim, :prefix_completion, :json_output\nGeneric :chat, :embeddings, :fim, :tools, :responses\n\n","category":"section"},{"location":"llm/#Result-Type-Hierarchy","page":"LLM Reference","title":"Result Type Hierarchy","text":"All API call results inherit from LLMRequestResponse:\n\nLLMRequestResponse (abstract)\n├── LLMSuccess          — Chat Completions success (.message::Message, .self::Chat)\n├── LLMFailure          — Chat Completions HTTP error (.response::String, .status::Int, .self::Chat)\n├── LLMCallError        — Chat Completions exception (.error::String, .status, .self::Chat)\n├── ResponseSuccess     — Responses API success (.response::ResponseObject)\n├── ResponseFailure     — Responses API HTTP error (.response::String, .status::Int)\n├── ResponseCallError   — Responses API exception (.error::String, .status)\n├── ImageSuccess        — Image Gen success (.response::ImageResponse)\n├── ImageFailure        — Image Gen HTTP error (.response::String, .status::Int)\n├── ImageCallError      — Image Gen exception (.error::String, .status)\n├── FIMSuccess          — FIM success (.response::FIMResponse)\n├── FIMFailure          — FIM HTTP error (.response::String, .status::Int)\n└── FIMCallError        — FIM exception (.error::String, .status)\n\nStandard pattern-matching idiom:\n\nresult = chatrequest!(chat)\nif result isa LLMSuccess\n    println(result.message.content)\nelseif result isa LLMFailure\n    @error \"HTTP $(result.status): $(result.response)\"\nelseif result isa LLMCallError\n    @error \"Exception: $(result.error)\"\nend\n\nresult = respond(\"Hello\")\nif result isa ResponseSuccess\n    println(output_text(result))\nelseif result isa ResponseFailure\n    @error \"HTTP $(result.status)\"\nelseif result isa ResponseCallError\n    @error result.error\nend\n\nresult = generate_image(\"A cat\")\nif result isa ImageSuccess\n    save_image(image_data(result)[1], \"cat.png\")\nelseif result isa ImageFailure\n    @error \"HTTP $(result.status)\"\nelseif result isa ImageCallError\n    @error result.error\nend\n\n","category":"section"},{"location":"llm/#API-Constants","page":"LLM Reference","title":"API Constants","text":"const OPENAI_BASE_URL = \"https://api.openai.com\"\nconst CHAT_COMPLETIONS_PATH = \"/v1/chat/completions\"\nconst EMBEDDINGS_PATH = \"/v1/embeddings\"\nconst RESPONSES_PATH = \"/v1/responses\"\nconst IMAGES_GENERATIONS_PATH = \"/v1/images/generations\"\nconst GEMINI_CHAT_URL = \"https://generativelanguage.googleapis.com/v1beta/openai/chat/completions\"","category":"section"},{"location":"llm/#Exceptions","page":"LLM Reference","title":"Exceptions","text":"struct InvalidConversationError <: Exception\n    reason::String\nend\n\nThrown by issendvalid / internal validation when conversation structure is invalid (e.g., missing system message position, consecutive same-role messages).\n\n","category":"section"},{"location":"llm/#Complete-Exports-List","page":"LLM Reference","title":"Complete Exports List","text":"Chat Completions: Chat, Message, RoleSystem, RoleUser, RoleAssistant, GPTTool, GPTToolCall, GPTFunctionSignature, GPTFunctionCallResult, InvalidConversationError, issendvalid, chatrequest!, update!, ResponseFormat\n\nResponses API: Respond, InputMessage, ResponseTool, FunctionTool, WebSearchTool, FileSearchTool, MCPTool, ComputerUseTool, ImageGenerationTool, CodeInterpreterTool, TextConfig, TextFormatSpec, Reasoning, ResponseObject, ResponseSuccess, ResponseFailure, ResponseCallError, respond, get_response, delete_response, list_input_items, cancel_response, compact_response, count_input_tokens, output_text, function_calls, input_text, input_image, input_file, function_tool, web_search, file_search, mcp_tool, computer_use, image_generation_tool, code_interpreter, text_format, json_schema_format, json_object_format\n\nImage Generation: ImageGeneration, ImageObject, ImageResponse, ImageSuccess, ImageFailure, ImageCallError, generate_image, image_data, save_image\n\nEmbeddings: Embeddings, embeddingrequest!\n\nCost Tracking: TokenUsage, token_usage, estimated_cost, cumulative_cost, DEFAULT_PRICING\n\nService Endpoints: ServiceEndpoint, ServiceEndpointSpec, OPENAIServiceEndpoint, AZUREServiceEndpoint, GEMINIServiceEndpoint, GenericOpenAIEndpoint, OllamaEndpoint, MistralEndpoint, DeepSeekEndpoint, add_azure_deploy_name!\n\nForking: fork\n\nTool Loop: CallableTool, ToolCallOutcome, ToolLoopResult, tool_loop!, tool_loop, to_tool\n\nMCP Client: MCPSession, MCPToolInfo, MCPResourceInfo, MCPPromptInfo, MCPServerCapabilities, MCPTransport, StdioTransport, HTTPTransport, MCPError, mcp_connect, mcp_disconnect!, mcp_tools, mcp_tools_respond, list_tools!, list_resources!, list_prompts!, call_tool, read_resource, get_prompt, ping\n\nMCP Server: MCPServer, MCPServerTool, MCPServerResource, MCPServerResourceTemplate, MCPServerPrompt, MCPServerPrimitive, register_tool!, register_resource!, register_resource_template!, register_prompt!, serve, @mcp_tool, @mcp_resource, @mcp_prompt\n\nFIM / Completions: FIMCompletion, FIMChoice, FIMResponse, FIMSuccess, FIMFailure, FIMCallError, fim_complete, fim_text, prefix_complete\n\nProvider Capabilities: has_capability, provider_capabilities\n\nResult Types: LLMRequestResponse, LLMSuccess, LLMFailure, LLMCallError","category":"section"},{"location":"api/capabilities/#capabilities_api","page":"Provider Capabilities","title":"Provider Capabilities","text":"Functions for querying and validating provider capabilities.\n\nEach service endpoint declares which API features it supports. Request functions validate capabilities before dispatching, giving clear errors instead of HTTP 404s.","category":"section"},{"location":"api/capabilities/#Functions","page":"Provider Capabilities","title":"Functions","text":"","category":"section"},{"location":"api/capabilities/#Capability-Symbols","page":"Provider Capabilities","title":"Capability Symbols","text":"Symbol Description\n:chat Chat Completions API (/v1/chat/completions)\n:embeddings Embeddings API (/v1/embeddings)\n:responses Responses API (/v1/responses)\n:images Image Generation API (/v1/images/generations)\n:tools Tool/function calling in chat\n:fim FIM Completion (/v1/completions with suffix)\n:prefix_completion Chat prefix completion\n:json_output JSON output mode (response_format)","category":"section"},{"location":"api/capabilities/#Capabilities-by-Provider","page":"Provider Capabilities","title":"Capabilities by Provider","text":"using UniLM\n\nfor (name, svc) in [\n    (\"OpenAI\",  OPENAIServiceEndpoint),\n    (\"Azure\",   AZUREServiceEndpoint),\n    (\"Gemini\",  GEMINIServiceEndpoint),\n    (\"DeepSeek\", DeepSeekEndpoint(\"k\")),\n    (\"Generic\", GenericOpenAIEndpoint(\"http://x\", \"\"))\n]\n    caps = join(sort(collect(provider_capabilities(svc))), \", \")\n    println(\"$name: $caps\")\nend","category":"section"},{"location":"api/capabilities/#UniLM.provider_capabilities","page":"Provider Capabilities","title":"UniLM.provider_capabilities","text":"provider_capabilities(service) -> Set{Symbol}\n\nReturn the set of capabilities supported by the given service endpoint.\n\nStandard capability symbols:\n\n:chat — Chat Completions API (/v1/chat/completions)\n:embeddings — Embeddings API (/v1/embeddings)\n:responses — Responses API (/v1/responses)\n:images — Image Generation API (/v1/images/generations)\n:tools — Tool/function calling in chat\n:fim — FIM Completion (/v1/completions with suffix)\n:prefix_completion — Chat prefix completion (continue from partial assistant message)\n:json_output — JSON output mode (response_format)\n\n\n\n\n\n","category":"function"},{"location":"api/capabilities/#UniLM.has_capability","page":"Provider Capabilities","title":"UniLM.has_capability","text":"has_capability(service, cap::Symbol) -> Bool\n\nCheck whether the service endpoint supports a given capability.\n\n\n\n\n\n","category":"function"},{"location":"api/endpoints/#Service-Endpoints","page":"Service Endpoints","title":"Service Endpoints","text":"Types for configuring multi-backend service endpoints.","category":"section"},{"location":"api/endpoints/#Abstract-Type","page":"Service Endpoints","title":"Abstract Type","text":"","category":"section"},{"location":"api/endpoints/#Built-in-Endpoints","page":"Service Endpoints","title":"Built-in Endpoints","text":"","category":"section"},{"location":"api/endpoints/#Generic-Endpoint","page":"Service Endpoints","title":"Generic Endpoint","text":"","category":"section"},{"location":"api/endpoints/#Configuration","page":"Service Endpoints","title":"Configuration","text":"Each endpoint reads its configuration from environment variables:","category":"section"},{"location":"api/endpoints/#OpenAI-(default)","page":"Service Endpoints","title":"OpenAI (default)","text":"Variable Description\nOPENAI_API_KEY Your OpenAI API key","category":"section"},{"location":"api/endpoints/#Azure-OpenAI","page":"Service Endpoints","title":"Azure OpenAI","text":"Variable Description\nAZURE_OPENAI_BASE_URL Azure endpoint base URL\nAZURE_OPENAI_API_KEY Azure API key\nAZURE_OPENAI_API_VERSION API version (e.g. 2024-12-01-preview)\nAZURE_OPENAI_DEPLOY_NAME_GPT_5_2 Deployment name for gpt-5.2","category":"section"},{"location":"api/endpoints/#Google-Gemini","page":"Service Endpoints","title":"Google Gemini","text":"Variable Description\nGEMINI_API_KEY Your Gemini API key","category":"section"},{"location":"api/endpoints/#Azure-Deployment-Mapping","page":"Service Endpoints","title":"Azure Deployment Mapping","text":"Azure requires model-to-deployment name mappings. Use add_azure_deploy_name! to register custom mappings:\n\nusing UniLM\n\n# Register a custom deployment for a specific model\nUniLM.add_azure_deploy_name!(\"gpt-5.2\", \"my-gpt52-deploy\")\nprintln(\"Registered deployment: \", UniLM._MODEL_ENDPOINTS_AZURE_OPENAI[\"gpt-5.2\"])","category":"section"},{"location":"api/endpoints/#Selecting-a-Backend","page":"Service Endpoints","title":"Selecting a Backend","text":"Pass the service keyword to any request constructor:\n\nchat = Chat(service=UniLM.AZUREServiceEndpoint, model=\"gpt-5.2\")\nprintln(\"Service: \", chat.service)\nprintln(\"Model: \", chat.model)","category":"section"},{"location":"api/endpoints/#UniLM.ServiceEndpoint","page":"Service Endpoints","title":"UniLM.ServiceEndpoint","text":"ServiceEndpoint\n\nAbstract supertype for LLM service backends. Subtypes control URL routing and authentication.\n\nBuilt-in subtypes:\n\nOPENAIServiceEndpoint — OpenAI API (default)\nAZUREServiceEndpoint — Azure OpenAI Service\nGEMINIServiceEndpoint — Google Gemini via OpenAI-compatible endpoint\nGenericOpenAIEndpoint — any OpenAI-compatible provider (Ollama, Mistral, vLLM, etc.)\n\n\n\n\n\n","category":"type"},{"location":"api/endpoints/#UniLM.OPENAIServiceEndpoint","page":"Service Endpoints","title":"UniLM.OPENAIServiceEndpoint","text":"OpenAI API service endpoint (default). Requires OPENAI_API_KEY env variable.\n\n\n\n\n\n","category":"type"},{"location":"api/endpoints/#UniLM.AZUREServiceEndpoint","page":"Service Endpoints","title":"UniLM.AZUREServiceEndpoint","text":"Azure OpenAI Service endpoint. Requires AZURE_OPENAI_BASE_URL, AZURE_OPENAI_API_KEY, and AZURE_OPENAI_API_VERSION env variables.\n\n\n\n\n\n","category":"type"},{"location":"api/endpoints/#UniLM.GEMINIServiceEndpoint","page":"Service Endpoints","title":"UniLM.GEMINIServiceEndpoint","text":"Google Gemini endpoint (OpenAI-compatible). Requires GEMINI_API_KEY env variable.\n\n\n\n\n\n","category":"type"},{"location":"api/endpoints/#UniLM.GenericOpenAIEndpoint","page":"Service Endpoints","title":"UniLM.GenericOpenAIEndpoint","text":"GenericOpenAIEndpoint <: ServiceEndpoint\n\nConfigurable endpoint for any OpenAI-compatible API provider. Supports Chat Completions, Embeddings, and (where the provider implements it) the Responses API.\n\nFields\n\nbase_url::String: Base URL without trailing slash (e.g., \"http://localhost:11434\")\napi_key::String: API key for Bearer auth. Use \"\" for local servers with no auth.\n\nExample\n\n# Ollama (local)\nchat = Chat(service=GenericOpenAIEndpoint(\"http://localhost:11434\", \"\"), model=\"llama3.1\")\n\n# Mistral\nchat = Chat(service=GenericOpenAIEndpoint(\"https://api.mistral.ai\", ENV[\"MISTRAL_API_KEY\"]),\n            model=\"mistral-large-latest\")\n\n\n\n\n\n","category":"type"},{"location":"api/endpoints/#UniLM.ServiceEndpointSpec","page":"Service Endpoints","title":"UniLM.ServiceEndpointSpec","text":"ServiceEndpointSpec\n\nType alias accepting both marker types (OPENAIServiceEndpoint) and instances (GenericOpenAIEndpoint(...)). Used as the type of service fields.\n\n\n\n\n\n","category":"type"},{"location":"api/endpoints/#UniLM.OllamaEndpoint","page":"Service Endpoints","title":"UniLM.OllamaEndpoint","text":"OllamaEndpoint(; base_url=\"http://localhost:11434\") -> GenericOpenAIEndpoint\n\nPre-configured endpoint for Ollama local server.\n\n\n\n\n\n","category":"function"},{"location":"api/endpoints/#UniLM.MistralEndpoint","page":"Service Endpoints","title":"UniLM.MistralEndpoint","text":"MistralEndpoint(; api_key=ENV[\"MISTRAL_API_KEY\"]) -> GenericOpenAIEndpoint\n\nPre-configured endpoint for Mistral AI API.\n\n\n\n\n\n","category":"function"},{"location":"api/endpoints/#UniLM.DeepSeekEndpoint","page":"Service Endpoints","title":"UniLM.DeepSeekEndpoint","text":"DeepSeekEndpoint <: ServiceEndpoint\n\nPre-configured endpoint for DeepSeek API. Supports chat completions, tool calling, FIM completion, and prefix completion.\n\nFIM and prefix completion use the beta base URL (https://api.deepseek.com/beta).\n\n\n\n\n\n","category":"type"},{"location":"#UniLM.jl","page":"Home","title":"UniLM.jl","text":"A unified Julia interface for large language models.\n\n(Image: CI) (Image: codecov) (Image: Aqua QA) (Image: ) (Image: Stable) (Image: Dev)","category":"section"},{"location":"#What-is-UniLM.jl?","page":"Home","title":"What is UniLM.jl?","text":"UniLM.jl provides a Julian, type-safe interface to LLM providers via the OpenAI-compatible API standard — covering the Chat Completions API, the Responses API, Image Generation, Embeddings, and MCP. Works with OpenAI, Azure, Gemini, Mistral, DeepSeek, Ollama, vLLM, LM Studio, and any OpenAI-compatible provider.","category":"section"},{"location":"#Key-Features","page":"Home","title":"Key Features","text":"🗣️ Chat Completions — stateful conversations with automatic history management\n🔮 Responses API — OpenAI's newer API with built-in tools, multi-turn chaining, and reasoning\n🖼️ Image Generation — create images from text prompts with gpt-image-1.5\n🔧 Tool/Function Calling — first-class support for function tools in both APIs, with automated tool_loop\n🔌 MCP (Model Context Protocol) — connect to MCP servers or build your own, with seamless tool loop integration\n📊 Embeddings — text embedding generation\n🌊 Streaming — real-time token streaming with do-block syntax\n📐 Structured Output — JSON Schema–constrained generation\n☁️ Multi-Backend — OpenAI, Azure OpenAI, and Google Gemini\n✅ Type Safety — invalid states are unrepresentable; tested with JET.jl and Aqua.jl","category":"section"},{"location":"#Two-APIs,-One-Package","page":"Home","title":"Two APIs, One Package","text":"Feature Chat Completions Responses API\nStateful conversations Chat + push! previous_response_id\nSystem prompt Message(Val(:system), ...) instructions kwarg\nTool calling GPTTool / GPTToolCall FunctionTool / function_tool\nWeb search ✗ WebSearchTool\nFile search ✗ FileSearchTool\nStreaming stream=true + callback do-block syntax\nStructured output ResponseFormat TextConfig / json_schema_format\nReasoning (O-series) ✗ Reasoning\nAutomated tool loop tool_loop! tool_loop\nMCP integration mcp_tools bridge MCPTool / mcp_tool","category":"section"},{"location":"#Installation","page":"Home","title":"Installation","text":"using Pkg\nPkg.add(url=\"https://github.com/algunion/UniLM.jl\")\n\nOr in the Pkg REPL:\n\npkg> add https://github.com/algunion/UniLM.jl","category":"section"},{"location":"#Quick-Example","page":"Home","title":"Quick Example","text":"Building requests — these construct objects locally without calling the API:\n\nusing UniLM\nusing JSON\n\n# Chat Completions request\nchat = Chat(model=\"gpt-5.2\")\npush!(chat, Message(Val(:system), \"You are a Julia expert.\"))\npush!(chat, Message(Val(:user), \"Explain multiple dispatch in one sentence.\"))\nprintln(\"Chat has \", length(chat), \" messages, model: \", chat.model)\nprintln(\"Request body preview:\")\nprintln(JSON.json(chat))\n\n# Responses API request\nr = Respond(input=\"What makes Julia special?\")\nprintln(\"Respond model: \", r.model)\nprintln(JSON.json(r))\n\n# Image Generation request\nig = ImageGeneration(prompt=\"A watercolor Julia logo\", quality=\"high\")\nprintln(\"Image model: \", ig.model)\nprintln(JSON.json(ig))\n\nWith a valid API key, actual API calls return structured results:\n\nResponses API (recommended for new code):\n\nresult = respond(\"Explain Julia's multiple dispatch in 2-3 sentences.\")\nif result isa ResponseSuccess\n    println(output_text(result))\nelse\n    println(\"Request failed — \", output_text(result))\nend\n\nChat Completions:\n\nchat = Chat(model=\"gpt-4o-mini\")\npush!(chat, Message(Val(:system), \"You are a concise Julia programming tutor.\"))\npush!(chat, Message(Val(:user), \"What is multiple dispatch? Answer in 2-3 sentences.\"))\nresult = chatrequest!(chat)\nif result isa LLMSuccess\n    println(result.message.content)\nelse\n    println(\"Request failed — see result for details\")\nend\n\nImage Generation:\n\nresult = generate_image(\n    \"A watercolor painting of a friendly robot reading a Julia programming book\",\n    size=\"1024x1024\", quality=\"medium\"\n)\nprintln(\"Success: \", result isa ImageSuccess)\nif result isa ImageSuccess\n    save_image(image_data(result)[1], joinpath(@__DIR__, \"assets\", \"generated_robot.png\"))\n    println(\"Saved to assets/generated_robot.png\")\nelse\n    println(\"Image generation failed — see result for details\")\nend\n\n(Image: Generated robot reading Julia)","category":"section"},{"location":"#Next-Steps","page":"Home","title":"Next Steps","text":"Getting Started — setup and first requests\nChat Completions Guide — deep dive into Chat and chatrequest!\nResponses API Guide — the newer Responses API\nImage Generation Guide — create images from text prompts\nMCP Guide — connect to MCP servers or build your own\nAPI Reference — full type and function reference","category":"section"},{"location":"guide/streaming/#streaming_guide","page":"Streaming","title":"Streaming","text":"Both APIs support real-time streaming of generated tokens, so you can display partial results as they arrive.","category":"section"},{"location":"guide/streaming/#Chat-Completions-Streaming","page":"Streaming","title":"Chat Completions Streaming","text":"Set stream=true and provide a callback:\n\nchat = Chat(model=\"gpt-4o-mini\", stream=true)\npush!(chat, Message(Val(:system), \"You are a poet.\"))\npush!(chat, Message(Val(:user), \"Write a very short 2-line poem about coding.\"))\ntask = chatrequest!(chat, callback=function(chunk, close)\n    if chunk isa String\n        print(chunk)\n    elseif chunk isa Message\n        println(\"\\n--- done ---\")\n    end\nend)\nresult = fetch(task)\nif result isa LLMSuccess\n    println(result.message.content)\nelse\n    println(\"Request failed — see result for details\")\nend\nnothing # hide","category":"section"},{"location":"guide/streaming/#Stopping-a-Stream-Early","page":"Streaming","title":"Stopping a Stream Early","text":"The callback receives a Ref{Bool} that you can set to true to stop streaming:\n\ntask = chatrequest!(chat, callback=function(chunk, close)\n    if chunk isa String\n        print(chunk)\n        if contains(chunk, \"bad word\")\n            close[] = true  # stop the stream\n        end\n    end\nend)","category":"section"},{"location":"guide/streaming/#Responses-API-Streaming","page":"Streaming","title":"Responses API Streaming","text":"The Responses API provides an even cleaner streaming interface using Julia's do-block syntax:\n\ntask = respond(\"Write a haiku about Julia programming.\") do chunk, close\n    if chunk isa String\n        print(chunk)\n    elseif chunk isa UniLM.ResponseObject\n        println(\"\\nDone! Status: \", chunk.status)\n    end\nend\nresult = fetch(task)\nif result isa ResponseSuccess\n    println(output_text(result))\nelse\n    println(\"Request failed — \", output_text(result))\nend\n\nThe do-block form automatically sets stream=true.","category":"section"},{"location":"guide/streaming/#With-Explicit-Configuration","page":"Streaming","title":"With Explicit Configuration","text":"r = Respond(\n    input=\"Explain quantum computing step by step\",\n    model=\"gpt-5.2\",\n    stream=true,\n    max_output_tokens=2000,\n)\nprintln(\"Stream enabled: \", r.stream)\nprintln(\"Request preview:\")\nprintln(JSON.json(r))","category":"section"},{"location":"guide/streaming/#Notes","page":"Streaming","title":"Notes","text":"Streaming runs on a separate Julia thread via Threads.@spawn. Make sure Julia is started with multiple threads (julia -t auto).\nThe returned Task can be fetched to get the final result.\nThe close Ref{Bool} can be set to true from the callback to terminate the stream early.\nOn completion, the Chat Completions callback receives a Message; the Responses API callback receives a ResponseObject.","category":"section"},{"location":"guide/responses_api/#responses_guide","page":"Responses API","title":"Responses API","text":"The Responses API is OpenAI's newer, more flexible alternative to Chat Completions. Key advantages include built-in tools (web search, file search), stateless multi-turn via previous_response_id, and reasoning support for O-series models.","category":"section"},{"location":"guide/responses_api/#Basic-Usage","page":"Responses API","title":"Basic Usage","text":"The simplest call — just a string:\n\nresult = respond(\"Explain Julia's multiple dispatch in 2-3 sentences.\")\nif result isa ResponseSuccess\n    println(output_text(result))\nelse\n    println(\"Request failed — \", output_text(result))\nend\n\nif result isa ResponseSuccess\n    println(\"ID:     \", result.response.id)\n    println(\"Status: \", result.response.status)\n    println(\"Model:  \", result.response.model)\nelse\n    println(\"No response metadata available\")\nend","category":"section"},{"location":"guide/responses_api/#The-Respond-Type","page":"Responses API","title":"The Respond Type","text":"For full control, construct a Respond object:\n\nr = Respond(\n    model=\"gpt-5.2\",\n    input=\"Explain monads simply\",\n    instructions=\"You are a functional programming expert. Be concise.\",\n    temperature=0.5,\n    max_output_tokens=500,\n)\nprintln(\"Model: \", r.model)\nprintln(\"Request body:\")\nprintln(JSON.json(r))","category":"section"},{"location":"guide/responses_api/#Instructions-(System-Prompt)","page":"Responses API","title":"Instructions (System Prompt)","text":"Unlike Chat Completions where you push a system Message, the Responses API uses the instructions parameter:\n\nresult = respond(\n    \"Translate to French: The quick brown fox jumps over the lazy dog.\",\n    instructions=\"You are a professional translator. Respond only with the translation.\"\n)\nif result isa ResponseSuccess\n    println(output_text(result))\nelse\n    println(\"Request failed — \", output_text(result))\nend","category":"section"},{"location":"guide/responses_api/#Structured-Input","page":"Responses API","title":"Structured Input","text":"For multimodal inputs, use InputMessage with content helpers:\n\n# Text-only structured input\nmsgs = [\n    InputMessage(role=\"system\", content=\"You analyze images.\"),\n    InputMessage(role=\"user\", content=[\n        input_text(\"What do you see in this image?\"),\n        input_image(\"https://example.com/photo.jpg\"),\n    ]),\n]\nr = Respond(input=msgs, model=\"gpt-5.2\")\nprintln(\"Input is structured: \", r.input isa Vector)\nprintln(\"Number of input messages: \", length(r.input))","category":"section"},{"location":"guide/responses_api/#Input-Helpers","page":"Responses API","title":"Input Helpers","text":"Function Purpose\ninput_text Text content part\ninput_image Image URL content part\ninput_file File (URL or ID) content part","category":"section"},{"location":"guide/responses_api/#Multi-Turn-Conversations","page":"Responses API","title":"Multi-Turn Conversations","text":"Chain requests using previous_response_id — no need to re-send the full history:\n\nr1 = respond(\"Tell me a one-liner programming joke.\", instructions=\"Be concise.\")\nif r1 isa ResponseSuccess\n    println(output_text(r1))\nelse\n    println(\"Request failed — \", output_text(r1))\nend\n\nif r1 isa ResponseSuccess\n    r2 = respond(\"Explain why that's funny, in one sentence.\", previous_response_id=r1.response.id)\n    if r2 isa ResponseSuccess\n        println(output_text(r2))\n    else\n        println(\"Request failed — \", output_text(r2))\n    end\nelse\n    println(\"Skipped — first request failed\")\nend","category":"section"},{"location":"guide/responses_api/#Built-in-Tools","page":"Responses API","title":"Built-in Tools","text":"","category":"section"},{"location":"guide/responses_api/#Web-Search","page":"Responses API","title":"Web Search","text":"result = respond(\n    \"What is the latest stable release of the Julia programming language?\",\n    tools=[web_search()]\n)\nif result isa ResponseSuccess\n    println(output_text(result))\nelse\n    println(\"Request failed — \", output_text(result))\nend","category":"section"},{"location":"guide/responses_api/#File-Search","page":"Responses API","title":"File Search","text":"result = respond(\n    \"Find information about error handling\",\n    tools=[file_search([\"vs_abc123\"])]\n)","category":"section"},{"location":"guide/responses_api/#Function-Tools","page":"Responses API","title":"Function Tools","text":"weather_tool = function_tool(\n    \"get_weather\",\n    \"Get current weather for a location\",\n    parameters=Dict(\n        \"type\" => \"object\",\n        \"properties\" => Dict(\n            \"location\" => Dict(\"type\" => \"string\", \"description\" => \"City name\")\n        ),\n        \"required\" => [\"location\"]\n    )\n)\nprintln(\"Tool name: \", weather_tool.name)\nprintln(\"Tool JSON: \", JSON.json(JSON.lower(weather_tool)))\n\nresult = respond(\"What's the weather in Tokyo? Use celsius.\", tools=[weather_tool])\ncalls = function_calls(result)\nif !isempty(calls)\n    println(\"Function: \", calls[1][\"name\"])\n    println(\"Arguments: \", JSON.json(JSON.parse(calls[1][\"arguments\"]), 2))\nelse\n    println(\"No function calls — \", output_text(result))\nend","category":"section"},{"location":"guide/responses_api/#Reasoning-(O-Series-Models)","page":"Responses API","title":"Reasoning (O-Series Models)","text":"For models like o3 that support extended reasoning:\n\nr = Respond(\n    input=\"Prove that √2 is irrational\",\n    model=\"o3\",\n    reasoning=Reasoning(effort=\"high\", summary=\"detailed\")\n)\nprintln(\"Model: \", r.model)\nprintln(\"Reasoning effort: \", r.reasoning.effort)\nprintln(JSON.json(r))","category":"section"},{"location":"guide/responses_api/#Structured-Output","page":"Responses API","title":"Structured Output","text":"Force JSON-conformant output:\n\n# JSON Schema format\nfmt = json_schema_format(\n    \"colors\",\n    \"A list of colors\",\n    Dict(\n        \"type\" => \"object\",\n        \"properties\" => Dict(\n            \"colors\" => Dict(\n                \"type\" => \"array\",\n                \"items\" => Dict(\"type\" => \"string\")\n            )\n        ),\n        \"required\" => [\"colors\"],\n        \"additionalProperties\" => false\n    ),\n    strict=true\n)\nprintln(\"Format type: \", fmt.format.type)\nprintln(\"Schema name: \", fmt.format.name)\n\nresult = respond(\"List 5 popular colors\", text=fmt)\nif result isa ResponseSuccess\n    println(JSON.json(JSON.parse(output_text(result)), 2))\nelse\n    println(\"Request failed — \", output_text(result))\nend","category":"section"},{"location":"guide/responses_api/#Response-Accessors","page":"Responses API","title":"Response Accessors","text":"result = respond(\"Hello!\")\n\nif result isa ResponseSuccess\n    r = result.response\n\n    output_text(result)      # full text output\n    function_calls(result)   # Vector of function call Dicts (empty if none)\n\n    r.id                     # \"resp_00e791c8...\"\n    r.status                 # \"completed\"\n    r.model                  # \"gpt-5.2-2025-12-11\"\n    r.output                 # full output array\n    r.usage                  # Dict with token counts\nend","category":"section"},{"location":"guide/responses_api/#Managing-Stored-Responses","page":"Responses API","title":"Managing Stored Responses","text":"When you pass store=true, the response is saved on OpeAnI's servers and can be retrieved, inspected, or deleted later:\n\nr = respond(\"Say 'stored response test' and nothing else.\", store=true)\nif r isa ResponseSuccess\n    rid = r.response.id\n    println(\"Stored response ID: \", rid)\n\n    # Retrieve\n    retrieved = get_response(rid)\n    if retrieved isa ResponseSuccess\n        println(\"Retrieved text: \", output_text(retrieved))\n    end\n\n    # List input items\n    items = list_input_items(rid)\n    if items isa Dict\n        println(\"Input items: \", length(items[\"data\"]))\n    end\n\n    # Delete\n    del = delete_response(rid)\n    if del isa Dict\n        println(\"Deleted: \", del[\"deleted\"])\n    end\nelse\n    println(\"Request failed — \", output_text(r))\nend","category":"section"},{"location":"guide/responses_api/#Metadata","page":"Responses API","title":"Metadata","text":"Attach arbitrary key-value metadata to any request for tracking, filtering, or debugging:\n\nresult = respond(\n    \"Say 'metadata test' and nothing else.\",\n    metadata=Dict(\"env\" => \"docs\", \"request_id\" => \"demo_123\")\n)\nif result isa ResponseSuccess\n    println(output_text(result))\nelse\n    println(\"Request failed — \", output_text(result))\nend","category":"section"},{"location":"guide/responses_api/#Service-Tier","page":"Responses API","title":"Service Tier","text":"Control the processing tier for your request (\"auto\", \"default\", \"flex\", \"priority\"):\n\nresult = respond(\"Say 'tier test' and nothing else.\", service_tier=\"auto\")\nif result isa ResponseSuccess\n    println(output_text(result))\nelse\n    println(\"Request failed — \", output_text(result))\nend","category":"section"},{"location":"guide/responses_api/#Counting-Input-Tokens","page":"Responses API","title":"Counting Input Tokens","text":"Estimate token usage before making a full request — useful for cost estimation or verifying that input fits within the context window:\n\nresult = count_input_tokens(input=\"Tell me a joke about programming\")\nif result isa Dict\n    println(\"Input tokens: \", result[\"input_tokens\"])\nelse\n    println(\"Request failed — see result for details\")\nend\n\nWith tools and instructions:\n\ntool = function_tool(\"search\", \"Search for information\",\n    parameters=Dict(\"type\" => \"object\", \"properties\" => Dict(\n        \"query\" => Dict(\"type\" => \"string\")\n    ), \"required\" => [\"query\"], \"additionalProperties\" => false),\n    strict=true\n)\nresult = count_input_tokens(\n    input=\"Search for Julia language news\",\n    instructions=\"You are a helpful assistant.\",\n    tools=[tool]\n)\nif result isa Dict\n    println(\"Tokens with tools: \", result[\"input_tokens\"])\nelse\n    println(\"Request failed — see result for details\")\nend","category":"section"},{"location":"guide/responses_api/#Compacting-Conversations","page":"Responses API","title":"Compacting Conversations","text":"For long conversations, compact_response compresses the history into opaque, encrypted items that reduce token usage while preserving context:\n\nitems = [\n    Dict(\"role\" => \"user\", \"content\" => \"Hello, I want to learn about Julia.\"),\n    Dict(\"type\" => \"message\", \"role\" => \"assistant\", \"status\" => \"completed\",\n         \"content\" => [Dict(\"type\" => \"output_text\",\n            \"text\" => \"Julia is a high-performance programming language for technical computing.\")])\n]\nresult = compact_response(input=items)\nif result isa Dict\n    println(\"Compact succeeded\")\n    println(\"Output items: \", length(result[\"output\"]))\n    println(\"Usage: \", result[\"usage\"])\nelse\n    println(\"Request failed — see result for details\")\nend","category":"section"},{"location":"guide/responses_api/#Cancelling-Responses","page":"Responses API","title":"Cancelling Responses","text":"Cancel an in-progress (background) response:\n\n# Start a background response\nresult = respond(\"Write a very long essay about Julia\", background=true)\n\n# Cancel it\nif result isa ResponseSuccess\n    cancel_result = cancel_response(result.response.id)\n    if cancel_result isa ResponseSuccess\n        println(\"Cancelled: \", cancel_result.response.status)\n    end\nend","category":"section"},{"location":"guide/responses_api/#Parameters-Reference","page":"Responses API","title":"Parameters Reference","text":"Parameter Type Default Description\nmodel String \"gpt-5.2\" Model to use\ninput Union{String, Vector} (required) String or Vector{InputMessage}\ninstructions String — System-level instructions\ntools Vector — Available tools (function, web search, file search)\ntool_choice String — \"auto\", \"none\", \"required\"\nparallel_tool_calls Bool — Allow parallel tool calls\ntemperature Float64 — 0.0–2.0 (mutually exclusive with top_p)\ntop_p Float64 — 0.0–1.0 (mutually exclusive with temperature)\nmax_output_tokens Int64 — Maximum tokens in the response\nstream Bool — Enable streaming\ntext TextConfig — Output format (text, jsonobject, jsonschema)\nreasoning Reasoning — Reasoning config for O-series models\ntruncation String — \"auto\" or \"disabled\"\nstore Bool — Store response for later retrieval\nmetadata Dict — Arbitrary key-value metadata\nprevious_response_id String — Chain to a previous response for multi-turn\nuser String — End-user identifier\nbackground Bool — Run in background (cancellable)\ninclude Vector{String} — Extra data to include (e.g. \"file_search_call.results\")\nmax_tool_calls Int64 — Max number of tool calls per turn\nservice_tier String — \"auto\", \"default\", \"flex\", \"priority\"\ntop_logprobs Int64 — 0–20, top log probabilities\nprompt Dict — Prompt template reference\nprompt_cache_key String — Cache key for prompt caching\nprompt_cache_retention String — \"in-memory\" or \"24h\"\nconversation Any — Conversation context (String or Dict)\ncontext_management Vector — Context management strategies\nstream_options Dict — Streaming options (e.g. include_usage)","category":"section"},{"location":"guide/responses_api/#Retry-Behaviour","page":"Responses API","title":"Retry Behaviour","text":"respond automatically retries on HTTP 429, 500, and 503 errors with exponential backoff and jitter (up to 30 attempts, max 60s delay). On 429 responses, the Retry-After header is respected. This applies to all Responses API functions (respond, get_response, delete_response, etc.).","category":"section"},{"location":"guide/responses_api/#Parameter-Validation","page":"Responses API","title":"Parameter Validation","text":"The Respond constructor validates parameter ranges at construction time:\n\nParameter Valid Range\ntemperature 0.0–2.0\ntop_p 0.0–1.0\nmax_output_tokens ≥ 1\ntop_logprobs 0–20\n\nOut-of-range values throw ArgumentError. Additionally, temperature and top_p are mutually exclusive.","category":"section"},{"location":"guide/responses_api/#See-Also","page":"Responses API","title":"See Also","text":"Respond — full type reference\nResponseObject — response structure\nTool Calling — detailed tool calling guide\nStreaming — streaming with do-blocks","category":"section"}]
}
